'use client';

/**
 * react/index.ts — the `fontuccine/react` wrapper.
 *
 * THIN by contract (Phase-5 wrapper rules): props → config object; NO
 * framework-specific animation logic (the shared ticker + StretchController own
 * all of that); attach/destroy on a ref inside an effect. `react`/`react-dom` are
 * peerDependencies.
 *
 * SSR-inert: importing this module and rendering on the server touch no
 * `window`/`document` — `attach()` runs only inside `useEffect`, which never
 * fires during SSR. StrictMode-safe: the effect's mount→unmount→mount cycle maps
 * to attach→destroy→attach; the WebGL shared backend is ref-counted
 * (acquire/release), so the middle unmount does not destroy a context the remount
 * still needs (verified in test/react-wrapper).
 */
import {
  createElement,
  useEffect,
  useRef,
  type ElementType,
  type ReactNode,
  type RefObject,
} from 'react';
import { attach } from '../engine/attach';
import type { FontuccineConfig, Instance } from '../engine/types';

export type { FontuccineConfig, Instance } from '../engine/types';

const DEFAULT_CONFIG: FontuccineConfig = {};

/**
 * Attach Fontuccine to an existing ref for the lifetime of the component.
 * `config` should be memoized by the caller — a new `config` identity re-attaches
 * (destroy + attach), which is the intended way to change axis/trigger/etc.
 * Returns the live `Instance` (or null before the first client effect) via a ref,
 * for imperative `.set()` on `trigger:'custom'`.
 */
export function useFontuccine(
  ref: RefObject<HTMLElement | null>,
  config: FontuccineConfig = DEFAULT_CONFIG,
): RefObject<Instance | null> {
  const instanceRef = useRef<Instance | null>(null);

  useEffect(() => {
    const el = ref.current;
    if (!el) return;
    const instance = attach(el, config);
    instanceRef.current = instance;
    return () => {
      instance.destroy();
      instanceRef.current = null;
    };
    // Re-attach when the element or the config identity changes.
  }, [ref, config]);

  return instanceRef;
}

export interface FontuccineProps {
  /** Element type to render (default 'span'). */
  as?: ElementType;
  /** Fontuccine config (memoize to avoid re-attaching every render). */
  config?: FontuccineConfig;
  children?: ReactNode;
  className?: string;
  style?: Record<string, string | number>;
  [key: string]: unknown;
}

/**
 * `<Fontuccine as="h1" config={...}>Stretch me</Fontuccine>` — renders the given
 * element with the real text as children (so SSR ships the text and it stays for
 * a11y/SEO) and attaches the engine to it on the client.
 */
export function Fontuccine(props: FontuccineProps): ReactNode {
  const { as = 'span', config, children, ...rest } = props;
  const ref = useRef<HTMLElement | null>(null);
  useFontuccine(ref, config ?? DEFAULT_CONFIG);
  return createElement(as, { ...rest, ref }, children);
}

export default Fontuccine;

/**
 * flex-profile.ts — the tangent-aligned flex profile (Pagurek 2025),
 * productionized for < 5ms/glyph/axis at 96 slices.
 *
 *   flex(slice) = 1                                if slice ∩ glyph = ∅
 *               = min over interior p of |τ̂(p) · ŝ|^k   otherwise
 *
 * Each INTERIOR point takes the tangent of its NEAREST boundary sample — that
 * is what encodes local stroke direction. The boundary-bucketing shortcut is
 * FALSIFIED (RESEARCH §1.1). Keep the nearest-boundary field.
 *
 * Performance architecture:
 *  - Sampling, winding-filter and the k-d tree are built ONCE per glyph in a
 *    FlexField (buildFlexField), then shared by both axes. Analysis is static.
 *  - Point-in-glyph is a per-slice SCANLINE (one edge sweep per slice) instead
 *    of a winding test per interior point — O(E) per slice, not O(E) per point.
 *  - Nearest lookup is the k-d tree (spatial/kdtree.ts); a brute mode is kept
 *    for the T2 parity test. Both share the same scanline, so results match.
 */
import type { SampledOutline, Bounds1D, Axis, BoundarySample } from './types';
import { filterVisibleSamples } from './winding';
import { KDTree } from './spatial/kdtree';

type Ring = Array<[number, number]>;

/** Prebuilt, axis-independent analysis state for one glyph. */
export interface FlexField {
  polygons: Ring[];
  samples: BoundarySample[];
  /** Nearest boundary sample index for a query point. */
  nearest: (x: number, y: number) => number;
}

export interface FieldOptions {
  spatial?: 'kdtree' | 'brute';
  filterInvisible?: boolean;
}

/** Build the shared per-glyph field (sampling → winding-filter → k-d tree). */
export function buildFlexField(outline: SampledOutline, options: FieldOptions = {}): FlexField {
  const { spatial = 'kdtree', filterInvisible = true } = options;
  const raw = outline.samples;
  const samples = filterInvisible ? filterVisibleSamples(raw, outline.polygons) : raw;

  let nearest: (x: number, y: number) => number;
  if (samples.length === 0) {
    nearest = () => -1;
  } else if (spatial === 'brute') {
    nearest = (x, y) => {
      let best = -1;
      let bestD = Infinity;
      for (let i = 0; i < samples.length; i++) {
        const s = samples[i];
        const d = (s.x - x) * (s.x - x) + (s.y - y) * (s.y - y);
        if (d < bestD) {
          bestD = d;
          best = i;
        }
      }
      return best;
    };
  } else {
    const tree = new KDTree(samples);
    nearest = (x, y) => tree.nearest(x, y);
  }

  return { polygons: outline.polygons, samples, nearest };
}

export interface FlexProfileOptions {
  axis: Axis;
  slices?: number;
  k?: number;
  bounds: Bounds1D;
  crossBounds: Bounds1D;
  interiorSamples?: number;
  smooth?: number;
  /** 'kdtree' (default) or 'brute' — brute is for parity testing only. */
  spatial?: 'kdtree' | 'brute';
  /** Winding-filter invisible self-intersection samples (default true). */
  filterInvisible?: boolean;
  /** Edge-clamp first/last slice to their neighbour (default true). */
  edgeClamp?: boolean;
  /** Reuse a prebuilt field (both axes of a glyph share one). */
  field?: FlexField;
}

/**
 * Nonzero-winding crossings of the outline with the line {stretch-axis = a}.
 * Reused for every interior sample in the slice. Returns parallel arrays of
 * cross-axis crossing coordinates and their winding direction (±1), so
 * inside(c) = (Σ dir where crossing > c) ≠ 0.
 */
function sliceCrossings(
  rings: Ring[],
  a: number,
  axis: Axis,
  outCross: number[],
  outDir: number[],
): number {
  let n = 0;
  for (const ring of rings) {
    const m = ring.length;
    if (m < 3) continue;
    for (let i = 0, j = m - 1; i < m; j = i++) {
      const pi = ring[i];
      const pj = ring[j];
      // a-coord = stretch axis; c-coord = cross axis
      const a0 = axis === 'x' ? pj[0] : pj[1];
      const a1 = axis === 'x' ? pi[0] : pi[1];
      if ((a0 <= a && a < a1) || (a1 <= a && a < a0)) {
        const c0 = axis === 'x' ? pj[1] : pj[0];
        const c1 = axis === 'x' ? pi[1] : pi[0];
        const t = (a - a0) / (a1 - a0);
        outCross[n] = c0 + t * (c1 - c0);
        outDir[n] = a1 > a0 ? 1 : -1;
        n++;
      }
    }
  }
  return n;
}

export function computeFlexProfile(
  outline: SampledOutline,
  options: FlexProfileOptions,
): Float32Array {
  const {
    axis,
    slices = 64,
    k = 8,
    bounds,
    crossBounds,
    interiorSamples = 48,
    smooth = 0.75,
    spatial = 'kdtree',
    filterInvisible = true,
    edgeClamp = true,
  } = options;

  const { min, max } = bounds;
  const span = max - min;
  if (span <= 0 || outline.samples.length === 0) return new Float32Array(slices).fill(1);

  const field = options.field ?? buildFlexField(outline, { spatial, filterInvisible });
  const { polygons, samples, nearest } = field;
  if (samples.length === 0) return new Float32Array(slices).fill(1);

  const cMin = crossBounds.min;
  const cSpan = crossBounds.max - crossBounds.min;
  const flex = new Float32Array(slices).fill(1); // empty slice → fully stretchy

  // Reused scratch for crossings (grows as needed).
  const cross: number[] = [];
  const dir: number[] = [];

  for (let i = 0; i < slices; i++) {
    const a = min + ((i + 0.5) / slices) * span; // slice center on stretch axis
    const nc = sliceCrossings(polygons, a, axis, cross, dir);
    if (nc === 0) continue; // slice misses the glyph → stays 1

    let m = Infinity;
    for (let j = 0; j < interiorSamples; j++) {
      const c = cMin + ((j + 0.5) / interiorSamples) * cSpan;
      // nonzero-winding inside test via the precomputed crossings
      let wind = 0;
      for (let e = 0; e < nc; e++) if (cross[e] > c) wind += dir[e];
      if (wind === 0) continue;

      const x = axis === 'x' ? a : c;
      const y = axis === 'x' ? c : a;
      const ni = nearest(x, y);
      if (ni < 0) continue;
      const nb = samples[ni];
      const align = Math.abs(axis === 'x' ? nb.tx : nb.ty); // |τ̂ · ŝ|
      const f = Math.pow(align, k);
      if (f < m) m = f;
      if (m === 0) break;
    }
    if (Number.isFinite(m)) flex[i] = m;
  }

  if (edgeClamp && slices >= 2) {
    flex[0] = flex[1];
    flex[slices - 1] = flex[slices - 2];
  }

  return smooth > 0 ? gaussianSmooth(flex, smooth) : flex;
}

function gaussianSmooth(arr: Float32Array, sigma: number): Float32Array {
  const radius = Math.max(1, Math.ceil(sigma * 3));
  const kernel: number[] = [];
  let sum = 0;
  for (let i = -radius; i <= radius; i++) {
    const w = Math.exp(-(i * i) / (2 * sigma * sigma));
    kernel.push(w);
    sum += w;
  }
  const out = new Float32Array(arr.length);
  for (let i = 0; i < arr.length; i++) {
    let acc = 0;
    for (let j = -radius; j <= radius; j++) {
      const idx = Math.min(arr.length - 1, Math.max(0, i + j));
      acc += arr[idx] * kernel[j + radius];
    }
    out[i] = acc / sum;
  }
  return out;
}

/**
 * geometry/segments.ts — segment evaluation, command→contour conversion,
 * and de Casteljau splitting.
 *
 * A "segment" carries explicit endpoints so it can be evaluated and split
 * without walking the command list.
 */
import type { PathCommand } from '../types';

export interface Point {
  x: number;
  y: number;
}

export interface LineSeg {
  type: 'L';
  p0: Point;
  p1: Point;
}
export interface QuadSeg {
  type: 'Q';
  p0: Point;
  p1: Point;
  p2: Point;
}
export interface CubicSeg {
  type: 'C';
  p0: Point;
  p1: Point;
  p2: Point;
  p3: Point;
}
export type Segment = LineSeg | QuadSeg | CubicSeg;

export interface PointTangent {
  x: number;
  y: number;
  tx: number;
  ty: number;
}

/** Evaluate point and (unnormalized) tangent of one segment at t ∈ [0,1]. */
export function evalSegment(seg: Segment, t: number): PointTangent {
  const p0 = seg.p0;
  switch (seg.type) {
    case 'L': {
      const dx = seg.p1.x - p0.x;
      const dy = seg.p1.y - p0.y;
      return { x: p0.x + t * dx, y: p0.y + t * dy, tx: dx, ty: dy };
    }
    case 'Q': {
      const { p1, p2 } = seg;
      const mt = 1 - t;
      return {
        x: mt * mt * p0.x + 2 * mt * t * p1.x + t * t * p2.x,
        y: mt * mt * p0.y + 2 * mt * t * p1.y + t * t * p2.y,
        tx: 2 * mt * (p1.x - p0.x) + 2 * t * (p2.x - p1.x),
        ty: 2 * mt * (p1.y - p0.y) + 2 * t * (p2.y - p1.y),
      };
    }
    case 'C': {
      const { p1, p2, p3 } = seg;
      const mt = 1 - t;
      return {
        x: mt ** 3 * p0.x + 3 * mt * mt * t * p1.x + 3 * mt * t * t * p2.x + t ** 3 * p3.x,
        y: mt ** 3 * p0.y + 3 * mt * mt * t * p1.y + 3 * mt * t * t * p2.y + t ** 3 * p3.y,
        tx: 3 * mt * mt * (p1.x - p0.x) + 6 * mt * t * (p2.x - p1.x) + 3 * t * t * (p3.x - p2.x),
        ty: 3 * mt * mt * (p1.y - p0.y) + 6 * mt * t * (p2.y - p1.y) + 3 * t * t * (p3.y - p2.y),
      };
    }
  }
}

/** Convert an opentype-style command list into contours of segments. */
export function commandsToContours(commands: PathCommand[]): Segment[][] {
  const contours: Segment[][] = [];
  let segs: Segment[] = [];
  let cur: Point | null = null;
  let start: Point | null = null;

  for (const c of commands) {
    switch (c.type) {
      case 'M':
        if (segs.length) {
          contours.push(segs);
          segs = [];
        }
        cur = { x: c.x ?? 0, y: c.y ?? 0 };
        start = cur;
        break;
      case 'L':
        if (cur) segs.push({ type: 'L', p0: cur, p1: { x: c.x ?? 0, y: c.y ?? 0 } });
        cur = { x: c.x ?? 0, y: c.y ?? 0 };
        break;
      case 'Q':
        if (cur) {
          segs.push({
            type: 'Q',
            p0: cur,
            p1: { x: c.x1 ?? 0, y: c.y1 ?? 0 },
            p2: { x: c.x ?? 0, y: c.y ?? 0 },
          });
        }
        cur = { x: c.x ?? 0, y: c.y ?? 0 };
        break;
      case 'C':
        if (cur) {
          segs.push({
            type: 'C',
            p0: cur,
            p1: { x: c.x1 ?? 0, y: c.y1 ?? 0 },
            p2: { x: c.x2 ?? 0, y: c.y2 ?? 0 },
            p3: { x: c.x ?? 0, y: c.y ?? 0 },
          });
        }
        cur = { x: c.x ?? 0, y: c.y ?? 0 };
        break;
      case 'Z':
        if (cur && start && (cur.x !== start.x || cur.y !== start.y)) {
          segs.push({ type: 'L', p0: cur, p1: start });
        }
        if (segs.length) {
          contours.push(segs);
          segs = [];
        }
        cur = start;
        break;
    }
  }
  if (segs.length) contours.push(segs);
  return contours;
}

const lerp = (a: Point, b: Point, t: number): Point => ({
  x: a.x + (b.x - a.x) * t,
  y: a.y + (b.y - a.y) * t,
});

/**
 * de Casteljau split at t → { left, right } segments of the same degree.
 * Useful for the SVG tier (split at slice boundaries → affine-per-slice remap).
 */
export function splitSegment(seg: Segment, t: number): { left: Segment; right: Segment } {
  switch (seg.type) {
    case 'L': {
      const m = lerp(seg.p0, seg.p1, t);
      return {
        left: { type: 'L', p0: seg.p0, p1: m },
        right: { type: 'L', p0: m, p1: seg.p1 },
      };
    }
    case 'Q': {
      const a = lerp(seg.p0, seg.p1, t);
      const b = lerp(seg.p1, seg.p2, t);
      const m = lerp(a, b, t);
      return {
        left: { type: 'Q', p0: seg.p0, p1: a, p2: m },
        right: { type: 'Q', p0: m, p1: b, p2: seg.p2 },
      };
    }
    case 'C': {
      const a = lerp(seg.p0, seg.p1, t);
      const b = lerp(seg.p1, seg.p2, t);
      const c = lerp(seg.p2, seg.p3, t);
      const d = lerp(a, b, t);
      const e = lerp(b, c, t);
      const m = lerp(d, e, t);
      return {
        left: { type: 'C', p0: seg.p0, p1: a, p2: d, p3: m },
        right: { type: 'C', p0: m, p1: e, p2: c, p3: seg.p3 },
      };
    }
  }
}

/**
 * kerning.ts — advances + kerning in STRETCHED space (RESEARCH §5.6).
 *
 * ── The rule (functional decision, surfaced to the user via the architect) ──
 * Empty space — left/right side bearings AND inter-glyph kerning — is treated
 * as fully-stretchy (flex = 1), exactly like an empty slice in the flex model.
 * A glyph's INK also grows to W·stretch in total (invariant I1), with its
 * internal distribution protecting strokes/serifs. Since ink-extent, side
 * bearings and kerns all scale by the same ratio, a horizontal stretch of
 * ratio r multiplies every glyph advance and every kern by exactly r:
 *
 *     stretchedAdvance = advanceWidth · r
 *     stretchedKern    = kernBefore   · r
 *     runWidth         = r · Σ(advanceWidth + kernBefore)
 *
 * At r === 1 this reproduces the native metrics EXACTLY (regression anchor).
 * The per-glyph frame origin `penX` is offset so the glyph's own remap
 * (anchored at bounds.min) lands its ink at the stretched left side bearing:
 *
 *     penX = cursor + bounds.min·(r − 1)     // renderer draws penX + remap(x)
 *
 * This is deliberately simple and easy to change: if a future design wants
 * side bearings to stay RIGID (ink-only stretch), only this file changes —
 * set stretchedKern = kernBefore and penX/advance accordingly.
 */
import type { Bounds1D } from './types';
import { buildRemap } from './lut';
import type { Remap } from './types';

export interface LayoutGlyph {
  /** Static flex profile for the layout axis. */
  profile: Float32Array;
  /** Ink bounds along the layout axis (glyph coordinate space). */
  bounds: Bounds1D;
  /** Advance width (pen advance) in glyph units. */
  advanceWidth: number;
  /** Kerning applied BEFORE this glyph (0 for the first). */
  kernBefore?: number;
}

export interface LayoutGlyphResult {
  /** Frame origin: render outline points as penX + remap(pointX). */
  penX: number;
  /** Stretched advance for this glyph. */
  advance: number;
  /** Stretched kern applied before this glyph. */
  kern: number;
  /** Stretched ink left/right edges in run space. */
  inkLeft: number;
  inkRight: number;
  /** The glyph's per-frame remap (origin anchored at bounds.min). */
  remap: Remap;
}

export interface LayoutRunOptions {
  axis?: 'x';
  stretch: number;
  /** Run origin (default 0). */
  origin?: number;
}

export interface LayoutRunResult {
  glyphs: LayoutGlyphResult[];
  /** Total stretched run width = Σ(advance + kern). */
  width: number;
}

/**
 * Lay out a run of glyphs in stretched space.
 * Only axis 'x' (horizontal) is implemented; 'y' would mirror using vertical
 * metrics, which glyphs here do not carry.
 */
export function layoutRun(glyphs: LayoutGlyph[], options: LayoutRunOptions): LayoutRunResult {
  const { stretch, origin = 0 } = options;
  const axis = options.axis ?? 'x';
  if (axis !== 'x') {
    throw new Error(`layoutRun: axis '${axis}' not supported (only 'x')`);
  }

  const out: LayoutGlyphResult[] = [];
  let cursor = origin;

  for (const g of glyphs) {
    const kern = (g.kernBefore ?? 0) * stretch; // empty → fully stretchy
    cursor += kern;

    const remap = buildRemap(g.profile, {
      min: g.bounds.min,
      max: g.bounds.max,
      stretch,
    });

    // remap anchors ink-left at bounds.min; shift the frame so it lands at the
    // stretched left side bearing.
    const penX = cursor + g.bounds.min * (stretch - 1);
    const inkLeft = penX + remap.remap(g.bounds.min);
    const inkRight = penX + remap.remap(g.bounds.max);

    const advance = g.advanceWidth * stretch;

    out.push({ penX, advance, kern, inkLeft, inkRight, remap });
    cursor += advance;
  }

  return { glyphs: out, width: cursor - origin };
}

/**
 * lut.ts — buildRemap + the normalized GPU LUT contract.
 *
 * Turns a static flex profile + a per-frame stretch ratio into a monotonic 1D
 * coordinate remap. This is the ONLY math that runs per frame (O(slices)); it
 * is identical across the WebGL, SVG and VF tiers.
 *
 * Compression guard (stretch < 1): rigid slices must never invert. Each slice's
 * shrink is clamped to 99.9% of its width and the deficit is water-filled over
 * slices that still have capacity.
 */
import type { FlexLUT, Remap } from './types';

export interface BuildRemapOptions {
  min: number;
  max: number;
  stretch: number;
}

export function buildRemap(
  flex: Float32Array | number[],
  { min, max, stretch }: BuildRemapOptions,
): Remap {
  const N = flex.length;
  const W = max - min;
  const w = W / N; // original slice width
  const E = W * (stretch - 1); // total extra space (negative = compress)

  let sumF = 0;
  for (let i = 0; i < N; i++) sumF += flex[i];

  // Per-slice extra space.
  const e = new Float64Array(N);
  if (sumF < 1e-9) {
    // Fully rigid glyph → degrade to uniform scaling (Pagurek's observation).
    for (let i = 0; i < N; i++) e[i] = E / N;
  } else {
    for (let i = 0; i < N; i++) e[i] = (E * flex[i]) / sumF;
  }

  // Compression guard: no slice may shrink below 0.1% of its width.
  if (E < 0) {
    const floor = -w * 0.999;
    for (let pass = 0; pass < 4; pass++) {
      let deficit = 0;
      let capacity = 0;
      for (let i = 0; i < N; i++) {
        if (e[i] < floor) {
          deficit += e[i] - floor;
          e[i] = floor;
        } else if (e[i] > floor) {
          capacity += flex[i];
        }
      }
      if (deficit === 0 || capacity < 1e-9) break;
      for (let i = 0; i < N; i++) {
        if (e[i] > floor) e[i] += (deficit * flex[i]) / capacity;
      }
    }
  }

  // Original-space slice boundaries — the SVG tier splits béziers against these.
  const boundaries = new Float64Array(N + 1);
  for (let i = 0; i <= N; i++) boundaries[i] = min + i * w;

  // Stretched cumulative boundaries. Origin anchored at `min`; alignment
  // (center/right growth) is the renderer's concern.
  const sb = new Float64Array(N + 1);
  sb[0] = min;
  for (let i = 0; i < N; i++) sb[i + 1] = sb[i] + w + e[i];

  function remap(x: number): number {
    const u = (x - min) / W; // normalized 0..1
    if (u <= 0) return sb[0] + u * (w + e[0]) * N; // linear extrapolation
    if (u >= 1) return sb[N] + (u - 1) * (w + e[N - 1]) * N;
    const f = u * N;
    const i = Math.min(N - 1, Math.floor(f));
    const t = f - i;
    return sb[i] + t * (w + e[i]);
  }

  function toNormalizedLUT(): FlexLUT {
    const total = sb[N] - sb[0];
    const lut = new Float32Array(N + 1);
    for (let i = 0; i <= N; i++) lut[i] = total === 0 ? i / N : (sb[i] - sb[0]) / total;
    // Guard the endpoints against float drift so assertLUT is exact.
    lut[0] = 0;
    lut[N] = 1;
    return lut;
  }

  return { remap, boundaries, stretchedBoundaries: sb, extras: e, sliceWidth: w, toNormalizedLUT };
}

/**
 * Assert the FlexLUT contract: Float32Array length ≥ 2, lut[0]===0,
 * lut[last]===1 (±tol), monotonic non-decreasing. Throws on violation.
 */
export function assertLUT(lut: FlexLUT, tol = 1e-6): void {
  if (!(lut instanceof Float32Array)) {
    throw new TypeError('FlexLUT must be a Float32Array');
  }
  if (lut.length < 2) {
    throw new RangeError(`FlexLUT must have length ≥ 2 (got ${lut.length})`);
  }
  if (Math.abs(lut[0] - 0) > tol) {
    throw new RangeError(`FlexLUT[0] must be 0 (got ${lut[0]})`);
  }
  const last = lut.length - 1;
  if (Math.abs(lut[last] - 1) > tol) {
    throw new RangeError(`FlexLUT[N] must be 1 (got ${lut[last]})`);
  }
  for (let i = 1; i < lut.length; i++) {
    if (lut[i] < lut[i - 1] - tol) {
      throw new RangeError(
        `FlexLUT not monotonic at ${i}: ${lut[i - 1]} → ${lut[i]} (fold-over is GPU-unsafe)`,
      );
    }
  }
}

/**
 * sampling/outline.ts — ARC-LENGTH-UNIFORM outline sampling.
 *
 * Upgrade over the reference's t-uniform sampling (01-flex-profile.mjs line 42
 * TODO): samples are spaced by constant arc length along each contour, so
 * curved regions and long straights get proportional coverage — no clustering
 * near cusps, no starvation on long lines. Tangents are analytic (exact).
 *
 * Output shape is unchanged: { samples:[{x,y,tx,ty(unit)}], polygons:[ring...] }.
 */
import type { PathCommand, SampledOutline, BBox } from '../types';
import { commandsToContours, evalSegment } from '../geometry/segments';
import type { Segment } from '../geometry/segments';

const FINE = 16; // sub-steps per segment for the arc-length table

interface FineTable {
  ts: number[]; // parameter at each fine vertex
  cum: number[]; // cumulative arc length at each fine vertex
  length: number;
}

/** Build a cumulative arc-length table for one segment via fine chords. */
function fineTable(seg: Segment): FineTable {
  const ts: number[] = [];
  const cum: number[] = [];
  let prev = evalSegment(seg, 0);
  let acc = 0;
  ts.push(0);
  cum.push(0);
  for (let i = 1; i <= FINE; i++) {
    const t = i / FINE;
    const p = evalSegment(seg, t);
    acc += Math.hypot(p.x - prev.x, p.y - prev.y);
    ts.push(t);
    cum.push(acc);
    prev = p;
  }
  return { ts, cum, length: acc };
}

/** Invert arc length → parameter t within a segment (linear between fine vertices). */
function tAtArc(table: FineTable, d: number): number {
  const { ts, cum } = table;
  if (d <= 0) return 0;
  if (d >= table.length) return 1;
  // linear scan (FINE is small)
  for (let i = 1; i < cum.length; i++) {
    if (cum[i] >= d) {
      const seg = cum[i] - cum[i - 1];
      const frac = seg > 1e-12 ? (d - cum[i - 1]) / seg : 0;
      return ts[i - 1] + frac * (ts[i] - ts[i - 1]);
    }
  }
  return 1;
}

export interface SampleOptions {
  /** Target boundary samples per segment (distributed by arc length). */
  samplesPerSegment?: number;
}

/**
 * Sample an outline into a boundary tangent field + point-in-glyph polygons.
 * Accepts a positional number (ref-compatible) or an options object.
 */
export function sampleOutline(
  commands: PathCommand[],
  opts: number | SampleOptions = 24,
): SampledOutline {
  const samplesPerSegment = typeof opts === 'number' ? opts : opts.samplesPerSegment ?? 24;
  const contours = commandsToContours(commands);
  const samples: SampledOutline['samples'] = [];
  const polygons: SampledOutline['polygons'] = [];

  for (const segs of contours) {
    if (segs.length === 0) continue;
    const tables = segs.map(fineTable);
    let L = 0;
    for (const t of tables) L += t.length;
    if (L <= 1e-9) continue;

    const count = Math.max(8, Math.round(segs.length * samplesPerSegment));
    const spacing = L / count;

    const ring: Array<[number, number]> = [];
    let carry = 0; // arc distance into the current segment before the next sample

    for (let si = 0; si < segs.length; si++) {
      const seg = segs[si];
      const table = tables[si];
      const len = table.length;
      let d = carry;
      while (d < len - 1e-9) {
        const t = tAtArc(table, d);
        const p = evalSegment(seg, t);
        ring.push([p.x, p.y]);
        const l = Math.hypot(p.tx, p.ty);
        if (l > 1e-9) samples.push({ x: p.x, y: p.y, tx: p.tx / l, ty: p.ty / l });
        d += spacing;
      }
      carry = d - len; // leftover distance carried into the next segment
    }

    if (ring.length >= 3) polygons.push(ring);
  }

  return { samples, polygons };
}

/** Axis-aligned bounding box of the sampled boundary. */
export function sampleBounds(outline: SampledOutline): BBox {
  let minX = Infinity, maxX = -Infinity, minY = Infinity, maxY = -Infinity;
  for (const s of outline.samples) {
    if (s.x < minX) minX = s.x;
    if (s.x > maxX) maxX = s.x;
    if (s.y < minY) minY = s.y;
    if (s.y > maxY) maxY = s.y;
  }
  return { minX, maxX, minY, maxY };
}

/**
 * spatial/kdtree.ts — static 2D k-d tree for nearest-boundary lookup.
 *
 * Replaces the reference's O(n) brute-force nearestSample with O(log n)
 * average queries. Built in-house (no dependency), stored in flat typed
 * arrays for cache locality.
 *
 * PARITY GUARANTEE: nearest() returns the SAME sample index as brute force,
 * including ties — ties are broken toward the LOWEST index, and pruning uses
 * `<=` so equal-distance branches are still explored. This is required: the
 * accelerated path must not alter flex results (see the T2 parity test).
 */

export class KDTree {
  private readonly xs: Float64Array;
  private readonly ys: Float64Array;
  private readonly idx: Int32Array; // node order → original sample index
  private readonly axisOf: Uint8Array; // split axis per node position
  private readonly n: number;

  constructor(points: ArrayLike<{ x: number; y: number }>) {
    this.n = points.length;
    this.xs = new Float64Array(this.n);
    this.ys = new Float64Array(this.n);
    this.idx = new Int32Array(this.n);
    this.axisOf = new Uint8Array(this.n);
    const order = new Int32Array(this.n);
    for (let i = 0; i < this.n; i++) {
      this.xs[i] = points[i].x;
      this.ys[i] = points[i].y;
      order[i] = i;
    }
    if (this.n > 0) this.build(order, 0, this.n, 0);
  }

  /** Recursively partition `order[lo,hi)` into a balanced tree (median split). */
  private build(order: Int32Array, lo: number, hi: number, depth: number): void {
    if (lo >= hi) return;
    const axis = depth & 1; // 0 = x, 1 = y
    const mid = (lo + hi) >> 1;
    this.nthElement(order, lo, hi, mid, axis);
    // Node stored at position `mid`: remember its original index + split axis.
    this.idx[mid] = order[mid];
    this.axisOf[mid] = axis;
    this.build(order, lo, mid, depth + 1);
    this.build(order, mid + 1, hi, depth + 1);
  }

  private coord(sampleIndex: number, axis: number): number {
    return axis === 0 ? this.xs[sampleIndex] : this.ys[sampleIndex];
  }

  /** Quickselect: partition so order[k] holds the k-th smallest along axis. */
  private nthElement(order: Int32Array, lo: number, hi: number, k: number, axis: number): void {
    let l = lo;
    let r = hi - 1;
    while (l < r) {
      const pivot = this.coord(order[(l + r) >> 1], axis);
      let i = l;
      let j = r;
      while (i <= j) {
        while (this.coord(order[i], axis) < pivot) i++;
        while (this.coord(order[j], axis) > pivot) j--;
        if (i <= j) {
          const t = order[i];
          order[i] = order[j];
          order[j] = t;
          i++;
          j--;
        }
      }
      if (k <= j) r = j;
      else if (k >= i) l = i;
      else break;
    }
  }

  /**
   * Nearest sample index to (qx,qy). Returns -1 if the tree is empty.
   * Exact; lowest-index tie-break to match brute force.
   */
  nearest(qx: number, qy: number): number {
    if (this.n === 0) return -1;
    this.bestDist = Infinity;
    this.bestIdx = -1;
    this.search(0, this.n, qx, qy);
    return this.bestIdx;
  }

  private bestDist = Infinity;
  private bestIdx = -1;

  private search(lo: number, hi: number, qx: number, qy: number): void {
    if (lo >= hi) return;
    const mid = (lo + hi) >> 1;
    const si = this.idx[mid];
    const dx = this.xs[si] - qx;
    const dy = this.ys[si] - qy;
    const d = dx * dx + dy * dy;
    if (d < this.bestDist || (d === this.bestDist && si < this.bestIdx)) {
      this.bestDist = d;
      this.bestIdx = si;
    }
    const axis = this.axisOf[mid];
    const delta = axis === 0 ? qx - this.xs[si] : qy - this.ys[si];
    const near = delta < 0;
    // Descend the near side first.
    if (near) this.search(lo, mid, qx, qy);
    else this.search(mid + 1, hi, qx, qy);
    // Explore the far side only if the splitting plane is within best radius.
    // `<=` (not `<`) keeps equal-distance candidates reachable for tie-break.
    if (delta * delta <= this.bestDist) {
      if (near) this.search(mid + 1, hi, qx, qy);
      else this.search(lo, mid, qx, qy);
    }
  }
}

/**
 * types.ts — shared analysis-core types + the worker protocol.
 *
 * All types here are erasable (interfaces / unions only) so Node's native
 * TypeScript type-stripping runs them with no build step.
 */

// ------------------------------------------------------------ outline commands

/** opentype.js-shaped path command. */
export interface PathCommand {
  type: 'M' | 'L' | 'Q' | 'C' | 'Z';
  x?: number;
  y?: number;
  x1?: number;
  y1?: number;
  x2?: number;
  y2?: number;
}

export type Axis = 'x' | 'y';

/** A boundary sample: position + UNIT tangent. */
export interface BoundarySample {
  x: number;
  y: number;
  tx: number;
  ty: number;
}

/** Result of sampling an outline. */
export interface SampledOutline {
  /** Flat boundary samples with unit tangents (the tangent field). */
  samples: BoundarySample[];
  /** Per-contour point rings [x,y][] for winding / point-in-glyph tests. */
  polygons: Array<Array<[number, number]>>;
}

export interface BBox {
  minX: number;
  minY: number;
  maxX: number;
  maxY: number;
}

/** 1D bounds along one axis. */
export interface Bounds1D {
  min: number;
  max: number;
}

// --------------------------------------------------------------- LUT contract

/**
 * FlexLUT — THE cross-tier GPU interface.
 *
 * A normalized cumulative remap: a Float32Array of length N+1 where
 *   lut[0]   === 0            (±1e-6)
 *   lut[N]   === 1            (±1e-6)
 *   lut[i+1] >= lut[i]        (monotonic non-decreasing — GPU-safe, no folds)
 *
 * Shader usage:  remapped = mix(lut[i], lut[i+1], fract(u * N));  // u ∈ [0,1]
 *
 * Consumed identically by the WebGL, SVG and VF tiers. Changing this shape is
 * an architect-level decision (see CLAUDE.md hard rule 3).
 */
export type FlexLUT = Float32Array;

/** Return type of buildRemap(). */
export interface Remap {
  /** Map an ORIGINAL axis coordinate to its stretched position. */
  remap: (x: number) => number;
  /**
   * Slice boundaries in ORIGINAL coordinate space: boundaries[i] = min + i*w.
   * The SVG tier splits béziers against these (see refs/examples/05-svg-tier).
   */
  boundaries: Float64Array;
  /**
   * Cumulative slice boundaries in STRETCHED space (boundaries after the
   * remap is applied). Used to prove non-inversion under compression.
   */
  stretchedBoundaries: Float64Array;
  /** Per-slice extra space distributed by the flex profile. */
  extras: Float64Array;
  /** Original slice width (W / N). */
  sliceWidth: number;
  /** Build the normalized GPU LUT (the FlexLUT contract). */
  toNormalizedLUT: () => FlexLUT;
}

