/**
 * winding.ts — nonzero winding number + winding-aware sample filtering.
 *
 * Two jobs:
 *  1. windingNumber() / pointInside(): nonzero-rule containment. Fonts fill
 *     with the nonzero rule (TrueType & CFF); even-odd wrongly treats a
 *     self-overlap as a hole. Nonzero agrees with even-odd on all
 *     non-overlapping contours, so this is a safe upgrade.
 *  2. filterVisibleSamples(): drop boundary samples that sit on INVISIBLE
 *     self-intersection segments (the Playfair Display 'W' case, RESEARCH §5.2).
 *     A visible boundary sample has exactly one side inside the filled shape;
 *     a buried sample (inside an overlap) has BOTH sides inside — its tangent
 *     is not on the real silhouette and would corrupt the flex minima.
 */
import type { BoundarySample } from './types';

type Ring = Array<[number, number]>;

/** isLeft > 0 if p2 is left of the directed line p0→p1. */
function isLeft(p0x: number, p0y: number, p1x: number, p1y: number, px: number, py: number): number {
  return (p1x - p0x) * (py - p0y) - (px - p0x) * (p1y - p0y);
}

/** Nonzero winding number of (x,y) w.r.t. all rings (Dan Sunday's algorithm). */
export function windingNumber(x: number, y: number, rings: Ring[]): number {
  let wn = 0;
  for (const ring of rings) {
    const n = ring.length;
    if (n < 3) continue;
    for (let i = 0, j = n - 1; i < n; j = i++) {
      const [xi, yi] = ring[i];
      const [xj, yj] = ring[j];
      if (yj <= y) {
        if (yi > y && isLeft(xj, yj, xi, yi, x, y) > 0) wn++;
      } else {
        if (yi <= y && isLeft(xj, yj, xi, yi, x, y) < 0) wn--;
      }
    }
  }
  return wn;
}

/** Nonzero-rule point-in-glyph test. */
export function pointInside(x: number, y: number, rings: Ring[]): boolean {
  return windingNumber(x, y, rings) !== 0;
}

/**
 * y-banded winding index — makes repeated winding queries near-linear.
 *
 * A horizontal-ray winding query at height y is only affected by edges whose
 * vertical span contains y, so bucketing edges by y-band is EXACT (not an
 * approximation): winding() returns the same value as windingNumber().
 */
export class WindingIndex {
  private readonly x0: Float64Array;
  private readonly y0: Float64Array;
  private readonly x1: Float64Array;
  private readonly y1: Float64Array;
  private readonly bands: Int32Array[];
  private readonly yMin: number;
  private readonly invBandH: number;
  private readonly B: number;

  constructor(rings: Ring[]) {
    // Collect edges.
    const ax0: number[] = [];
    const ay0: number[] = [];
    const ax1: number[] = [];
    const ay1: number[] = [];
    let yMin = Infinity;
    let yMax = -Infinity;
    for (const ring of rings) {
      const n = ring.length;
      if (n < 3) continue;
      for (let i = 0, j = n - 1; i < n; j = i++) {
        const [xi, yi] = ring[i];
        const [xj, yj] = ring[j];
        ax0.push(xj);
        ay0.push(yj);
        ax1.push(xi);
        ay1.push(yi);
        if (yi < yMin) yMin = yi;
        if (yj < yMin) yMin = yj;
        if (yi > yMax) yMax = yi;
        if (yj > yMax) yMax = yj;
      }
    }
    const E = ax0.length;
    this.x0 = Float64Array.from(ax0);
    this.y0 = Float64Array.from(ay0);
    this.x1 = Float64Array.from(ax1);
    this.y1 = Float64Array.from(ay1);
    this.yMin = yMin;
    const yh = yMax - yMin;
    this.B = Math.max(1, Math.min(256, Math.round(Math.sqrt(E || 1))));
    this.invBandH = yh > 0 ? this.B / yh : 0;

    // Bucket edges into the y-bands their span covers.
    const lists: number[][] = Array.from({ length: this.B }, () => []);
    for (let e = 0; e < E; e++) {
      const lo = Math.min(this.y0[e], this.y1[e]);
      const hi = Math.max(this.y0[e], this.y1[e]);
      let bLo = this.bandOf(lo);
      let bHi = this.bandOf(hi);
      if (bLo > bHi) {
        const t = bLo;
        bLo = bHi;
        bHi = t;
      }
      for (let b = bLo; b <= bHi; b++) lists[b].push(e);
    }
    this.bands = lists.map((l) => Int32Array.from(l));
  }

  private bandOf(y: number): number {
    const b = Math.floor((y - this.yMin) * this.invBandH);
    return b < 0 ? 0 : b >= this.B ? this.B - 1 : b;
  }

  winding(x: number, y: number): number {
    const band = this.bands[this.bandOf(y)];
    if (!band) return 0;
    let wn = 0;
    for (let idx = 0; idx < band.length; idx++) {
      const e = band[idx];
      const xj = this.x0[e];
      const yj = this.y0[e];
      const xi = this.x1[e];
      const yi = this.y1[e];
      if (yj <= y) {
        if (yi > y && isLeft(xj, yj, xi, yi, x, y) > 0) wn++;
      } else {
        if (yi <= y && isLeft(xj, yj, xi, yi, x, y) < 0) wn--;
      }
    }
    return wn;
  }

  inside(x: number, y: number): boolean {
    return this.winding(x, y) !== 0;
  }
}

/**
 * Keep only samples on the VISIBLE silhouette. A sample is visible when a
 * tiny nudge along its normal lands inside the shape on exactly one side.
 *
 * @param eps  nudge distance in glyph units (defaults to 1e-3 of the bbox diag)
 */
export function filterVisibleSamples(
  samples: BoundarySample[],
  rings: Ring[],
  eps?: number,
): BoundarySample[] {
  if (samples.length === 0) return samples;
  let e = eps ?? 0;
  if (e <= 0) {
    let minX = Infinity, minY = Infinity, maxX = -Infinity, maxY = -Infinity;
    for (const s of samples) {
      if (s.x < minX) minX = s.x;
      if (s.x > maxX) maxX = s.x;
      if (s.y < minY) minY = s.y;
      if (s.y > maxY) maxY = s.y;
    }
    e = Math.max(1e-4, Math.hypot(maxX - minX, maxY - minY) * 1e-3);
  }
  const index = new WindingIndex(rings);
  const out: BoundarySample[] = [];
  for (const s of samples) {
    // normal = 90° rotation of the unit tangent
    const nx = -s.ty;
    const ny = s.tx;
    const insideA = index.inside(s.x + e * nx, s.y + e * ny);
    const insideB = index.inside(s.x - e * nx, s.y - e * ny);
    if (insideA !== insideB) out.push(s); // exactly one side inside → on silhouette
  }
  // Degenerate guard: if filtering nuked everything (pathological outline),
  // fall back to the unfiltered set rather than returning an empty field.
  return out.length > 0 ? out : samples;
}

/**
 * dom/overlay.ts — the SHARED accessibility/SEO overlay (RESEARCH §3 invariant;
 * CLAUDE.md rule 6). Every render tier (SVG here, WebGL/VF later) mounts through
 * this so the a11y/SEO/selection contract is implemented ONCE.
 *
 * Contract:
 *  - The ORIGINAL text stays in the DOM, moved into a "text layer" that is made
 *    VISUALLY HIDDEN but NOT removed from the accessibility tree: it keeps its
 *    box (in flow), stays selectable, and is read by screen readers / crawlers.
 *    We use `color: transparent` (glyphs invisible, box + selection + a11y
 *    intact) — deliberately NOT `display:none` and NOT `visibility:hidden`,
 *    both of which drop the node from a11y/selection.
 *  - The render layer (the caller's <svg>/<canvas>) is `aria-hidden="true"`,
 *    `pointer-events:none` and `user-select:none`, so selection, find-in-page
 *    and screen readers all target the real text underneath.
 *  - The host gets layout+paint containment and its own isolation so per-frame
 *    paints from the render layer stay scoped (no page-wide invalidation).
 *
 * Wrap policy (RESEARCH §5 risk 1; CLAUDE.md rule 7 — no per-frame reflow):
 *  - 'nowrap'  : force `white-space:nowrap` on the text layer so the line never
 *                wraps, at any stretch.
 *  - 'reserve' : reserve horizontal space for the MAX-stretch box up front
 *                (min-width = naturalWidth × maxStretchRatio) so following
 *                content does not reflow as the render layer stretches. Sized
 *                from the CONFIGURED max ratio (default 4.5).
 *
 * Reserve basis (`options.reserveBasis`, shared cross-tier toggle):
 *  - 'tier-capability' (default): reserve the widest box THIS tier can actually
 *    paint. For the overlay (SVG/WebGL) that IS `naturalWidth × maxStretchRatio`
 *    — these tiers can stretch to the configured max, so their tier capability
 *    equals the uniform basis and the two modes coincide here.
 *  - 'uniform': every tier reserves `naturalWidth × maxStretchRatio` for
 *    cross-tier visual consistency. Identical to 'tier-capability' for the
 *    overlay; the difference is only observable in the axis-bounded VF tier.
 *
 * DOM-injectable (`options.document`) so it runs under jsdom / SSR shims.
 */

export type WrapMode = 'nowrap' | 'reserve';

/**
 * How `wrap:'reserve'` sizes its reserved box, shared across all tiers.
 *  - 'tier-capability': reserve what THIS tier can paint (axis-bounded for VF,
 *    max-ratio for the overlay tiers).
 *  - 'uniform': every tier reserves `naturalWidth × maxStretchRatio`, even when
 *    a tier cannot reach that width (VF then leaves a permanent gap — the
 *    accepted tradeoff for cross-tier visual consistency).
 */
export type ReserveBasis = 'tier-capability' | 'uniform';

export interface OverlayOptions {
  /** Element whose text is being stretched. Its current text becomes the source. */
  host: HTMLElement;
  /** The render layer to overlay (an <svg> for the SVG tier). */
  renderLayer: SVGElement | HTMLElement;
  /** Override the source text (defaults to host.textContent). */
  text?: string;
  /** Wrap behavior. Default 'nowrap'. */
  wrap?: WrapMode;
  /** Max stretch ratio the render layer can reach — sizes `reserve`. Default 4.5. */
  maxStretchRatio?: number;
  /**
   * How `wrap:'reserve'` sizes the reserved box. Default 'tier-capability'.
   * For the overlay (Tiers 1/2) both bases resolve to `maxStretchRatio`, so the
   * value does not change the reserved width here — it is threaded through for a
   * uniform cross-tier option surface (the VF tier is where the two diverge).
   */
  reserveBasis?: ReserveBasis;
  /** Injectable document (jsdom / SSR). Defaults to host.ownerDocument. */
  document?: Document;
}

export interface Overlay {
  readonly host: HTMLElement;
  /** Visually-hidden, still-selectable, still-in-a11y-tree real text. */
  readonly textLayer: HTMLElement;
  readonly renderLayer: SVGElement | HTMLElement;
  readonly text: string;
  readonly wrap: WrapMode;
  /** Last measured natural (unstretched) width in px, or null before measure(). */
  readonly naturalWidth: number | null;
  /**
   * READ-phase work: measure the natural text width and (for 'reserve') apply
   * the reserved min-width. Idempotent; call inside `ticker.read`.
   */
  measure(): void;
  /** Restore the host to its original DOM + inline styles. Leaks nothing. */
  destroy(): void;
}

interface SavedStyle {
  el: HTMLElement | SVGElement;
  cssText: string;
}

function setStyles(el: HTMLElement | SVGElement, styles: Record<string, string>): void {
  for (const [k, v] of Object.entries(styles)) el.style.setProperty(k, v);
}

export function createOverlay(options: OverlayOptions): Overlay {
  const host = options.host;
  const doc = options.document ?? host.ownerDocument;
  if (!doc) throw new Error('createOverlay: no document available');
  const renderLayer = options.renderLayer;
  const wrap: WrapMode = options.wrap ?? 'nowrap';
  const maxStretchRatio = options.maxStretchRatio ?? 4.5;
  const reserveBasis: ReserveBasis = options.reserveBasis ?? 'tier-capability';
  const text = options.text ?? host.textContent ?? '';

  const saved: SavedStyle[] = [];
  const save = (el: HTMLElement | SVGElement): void => {
    saved.push({ el, cssText: el.getAttribute('style') ?? '' });
  };

  // --- host: containment + isolation + a positioning context for the layers.
  save(host);
  const hostPosition =
    doc.defaultView?.getComputedStyle(host).position ?? host.style.position ?? 'static';
  setStyles(host, {
    contain: 'layout paint',
    isolation: 'isolate',
  });
  if (hostPosition === 'static') host.style.setProperty('position', 'relative');

  // --- text layer: move the real text into it, keep it selectable + in a11y.
  const originalNodes: ChildNode[] = Array.from(host.childNodes);
  const textLayer = doc.createElement('span');
  textLayer.setAttribute('data-fontuccine', 'text');
  setStyles(textLayer, {
    color: 'transparent',
    // keep selection + caret usable on the invisible text
    '-webkit-user-select': 'text',
    'user-select': 'text',
    'white-space': wrap === 'nowrap' ? 'nowrap' : 'normal',
  });
  for (const n of originalNodes) textLayer.appendChild(n);
  host.appendChild(textLayer);

  // --- render layer: on top, inert to a11y + pointer + selection.
  save(renderLayer);
  renderLayer.setAttribute('aria-hidden', 'true');
  setStyles(renderLayer, {
    position: 'absolute',
    top: '0',
    left: '0',
    overflow: 'visible',
    'pointer-events': 'none',
    '-webkit-user-select': 'none',
    'user-select': 'none',
  });
  if (renderLayer.parentNode !== host) host.appendChild(renderLayer);

  let naturalWidth: number | null = null;

  function measure(): void {
    // READ ONLY. One getBoundingClientRect on the text layer.
    const w = textLayer.getBoundingClientRect().width;
    if (Number.isFinite(w) && w > 0) naturalWidth = w;
    if (wrap === 'reserve' && naturalWidth != null) {
      // Reserve the widest box the render layer can occupy at full stretch so
      // downstream layout never reflows mid-interaction. The SVG/WebGL tiers can
      // paint the full configured max ratio, so BOTH reserve bases resolve to
      // `maxStretchRatio` here (only the axis-bounded VF tier differs).
      const factor = reserveBasis === 'uniform' ? maxStretchRatio : maxStretchRatio;
      host.style.setProperty('min-width', `${naturalWidth * factor}px`);
    }
  }

  function destroy(): void {
    // Move the real text nodes back to the host, drop our layers.
    if (textLayer.parentNode === host) {
      for (const n of Array.from(textLayer.childNodes)) host.insertBefore(n, textLayer);
      host.removeChild(textLayer);
    }
    if (renderLayer.parentNode === host) host.removeChild(renderLayer);
    // Restore inline styles exactly.
    for (const s of saved) {
      if (s.cssText) s.el.setAttribute('style', s.cssText);
      else s.el.removeAttribute('style');
    }
    renderLayer.removeAttribute('aria-hidden');
  }

  return {
    host,
    textLayer,
    renderLayer,
    text,
    wrap,
    get naturalWidth() {
      return naturalWidth;
    },
    measure,
    destroy,
  };
}

/**
 * engine/attach.ts — `Fontuccine.attach(target, config)`: the `.` entry
 * orchestrator that turns a config + a DOM target into a live stretch instance.
 *
 * Pipeline: config → StretchController (created synchronously so `.set()` and
 * ticker liveness are live immediately) → font load (lazy) → static per-glyph
 * analysis → tier selection → renderer → renderer.attach().
 *
 * CARRIED-FORWARD GUARANTEE (verified in test/engine-guarantee): the renderer is
 * ALWAYS driven by a StretchController, which is the ONLY registrant of a ticker
 * activity predicate (`() => !smoother.settled`). Renderers register NO liveness
 * of their own, so once the spring settles the shared ticker self-parks. This
 * file must never introduce a renderer-owned activity predicate.
 *
 * SSR: importing this module touches no `window`/`document`. All capability
 * probing + DOM work happens inside `attach()`, and `attach()` early-returns an
 * inert instance when there is no document (so wrappers can call it on the server
 * and simply get a no-op until they re-run in a browser effect).
 */
import { createStretchController } from '../interaction/stretch-controller';
import type { StretchController } from '../interaction/stretch-controller';
import { ticker as sharedTicker } from '../interaction/ticker';
import { prefersReducedMotion } from '../interaction/reduced-motion';
import { detectWebGL2 } from '../webgl/gl/capability';
import { probeTier0, cssSupportsFontStretchPercentage } from '../vf/probe';
import { createSvgRenderer } from '../svg/renderer';
import { createWebglRenderer } from '../webgl/renderer';
import { createVfRenderer } from '../vf/renderer';
import { AnalysisClient } from '../worker/client';
import { DEFAULT_PARAMS } from '../core/types';
import { loadEngineFont } from './font-load';
import { buildGlyphs } from './glyphs';
import { selectTier } from './tier-select';
import type { ResolvedTier } from './tier-select';
import type { FontuccineConfig, Instance } from './types';

interface TierRenderer {
  attach(): void;
  destroy(): void;
}

function resolveElement(target: string | Element, doc: Document | undefined): HTMLElement {
  if (typeof target === 'string') {
    if (!doc) throw new Error('fontuccine: cannot resolve a selector without a document');
    const el = doc.querySelector(target);
    if (!el) throw new Error(`fontuccine: no element matches "${target}"`);
    return el as HTMLElement;
  }
  return target as HTMLElement;
}

function defaultIsPrint(doc: Document | undefined): boolean {
  const view = doc?.defaultView ?? (typeof window !== 'undefined' ? window : undefined);
  try {
    return !!view?.matchMedia && view.matchMedia('print').matches;
  } catch {
    return false;
  }
}

export function attach(target: string | Element, config: FontuccineConfig = {}): Instance {
  const doc =
    config.document ?? (typeof document !== 'undefined' ? document : undefined);

  // SSR / no-DOM: hand back an inert instance (wrappers re-attach in an effect).
  if (!doc && typeof target === 'string') {
    return inertInstance('no document (SSR): attach is a no-op until a browser effect');
  }

  const el = resolveElement(target, doc);
  let direction = el.dir;
  try {
    direction = doc?.defaultView?.getComputedStyle(el).direction || direction;
  } catch {
    // A cross-realm or test element may not support computed styles.
  }
  if (direction === 'rtl') {
    return inertInstance('rtl direction: using static native text to preserve shaping');
  }
  const ticker = config.ticker ?? sharedTicker;
  const unitsPerEm = config.unitsPerEm ?? 1000;

  const min = config.minStretchRatio ?? 1;
  const max = config.maxStretchRatio ?? 4.5;
  const resting = Math.min(Math.max(1, min), max);

  const respectRM = config.respectReducedMotion ?? true;
  const isRM = config.isReducedMotion ?? prefersReducedMotion;

  // --- StretchController (synchronous): owns ticker liveness + `.set()`.
  const controller: StretchController = createStretchController({
    ...(config.trigger ? { trigger: config.trigger } : {}),
    ...(config.axis ? { axis: config.axis } : {}),
    maxStretchRatio: max,
    minStretchRatio: min,
    ...(config.velocityToStretch != null ? { velocityToStretch: config.velocityToStretch } : {}),
    ...(config.proximityRadius != null ? { proximityRadius: config.proximityRadius } : {}),
    ...(config.physics ? { physics: config.physics } : {}),
    ...(config.easingCurve ? { easingCurve: config.easingCurve } : {}),
    ...(config.easingDuration != null ? { easingDuration: config.easingDuration } : {}),
    respectReducedMotion: respectRM,
    isReducedMotion: isRM,
    element: el,
    ticker,
    restingValue: resting,
  });

  const client = config.analysisClient ?? new AnalysisClient();
  const ownsClient = !config.analysisClient;

  let destroyed = false;
  let selectedTier: ResolvedTier | null = null;
  let renderer: TierRenderer | null = null;
  const notes: string[] = [];
  let resolveReady!: () => void;
  const ready = new Promise<void>((r) => {
    resolveReady = r;
  });

  async function build(): Promise<void> {
    try {
      const reducedMotion = respectRM && isRM();
      const print = (config.isPrint ?? (() => defaultIsPrint(doc)))();
      const webgl2 = (config.detectWebGL2Support ?? (() => detectWebGL2().supported))();
      const compression = min < 1;

      // Load outlines + wdth axis (VF may still win; axis needed to probe it).
      const font = await loadEngineFont({
        ...(config.font ? { font: config.font } : {}),
        ...(config.fontUrl ? { fontUrl: config.fontUrl } : {}),
        ...(config.fontBuffer ? { fontBuffer: config.fontBuffer } : {}),
        ...(config.parsedFont ? { parsedFont: config.parsedFont } : {}),
        ...(config.wdthAxis !== undefined ? { wdthAxis: config.wdthAxis } : {}),
        unitsPerEm,
      });
      if (destroyed) return;

      const vfDecision = probeTier0(font.wdthAxis, {
        maxStretchRatio: max,
        minStretchRatio: min,
        axis: config.axis ?? 'horizontal',
      });
      const vfSupported = vfDecision.supported && cssSupportsFontStretchPercentage();

      const decision = selectTier(config.tier ?? 'auto', {
        webgl2,
        vfSupported,
        reducedMotion,
        print,
        compression,
      });
      selectedTier = decision.tier;
      notes.push(...decision.notes);
      if (destroyed) return;

      if (selectedTier === 'vf') {
        if (!font.wdthAxis) throw new Error('fontuccine: VF selected without a wdth axis');
        renderer = createVfRenderer({
          host: el,
          axis: font.wdthAxis,
          controller,
          wrap: config.wrap ?? 'nowrap',
          reserveBasis: config.reserveBasis ?? 'tier-capability',
          maxStretchRatio: max,
          restingStretch: resting,
          respectReducedMotion: respectRM,
          isReducedMotion: isRM,
          ticker,
          document: doc,
        });
      } else {
        const params = {
          ...DEFAULT_PARAMS,
          slices: config.lutResolution ?? DEFAULT_PARAMS.slices,
          k: config.edgeProtection ?? DEFAULT_PARAMS.k,
        };
        const glyphs = await buildGlyphs(font, config.text ?? el.textContent ?? '', client, params, unitsPerEm);
        if (destroyed) return;

        const common = {
          host: el,
          glyphs,
          controller,
          ...(config.text != null ? { text: config.text } : {}),
          wrap: config.wrap ?? 'nowrap',
          maxStretchRatio: max,
          restingStretch: resting,
          unitsPerEm,
          respectReducedMotion: respectRM,
          isReducedMotion: isRM,
          ticker,
          document: doc,
        };

        if (selectedTier === 'webgl') {
          const webglRenderer = createWebglRenderer({
            ...common,
            ...(config.effects ? { effects: config.effects } : {}),
            ...(config.color ? { color: config.color } : {}),
            ...(config.backend ? { backend: config.backend } : {}),
          });
          if (webglRenderer.supported) {
            renderer = webglRenderer;
          } else {
            webglRenderer.destroy();
            selectedTier = 'svg';
            notes.push('webgl renderer unavailable; fell through to svg');
            renderer = createSvgRenderer(common);
          }
        } else {
          renderer = createSvgRenderer(common);
        }
      }

      if (destroyed) {
        renderer?.destroy();
        renderer = null;
        return;
      }
      renderer.attach();
    } catch (err) {
      notes.push(`build failed: ${(err as Error)?.message ?? String(err)}`);
    } finally {
      resolveReady();
    }
  }

  void build();

  return {
    set(value: number) {
      controller.set(value);
    },
    destroy() {
      if (destroyed) return;
      destroyed = true;
      renderer?.destroy();
      renderer = null;
      controller.destroy();
      if (ownsClient) client.destroy();
    },
    get tier() {
      return selectedTier;
    },
    ready,
    get notes() {
      return notes;
    },
  };
}

function inertInstance(note: string): Instance {
  return {
    set() {},
    destroy() {},
    tier: null,
    ready: Promise.resolve(),
    notes: [note],
  };
}

/**
 * engine/font-load.ts — resolve a font outline source into a ParsedFont + the
 * `wdth` axis, LAZILY.
 *
 * Size discipline (Phase-5 budget): opentype.js and the parser are pulled in via
 * DYNAMIC import here, so they never land in the base `.` bundle — they load only
 * when a font binary must actually be parsed (SVG/WebGL tiers). The VF tier can
 * be selected with just an injected `wdthAxis` and never triggers this path.
 *
 * The frozen `font/parser.ts` is CONSUMED, not modified (CLAUDE.md). It gives us
 * outlines (`.glyph`) and kerning (`.kernPair`); it does not surface `fvar` or
 * blank-glyph advances, so we additionally read those structurally off a raw
 * opentype parse of the SAME bytes (`getWdthAxis`, `advanceOf`). Parsing twice is
 * a one-time, off-hot-path cost.
 */
import type { ParsedFont } from '../font/parser';
import type { WdthAxis } from '../vf/detect';
import { getWdthAxis } from '../vf/detect';
import type { FontSource } from './types';

export interface LoadedFont {
  parsed: ParsedFont;
  wdthAxis: WdthAxis | null;
  /** Advance (font units) for any char, including blanks — undefined when only a
   *  pre-parsed ParsedFont was supplied (no raw font to read blank advances). */
  advanceOf?: (char: string) => number;
}

function toArrayBuffer(view: ArrayBuffer | ArrayBufferView): ArrayBuffer {
  if (view instanceof ArrayBuffer) return view;
  const v = view as ArrayBufferView;
  return v.buffer.slice(v.byteOffset, v.byteOffset + v.byteLength) as ArrayBuffer;
}

function resolveSource(cfg: {
  font?: FontSource;
  fontUrl?: string;
  fontBuffer?: ArrayBuffer | ArrayBufferView;
  parsedFont?: ParsedFont;
  wdthAxis?: WdthAxis | null;
}): FontSource | null {
  if (cfg.font) return cfg.font;
  if (cfg.parsedFont) return { parsed: cfg.parsedFont, wdthAxis: cfg.wdthAxis ?? null };
  if (cfg.fontBuffer) return { buffer: cfg.fontBuffer };
  if (cfg.fontUrl) return { url: cfg.fontUrl };
  return null;
}

export async function loadEngineFont(
  cfg: {
    font?: FontSource;
    fontUrl?: string;
    fontBuffer?: ArrayBuffer | ArrayBufferView;
    parsedFont?: ParsedFont;
    wdthAxis?: WdthAxis | null;
    unitsPerEm?: number;
  },
): Promise<LoadedFont> {
  const src = resolveSource(cfg);
  if (!src) {
    throw new Error(
      'fontuccine: no font source. The SVG/WebGL tiers need outlines — pass ' +
        '`fontUrl`, `fontBuffer`, or `parsedFont` in the config.',
    );
  }
  const unitsPerEm = cfg.unitsPerEm ?? 1000;

  // Pre-parsed injection (advanced / tests): no raw bytes to read blanks from.
  if ('parsed' in src) {
    return { parsed: src.parsed, wdthAxis: src.wdthAxis ?? null };
  }

  const buffer =
    'buffer' in src
      ? toArrayBuffer(src.buffer)
      : await fetch(src.url).then((r) => {
          if (!r.ok) throw new Error(`fontuccine: font fetch failed (${r.status}) for ${src.url}`);
          return r.arrayBuffer();
        });

  // Lazy: opentype.js + the parser load ONLY here (dynamic import → own chunk).
  const [{ parseFont }, otMod] = await Promise.all([
    import('../font/parser'),
    import('opentype.js'),
  ]);
  const opentype = (otMod as { default?: unknown }).default ?? otMod;

  const parsed = parseFont(buffer, { fontSize: unitsPerEm });

  // Raw parse for fvar (wdth) + blank-glyph advances (parser omits both).
  let wdthAxis: WdthAxis | null = cfg.wdthAxis ?? null;
  let advanceOf: ((char: string) => number) | undefined;
  try {
    const otFont = (opentype as { parse(b: ArrayBuffer): unknown }).parse(buffer) as {
      unitsPerEm: number;
      tables?: { fvar?: { axes?: Array<{ tag: string; minValue: number; defaultValue: number; maxValue: number }> } };
      charToGlyph(ch: string): { advanceWidth?: number } | null;
    };
    if (wdthAxis === undefined || wdthAxis === null) wdthAxis = getWdthAxis(otFont);
    const scale = unitsPerEm / otFont.unitsPerEm;
    advanceOf = (char: string): number => {
      const g = otFont.charToGlyph(char);
      return (g?.advanceWidth ?? 0) * scale;
    };
  } catch {
    /* fvar/advance extraction is best-effort; outlines already succeeded */
  }

  return { parsed, wdthAxis, ...(advanceOf ? { advanceOf } : {}) };
}

/**
 * engine/glyphs.ts — turn a run of text + a loaded font into the per-glyph
 * static render inputs shared by the SVG and WebGL tiers (`SvgGlyph`/`WebglGlyph`
 * have the identical shape). Analysis is STATIC per glyph (CLAUDE.md rule 1): it
 * runs once through the AnalysisClient (worker off-thread, or the inline
 * fallback) and is cached there.
 */
import type { AnalysisClient } from '../worker/client';
import type { AnalyzeParams } from '../core/types';
import type { LoadedFont } from './font-load';

/** Shared static render input (⊇ SvgGlyph and WebglGlyph). */
export interface RenderGlyph {
  char: string;
  commands: import('../core/types').PathCommand[];
  flex: Float32Array;
  bounds: import('../core/types').Bounds1D;
  advanceWidth: number;
  bbox: import('../core/types').BBox;
  kernBefore: number;
}

function isBlank(ch: string): boolean {
  return /\s/.test(ch);
}

/**
 * Build one RenderGlyph per character of `text`. Blank glyphs (spaces) carry
 * their advance but no ink (empty commands, all-stretchy flex so slice counts
 * stay uniform across the run). Unmapped/zero-outline non-blank glyphs are
 * skipped. Kerning is read pairwise from the font in glyph units.
 */
export async function buildGlyphs(
  font: LoadedFont,
  text: string,
  client: AnalysisClient,
  params: Pick<AnalyzeParams, 'slices' | 'k'>,
  unitsPerEm: number,
): Promise<RenderGlyph[]> {
  const chars = Array.from(text);
  const out: RenderGlyph[] = [];
  let prev: string | null = null;

  for (const ch of chars) {
    const g = font.parsed.glyph(ch);
    const kernBefore = prev ? font.parsed.kernPair(prev, ch) : 0;

    if (!g) {
      if (isBlank(ch)) {
        const advanceWidth = font.advanceOf ? font.advanceOf(ch) : unitsPerEm * 0.25;
        out.push({
          char: ch,
          commands: [],
          flex: new Float32Array(params.slices).fill(1),
          bounds: { min: 0, max: 0 },
          advanceWidth,
          bbox: { minX: 0, minY: 0, maxX: 0, maxY: 0 },
          kernBefore,
        });
      }
      // non-blank unmapped glyph: nothing to render, still advance the cursor
      prev = ch;
      continue;
    }

    const res = await client.analyze({
      glyphId: ch,
      commands: g.commands,
      advanceWidth: g.advanceWidth,
      axes: ['x'],
      params,
    });
    const px = res.profiles.x;
    if (!px) {
      prev = ch;
      continue;
    }
    out.push({
      char: ch,
      commands: g.commands,
      flex: px.flex,
      bounds: px.bounds,
      advanceWidth: res.advanceWidth,
      bbox: res.bbox,
      kernBefore,
    });
    prev = ch;
  }

  return out;
}

/**
 * engine/tier-select.ts — PURE, Node-testable `tier:'auto'` dispatch + explicit
 * tier fall-through. No DOM, no font, no side effects: the engine gathers the
 * capability flags (WebGL2 probe, VF probe, reduced-motion/print, compression)
 * and this decides the renderer.
 *
 * Dispatch order (RESEARCH §3, §3.1 — locked by the Phase-5 task):
 *   1. WebGL2 + MSDF is PRIMARY when WebGL2 is present and the run is not
 *      reduced-motion / print / effective-compression.
 *   2. VF (`wdth`) is OPPORTUNISTIC — chosen only when WebGL2 is unavailable AND
 *      `probeTier0(...).supported` AND CSS `font-stretch:%` is supported.
 *   3. SVG is the fallback for no-WebGL, reduced-motion, print, opt-in vector
 *      fidelity (explicit `tier:'svg'`), and effective compression
 *      (`minStretchRatio < 1`) — WebGL clamps <1 to identity (§3.1) and VF cannot
 *      compress past `axis.min`, so only the exact-vector SVG tier compresses.
 *
 * Explicit `tier:'webgl'|'svg'|'vf'` forces that tier; if a forced tier DECLINES
 * (WebGL2 absent, or VF unusable on this font/range) the selector falls through
 * to the auto order and records a note (CLAUDE.md rule 9: surfaced to the caller
 * via `instance.notes`).
 */

export type Tier = 'auto' | 'webgl' | 'svg' | 'vf';
export type ResolvedTier = 'webgl' | 'svg' | 'vf';

/** Capability flags the selector reads (all resolved by the engine up front). */
export interface TierCaps {
  /** WebGL2 present per the gl/capability probe. */
  webgl2: boolean;
  /**
   * VF is usable: `probeTier0(...).supported` AND the runtime supports
   * `font-stretch:<percentage>` (`cssSupportsFontStretchPercentage()`).
   */
  vfSupported: boolean;
  /** Reduced-motion is active AND honored (`respectReducedMotion`). */
  reducedMotion: boolean;
  /** Print context (`@media print`). */
  print: boolean;
  /** Effective compression requested (`minStretchRatio < 1`). */
  compression: boolean;
}

export interface TierDecision {
  tier: ResolvedTier;
  /** Human-readable trail of why (fall-through reasons, forced declines). */
  notes: string[];
}

/** The auto order, factored out so forced tiers can fall through to it. */
function auto(caps: TierCaps, notes: string[]): ResolvedTier {
  if (caps.reducedMotion) {
    notes.push('reduced-motion → SVG (static, exact vectors; no per-frame work)');
    return 'svg';
  }
  if (caps.print) {
    notes.push('print → SVG (static exact vectors)');
    return 'svg';
  }
  if (caps.compression) {
    notes.push(
      'minStretchRatio<1 (compression) → SVG (WebGL clamps <1 to identity per §3.1; ' +
        'VF cannot compress past axis.min)',
    );
    return 'svg';
  }
  if (caps.webgl2) return 'webgl';
  if (caps.vfSupported) {
    notes.push('no WebGL2 → VF (opportunistic wdth tier)');
    return 'vf';
  }
  notes.push('no WebGL2 and no usable VF → SVG fallback');
  return 'svg';
}

export function selectTier(requested: Tier, caps: TierCaps): TierDecision {
  const notes: string[] = [];
  switch (requested) {
    case 'webgl':
      if (caps.webgl2) return { tier: 'webgl', notes };
      notes.push("forced tier 'webgl' unavailable (no WebGL2) → falling through to auto order");
      return { tier: auto(caps, notes), notes };
    case 'vf':
      if (caps.vfSupported) return { tier: 'vf', notes };
      notes.push(
        "forced tier 'vf' declined (font exposes no usable wdth axis for the requested " +
          'range, or CSS font-stretch:% unsupported) → falling through to auto order',
      );
      return { tier: auto(caps, notes), notes };
    case 'svg':
      // SVG is always available (pure vectors); it is also the vector-fidelity opt-in.
      return { tier: 'svg', notes };
    case 'auto':
    default:
      return { tier: auto(caps, notes), notes };
  }
}

/**
 * engine/types.ts — the public `Fontuccine.attach` config + instance types.
 *
 * The DOCUMENTED public schema is exactly README.md's "Public API sketch" plus
 * the ONE approved additive field `reserveBasis` (Phase-5 §4). The remaining
 * fields below the divider are ADVANCED / INJECTABLE seams (font source, DI for
 * tests, SSR document) — deliberately NOT part of the documented schema, exactly
 * as `StretchControllerConfig` carries `element`/`ticker`/`stimulus`. They never
 * change the meaning of a documented field.
 */
import type { EffectsConfig, RGBAColor } from '../webgl/types';
import type { WrapMode, ReserveBasis } from '../dom/overlay';
import type { WdthAxis } from '../vf/detect';
import type { ParsedFont } from '../font/parser';
import type { Ticker } from '../interaction/ticker';
import type { AnalysisClient } from '../worker/client';
import type { RenderBackend } from '../webgl/gl/device';
import type { Tier, ResolvedTier } from './tier-select';

export type { Tier, ResolvedTier } from './tier-select';
export type StretchAxis = 'horizontal' | 'vertical' | 'dual';
export type Trigger = 'scroll-velocity' | 'mouse-proximity' | 'hover' | 'custom';

/** A source for the font outline binary (needed by the SVG/WebGL tiers). */
export type FontSource =
  | { url: string }
  | { buffer: ArrayBuffer | ArrayBufferView }
  | { parsed: ParsedFont; wdthAxis?: WdthAxis | null };

export interface FontuccineConfig {
  // ─────────────── documented public schema (README.md) ───────────────
  axis?: StretchAxis;
  trigger?: Trigger;

  maxStretchRatio?: number;
  minStretchRatio?: number;
  /** Pagurek's k (edge protection): high = hard 9-slice, low = uniform. */
  edgeProtection?: number;
  /** Slices per axis (analysis LUT resolution). */
  lutResolution?: number;

  physics?: { stiffness?: number; damping?: number };
  easingCurve?: string;
  easingDuration?: number;
  proximityRadius?: number;
  velocityToStretch?: number;

  tier?: Tier;
  /** Tier-1 (WebGL) only; ignored by the SVG/VF tiers. */
  effects?: EffectsConfig;

  wrap?: WrapMode;
  respectReducedMotion?: boolean;

  /**
   * APPROVED additive field (Phase-5 §4). How `wrap:'reserve'` sizes the box:
   *  - 'tier-capability' (default): each tier reserves what it can actually paint
   *    (SVG/WebGL × maxStretchRatio, VF × axis-max).
   *  - 'uniform': every tier reserves × maxStretchRatio for cross-tier
   *    consistency (VF then leaves a permanent gap).
   */
  reserveBasis?: ReserveBasis;

  // ─────────── advanced / injectable (NOT the documented schema) ───────────
  /** Text to stretch (defaults to the target element's textContent). */
  text?: string;
  /** Ink color (WebGL tier). Default opaque black. */
  color?: RGBAColor;

  /** Font outline source. `fontUrl`/`fontBuffer`/`parsedFont` are conveniences. */
  font?: FontSource;
  fontUrl?: string;
  fontBuffer?: ArrayBuffer | ArrayBufferView;
  parsedFont?: ParsedFont;
  /** Explicit `wdth` axis (skips detection; pairs with `parsedFont`). */
  wdthAxis?: WdthAxis | null;
  /** Font units per em the outlines are emitted in. Default 1000. */
  unitsPerEm?: number;

  /** Shared ticker (defaults to the library singleton). */
  ticker?: Ticker;
  /** SSR / jsdom document (defaults to the target's ownerDocument). */
  document?: Document;
  /** Reuse an AnalysisClient (defaults to a per-instance one). */
  analysisClient?: AnalysisClient;

  /** DI for capability probing (tests). */
  isReducedMotion?: () => boolean;
  isPrint?: () => boolean;
  detectWebGL2Support?: () => boolean;
  /** Injected WebGL backend (tests). */
  backend?: RenderBackend;
}

export interface Instance {
  /** Manual drive for `trigger:'custom'` (clamped to [min,max]). */
  set(value: number): void;
  /** Tear down renderer + controller; restore the DOM. Leaks nothing. */
  destroy(): void;
  /** Selected renderer tier, or null until selection completes. */
  readonly tier: ResolvedTier | null;
  /** Resolves once the renderer is attached (or the build settled/failed). */
  readonly ready: Promise<void>;
  /** Tier-selection + fall-through trail (CLAUDE.md rule 9 transparency). */
  readonly notes: readonly string[];
}

/**
 * Minimal ambient types for opentype.js (no @types package shipped).
 * Only the surface the parser uses is declared.
 */
declare module 'opentype.js' {
  export interface PathCommandLike {
    type: 'M' | 'L' | 'Q' | 'C' | 'Z';
    x?: number;
    y?: number;
    x1?: number;
    y1?: number;
    x2?: number;
    y2?: number;
  }
  export interface BoundingBox {
    x1: number;
    y1: number;
    x2: number;
    y2: number;
  }
  export interface Path {
    commands: PathCommandLike[];
    getBoundingBox(): BoundingBox;
  }
  export interface Glyph {
    advanceWidth?: number;
    getPath(x: number, y: number, fontSize: number): Path;
  }
  export interface Font {
    unitsPerEm: number;
    names?: { fullName?: { en?: string } };
    charToGlyph(char: string): Glyph;
    getKerningValue(left: Glyph, right: Glyph): number;
  }
  export function parse(buffer: ArrayBuffer): Font;
  const _default: { parse(buffer: ArrayBuffer): Font };
  export default _default;
}

/**
 * font/parser.ts — font parsing behind a swappable interface.
 *
 * opentype.js is the default backend; the FontParser / ParsedFont interfaces
 * let Typr or harfbuzzjs drop in later without touching the analysis core.
 *
 * System-font / CSS-only fallback strategy:
 *   The analysis core needs an outline binary. When no font binary is
 *   obtainable (e.g. a CSS-only web font whose bytes the page can't read),
 *   there is nothing to analyze. Callers should catch FontUnavailableError and
 *   signal TIER DEGRADATION to the renderer layer (rasterize via canvas — the
 *   architect owns that decision). The core NEVER crashes the pipeline for it.
 */
import opentype from 'opentype.js';
import type { Font as OtFont } from 'opentype.js';
import type { PathCommand, BBox } from '../core/types';

export interface ParsedGlyph {
  commands: PathCommand[];
  advanceWidth: number;
  bbox: BBox;
}

export interface ParsedFont {
  /** Glyph for a single character, or null if unmapped/blank. */
  glyph(char: string): ParsedGlyph | null;
  /** Kerning between two characters, in the same units as glyph commands. */
  kernPair(a: string, b: string): number;
  /** Coordinate scale used for emitted commands (= fontSize). */
  unitsPerEm: number;
  name?: string;
}

export interface FontParser {
  parse(buffer: ArrayBuffer, opts?: { fontSize?: number }): ParsedFont;
}

/** Raised when no font binary is available — signals tier degradation. */
export class FontUnavailableError extends Error {
  constructor(message = 'No font binary available for analysis') {
    super(message);
    this.name = 'FontUnavailableError';
  }
}

/**
 * opentype.js-backed parser. Commands are emitted in SVG-down coordinates at
 * `fontSize` units-per-em (default 1000), matching 08-real-font-demo.mjs.
 */
export class OpentypeParser implements FontParser {
  parse(buffer: ArrayBuffer, opts: { fontSize?: number } = {}): ParsedFont {
    if (!buffer || buffer.byteLength === 0) {
      throw new FontUnavailableError('Empty font buffer');
    }
    let font: OtFont;
    try {
      font = opentype.parse(buffer);
    } catch (err) {
      throw new FontUnavailableError(`opentype.js failed to parse font: ${String(err)}`);
    }
    const fontSize = opts.fontSize ?? 1000;
    const scale = fontSize / font.unitsPerEm;

    return {
      unitsPerEm: fontSize,
      name: font.names?.fullName?.en,
      glyph(char: string): ParsedGlyph | null {
        const g = font.charToGlyph(char);
        if (!g) return null;
        const path = g.getPath(0, 0, fontSize);
        if (!path.commands || path.commands.length === 0) return null;
        // Path bbox is already at fontSize scale and in SVG-down space,
        // matching the emitted commands.
        const bb = path.getBoundingBox();
        return {
          commands: path.commands as PathCommand[],
          advanceWidth: (g.advanceWidth ?? 0) * scale,
          bbox: { minX: bb.x1, minY: bb.y1, maxX: bb.x2, maxY: bb.y2 },
        };
      },
      kernPair(a: string, b: string): number {
        const ga = font.charToGlyph(a);
        const gb = font.charToGlyph(b);
        if (!ga || !gb) return 0;
        return (font.getKerningValue(ga, gb) || 0) * scale;
      },
    };
  }
}

/** Convenience factory: parse a buffer with the default (opentype.js) backend. */
export function parseFont(buffer: ArrayBuffer, opts?: { fontSize?: number }): ParsedFont {
  return new OpentypeParser().parse(buffer, opts);
}

/**
 * easing.ts — cubic-bezier parsing + a time-based smoother.
 *
 * README allows `easingCurve: 'cubic-bezier(…)'` as an ALTERNATIVE to spring
 * `physics`. The bezier string is parsed ONCE into an easing function; the
 * smoother tweens current→target over a fixed duration whenever the target
 * changes, exposing the same `Smoother` interface as the spring so the
 * controller can swap them transparently.
 *
 * NOTE (schema): a tween needs a duration. This module defaults to 0.3s and the
 * controller exposes it publicly as `easingDuration` (see README) alongside
 * `easingCurve`.
 */
import type { Smoother } from './spring';

export type EasingFn = (t: number) => number;

const NEWTON_ITERATIONS = 4;
const NEWTON_MIN_SLOPE = 0.001;
const SUBDIVISION_PRECISION = 1e-7;
const SUBDIVISION_MAX_ITERATIONS = 12;

function a(a1: number, a2: number): number {
  return 1 - 3 * a2 + 3 * a1;
}
function b(a1: number, a2: number): number {
  return 3 * a2 - 6 * a1;
}
function c(a1: number): number {
  return 3 * a1;
}
/** Horner-form cubic bezier component for control points (a1, a2) at parameter t. */
function calcBezier(t: number, a1: number, a2: number): number {
  return ((a(a1, a2) * t + b(a1, a2)) * t + c(a1)) * t;
}
function getSlope(t: number, a1: number, a2: number): number {
  return 3 * a(a1, a2) * t * t + 2 * b(a1, a2) * t + c(a1);
}

/**
 * Build a CSS-equivalent cubic-bezier easing from control points. Maps input
 * progress (x, the time fraction) → output progress (y) via Newton-Raphson
 * with a bisection fallback (the WebKit/`bezier-easing` algorithm).
 */
export function cubicBezier(x1: number, y1: number, x2: number, y2: number): EasingFn {
  if (x1 === y1 && x2 === y2) return (t) => t; // linear shortcut

  function tForX(x: number): number {
    let t = x;
    for (let i = 0; i < NEWTON_ITERATIONS; i++) {
      const slope = getSlope(t, x1, x2);
      if (slope === 0) break;
      const xVal = calcBezier(t, x1, x2) - x;
      t -= xVal / slope;
    }
    // Bisection fallback if Newton failed (flat regions).
    let lo = 0;
    let hi = 1;
    if (getSlope(t, x1, x2) >= NEWTON_MIN_SLOPE) return t;
    t = x;
    for (let i = 0; i < SUBDIVISION_MAX_ITERATIONS; i++) {
      const xVal = calcBezier(t, x1, x2);
      if (Math.abs(xVal - x) < SUBDIVISION_PRECISION) return t;
      if (xVal > x) hi = t;
      else lo = t;
      t = (lo + hi) / 2;
    }
    return t;
  }

  return (x) => {
    if (x <= 0) return 0;
    if (x >= 1) return 1;
    return calcBezier(tForX(x), y1, y2);
  };
}

/** Parse a `cubic-bezier(x1,y1,x2,y2)` string once. Throws on malformed input. */
export function parseCubicBezier(spec: string): EasingFn {
  const m = spec
    .trim()
    .match(/^cubic-bezier\(\s*([-\d.eE]+)\s*,\s*([-\d.eE]+)\s*,\s*([-\d.eE]+)\s*,\s*([-\d.eE]+)\s*\)$/);
  if (!m) throw new Error(`Invalid cubic-bezier string: ${JSON.stringify(spec)}`);
  const x1 = Number(m[1]);
  const y1 = Number(m[2]);
  const x2 = Number(m[3]);
  const y2 = Number(m[4]);
  if (x1 < 0 || x1 > 1 || x2 < 0 || x2 > 1) {
    throw new Error(`cubic-bezier x control points must be in [0,1]: ${spec}`);
  }
  return cubicBezier(x1, y1, x2, y2);
}

export interface BezierSmootherOptions {
  curve: string | EasingFn;
  /** Tween duration in seconds. Default 0.3. */
  duration?: number;
  initial?: number;
}

/** A `Smoother` that tweens toward its target with a cubic-bezier curve. */
export function createBezierSmoother(opts: BezierSmootherOptions): Smoother {
  const ease: EasingFn = typeof opts.curve === 'string' ? parseCubicBezier(opts.curve) : opts.curve;
  const duration = Math.max(1e-3, opts.duration ?? 0.3);

  let value = opts.initial ?? 0;
  let target = value;
  let start = value;
  let elapsed = duration; // start settled

  return {
    set(t) {
      if (t !== target) {
        start = value;
        target = t;
        elapsed = 0;
      }
    },
    step(dt) {
      if (elapsed >= duration) {
        value = target;
        return;
      }
      elapsed = Math.min(duration, elapsed + (dt > 0 ? dt : 0));
      const p = elapsed / duration;
      value = start + (target - start) * ease(p);
    },
    snap(v) {
      value = v;
      target = v;
      start = v;
      elapsed = duration;
    },
    get value() {
      return value;
    },
    get velocity() {
      return 0;
    },
    get target() {
      return target;
    },
    get settled() {
      return elapsed >= duration;
    },
  };
}

/**
 * gating.ts — IntersectionObserver visibility gate (R5).
 *
 * Offscreen or document-hidden instances must go fully idle: the controller
 * uses this to suspend its ticker subscriptions + stimulus listeners and resume
 * only when both gates are visible. When IntersectionObserver is unavailable
 * (Node/SSR) the viewport gate is treated as visible.
 */

export interface IntersectionEntryLike {
  isIntersecting: boolean;
}

export interface IntersectionObserverLike {
  observe(target: unknown): void;
  unobserve(target: unknown): void;
  disconnect(): void;
}

export interface VisibilityOptions {
  /** Injectable observer factory (default: global IntersectionObserver). */
  factory?: (cb: (entries: IntersectionEntryLike[]) => void) => IntersectionObserverLike;
  threshold?: number | number[];
  root?: unknown;
  rootMargin?: string;
}

/**
 * Observe `el`'s viewport and document visibility. `cb(visible)` fires on every
 * change (and once synchronously if no observer is available). Returns a
 * teardown fn.
 */
export function observeVisibility(
  el: unknown,
  cb: (visible: boolean) => void,
  opts: VisibilityOptions = {},
): () => void {
  const doc =
    (el as { ownerDocument?: Document } | null)?.ownerDocument ??
    (typeof document !== 'undefined' ? document : undefined);
  let intersecting = !opts.factory && typeof IntersectionObserver === 'undefined';
  let documentVisible = doc?.visibilityState !== 'hidden';
  const emit = (): void => cb(intersecting && documentVisible);
  const handler = (entries: IntersectionEntryLike[]): void => {
    for (const e of entries) {
      intersecting = e.isIntersecting;
      emit();
    }
  };
  const onDocumentVisibility = (): void => {
    documentVisible = doc?.visibilityState !== 'hidden';
    emit();
  };
  doc?.addEventListener('visibilitychange', onDocumentVisibility);

  const cleanup = (io?: IntersectionObserverLike): void => {
    io?.disconnect();
    doc?.removeEventListener('visibilitychange', onDocumentVisibility);
  };

  if (opts.factory) {
    const io = opts.factory(handler);
    io.observe(el);
    return () => cleanup(io);
  }

  if (typeof IntersectionObserver === 'undefined') {
    emit(); // headless: assume viewport-visible, while still honoring a document.
    return cleanup;
  }

  const io = new IntersectionObserver(
    (entries) => handler(entries as unknown as IntersectionEntryLike[]),
    { threshold: opts.threshold ?? 0, root: (opts.root ?? null) as Element | null, rootMargin: opts.rootMargin ?? '0px' },
  );
  io.observe(el as Element);
  return () => cleanup(io);
}

/**
 * reduced-motion.ts — `prefers-reduced-motion` query + change subscription.
 *
 * R7: under reduced motion, stimuli clamp to their resting value (static
 * output). This module only reports the preference; the controller does the
 * pinning. All access is guarded so it is a safe no-op in Node/SSR.
 */

const QUERY = '(prefers-reduced-motion: reduce)';

/** True if the user prefers reduced motion. Returns false when unavailable. */
export function prefersReducedMotion(): boolean {
  return typeof matchMedia !== 'undefined' ? matchMedia(QUERY).matches : false;
}

/** Subscribe to reduced-motion preference changes. Returns an unsubscribe fn. */
export function onReducedMotionChange(cb: (reduced: boolean) => void): () => void {
  if (typeof matchMedia === 'undefined') return () => {};
  const mql = matchMedia(QUERY);
  const handler = () => cb(mql.matches);
  // Older Safari exposes addListener/removeListener; guard both APIs.
  if (typeof mql.addEventListener === 'function') {
    mql.addEventListener('change', handler);
    return () => mql.removeEventListener('change', handler);
  }
  const legacy = mql as unknown as {
    addListener?: (h: () => void) => void;
    removeListener?: (h: () => void) => void;
  };
  legacy.addListener?.(handler);
  return () => legacy.removeListener?.(handler);
}

/**
 * spring.ts — critically-damped spring, frame-rate independent (R6).
 *
 * Integrated ANALYTICALLY (closed-form damped-harmonic-oscillator solution),
 * not with Euler steps, so it is exact at any timestep and cannot explode when
 * a backgrounded tab resumes with a huge dt. dt is still clamped as a second
 * guard against pathological gaps.
 *
 * Default damping is derived as critical (ζ = 1 ⇒ damping = 2√stiffness), so
 * the default spring never overshoots. Supplying a smaller `damping` makes it
 * underdamped (intentional overshoot, per README `physics`); a larger one makes
 * it overdamped. All three regimes use the correct analytic solution.
 */

/**
 * Common smoothing interface shared by the spring and the cubic-bezier smoother
 * so the controller can swap `physics` ⇄ `easingCurve` transparently.
 */
export interface Smoother {
  set(target: number): void;
  step(dt: number): void;
  snap(value: number): void;
  readonly value: number;
  readonly velocity: number;
  readonly target: number;
  readonly settled: boolean;
}

export interface SpringOptions {
  stiffness?: number;
  /** Omit for critical damping (2√stiffness). Smaller = overshoot. */
  damping?: number;
  initial?: number;
  /** Max integration step in seconds (tab-switch guard). Default 0.064. */
  maxDt?: number;
  restDisplacement?: number;
  restVelocity?: number;
}

export interface Spring extends Smoother {}

export function createSpring(opts: SpringOptions = {}): Spring {
  const stiffness = opts.stiffness ?? 170;
  const omega0 = Math.sqrt(Math.max(0, stiffness));
  const damping = opts.damping ?? 2 * omega0; // critical by default
  const zeta = omega0 > 0 ? damping / (2 * omega0) : 1;
  const maxDt = opts.maxDt ?? 0.064;
  const restD = opts.restDisplacement ?? 1e-3;
  const restV = opts.restVelocity ?? 1e-3;

  let x = opts.initial ?? 0;
  let v = 0;
  let target = x;

  function step(dtRaw: number): void {
    if (!(dtRaw > 0)) return;
    const dt = dtRaw > maxDt ? maxDt : dtRaw;
    if (omega0 <= 0) {
      x = target;
      v = 0;
      return;
    }

    const d0 = x - target; // displacement from target
    const v0 = v;
    let d: number;
    let vv: number;

    if (zeta < 1 - 1e-6) {
      // Underdamped.
      const wd = omega0 * Math.sqrt(1 - zeta * zeta);
      const e = Math.exp(-zeta * omega0 * dt);
      const c = Math.cos(wd * dt);
      const s = Math.sin(wd * dt);
      const A = d0;
      const B = (v0 + zeta * omega0 * d0) / wd;
      d = e * (A * c + B * s);
      vv = e * ((B * wd - zeta * omega0 * A) * c - (A * wd + zeta * omega0 * B) * s);
    } else if (zeta > 1 + 1e-6) {
      // Overdamped.
      const r = omega0 * Math.sqrt(zeta * zeta - 1);
      const r1 = -zeta * omega0 + r;
      const r2 = -zeta * omega0 - r;
      const c2 = (v0 - r1 * d0) / (r2 - r1);
      const c1 = d0 - c2;
      const e1 = Math.exp(r1 * dt);
      const e2 = Math.exp(r2 * dt);
      d = c1 * e1 + c2 * e2;
      vv = c1 * r1 * e1 + c2 * r2 * e2;
    } else {
      // Critically damped.
      const e = Math.exp(-omega0 * dt);
      const c1 = d0;
      const c2 = v0 + omega0 * d0;
      d = (c1 + c2 * dt) * e;
      vv = (c2 - omega0 * (c1 + c2 * dt)) * e;
    }

    x = target + d;
    v = vv;
  }

  return {
    set(t) {
      target = t;
    },
    step,
    snap(value) {
      x = value;
      v = 0;
      target = value;
    },
    get value() {
      return x;
    },
    get velocity() {
      return v;
    },
    get target() {
      return target;
    },
    get settled() {
      return Math.abs(x - target) <= restD && Math.abs(v) <= restV;
    },
  };
}

/**
 * stimuli/hover.ts — hover enter/leave → 0 | 1 target.
 *
 * `value` is a raw 0/1 target; the controller's spring smooths the transition
 * so an abrupt hover on/off still animates like motion design (R6). Pointer
 * events only (obligation #6). Touch and pen input intentionally stay static;
 * handlers record raw mouse-hover state only (R3).
 */
import type { Ticker } from '../ticker';
import type { Stimulus } from './types';

export interface HoverOptions {
  /** Element (EventTarget) whose hover state is tracked. */
  element: EventTarget;
  /** Enter event name (default 'pointerenter'). */
  enterEvent?: string;
  /** Leave event name (default 'pointerleave'). */
  leaveEvent?: string;
}

export function createHoverStimulus(opts: HoverOptions): Stimulus {
  const el = opts.element;
  const enterEvent = opts.enterEvent ?? 'pointerenter';
  const leaveEvent = opts.leaveEvent ?? 'pointerleave';

  let value = 0;
  let tickerRef: Ticker | null = null;
  let listening = false;

  const isMouse = (event: Event): boolean => {
    const pointerType = (event as PointerEvent).pointerType;
    return !pointerType || pointerType === 'mouse';
  };
  const onEnter = (event: Event): void => {
    if (!isMouse(event)) return;
    value = 1;
    tickerRef?.wake();
  };
  const onLeave = (event: Event): void => {
    if (!isMouse(event)) return;
    value = 0;
    tickerRef?.wake();
  };

  return {
    get value() {
      return value;
    },
    attach(ticker) {
      if (listening) this.detach();
      tickerRef = ticker;
      el.addEventListener(enterEvent, onEnter, { passive: true } as AddEventListenerOptions);
      el.addEventListener(leaveEvent, onLeave, { passive: true } as AddEventListenerOptions);
      el.addEventListener('pointercancel', onLeave, { passive: true } as AddEventListenerOptions);
      listening = true;
    },
    detach() {
      el.removeEventListener(enterEvent, onEnter);
      el.removeEventListener(leaveEvent, onLeave);
      el.removeEventListener('pointercancel', onLeave);
      tickerRef = null;
      value = 0;
      listening = false;
    },
  };
}

/**
 * stimuli/proximity.ts — 0..1 proximity of the pointer to an element.
 *
 * `value` is 1 when the pointer is on/inside the element and falls to 0 at
 * `radius` px away. Uses CACHED rects (R4): the rect is measured in the READ
 * phase and invalidated by ResizeObserver + scroll delta — NEVER in a handler
 * (R3). Pointer events only; touch and pen input intentionally stay static.
 * With multiple active mouse pointers the NEAREST one wins.
 */
import type { Ticker } from '../ticker';
import type { Disposable, RectSource, Stimulus } from './types';

interface PointerSample {
  x: number;
  y: number;
}

export interface ProximityOptions {
  element: RectSource;
  /** Distance in px at which proximity reaches 0. Default 240. */
  radius?: number;
  /** Target for pointermove/leave (default: window). */
  pointerTarget?: EventTarget;
  /** Target whose scroll invalidates the cached rect (default: window). */
  scrollTarget?: EventTarget;
  /** Injectable ResizeObserver factory (default: global ResizeObserver). */
  resizeObserverFactory?: (cb: () => void) => Disposable;
}

function resolveWindow(): (Window & typeof globalThis) | undefined {
  return typeof window !== 'undefined' ? window : undefined;
}

export function createProximityStimulus(opts: ProximityOptions): Stimulus {
  const win = resolveWindow();
  const el = opts.element;
  const radius = opts.radius ?? 240;
  const pointerTarget: EventTarget | undefined = opts.pointerTarget ?? win;
  const scrollTarget: EventTarget | undefined = opts.scrollTarget ?? win;

  // Nearest-wins across multiple pointers.
  const pointers = new Map<number, PointerSample>();
  let rect: { left: number; right: number; top: number; bottom: number } | null = null;
  let value = 0;

  let tickerRef: Ticker | null = null;
  let unsubRead: (() => void) | null = null;
  let unsubUpdate: (() => void) | null = null;
  let ro: Disposable | null = null;
  let listening = false;

  const measure = (): void => {
    rect = el.getBoundingClientRect();
  };

  const invalidate = (): void => {
    rect = null;
    tickerRef?.wake();
  };

  const onMove = (e: Event): void => {
    // Record raw pointer position only — NO layout read here (R3).
    const pe = e as PointerEvent;
    if (pe.pointerType && pe.pointerType !== 'mouse') return;
    const id = typeof pe.pointerId === 'number' ? pe.pointerId : 0;
    pointers.set(id, { x: pe.clientX, y: pe.clientY });
    tickerRef?.wake();
  };

  const onLeave = (e: Event): void => {
    const pe = e as PointerEvent;
    if (pe.pointerType && pe.pointerType !== 'mouse') return;
    const id = typeof pe.pointerId === 'number' ? pe.pointerId : 0;
    pointers.delete(id);
    tickerRef?.wake();
  };

  const onRead = (): void => {
    if (!rect) measure();
  };

  const onUpdate = (): void => {
    if (!rect || pointers.size === 0) {
      value = 0;
      return;
    }
    let best = 0;
    for (const p of pointers.values()) {
      const cx = Math.max(rect.left, Math.min(p.x, rect.right));
      const cy = Math.max(rect.top, Math.min(p.y, rect.bottom));
      const d = Math.hypot(p.x - cx, p.y - cy);
      const prox = Math.max(0, 1 - d / radius);
      if (prox > best) best = prox;
    }
    value = best;
  };

  const makeRO = (cb: () => void): Disposable | null => {
    if (opts.resizeObserverFactory) return opts.resizeObserverFactory(cb);
    if (typeof ResizeObserver !== 'undefined') {
      const obs = new ResizeObserver(() => cb());
      return { observe: (t) => obs.observe(t as Element), disconnect: () => obs.disconnect() };
    }
    return null;
  };

  return {
    get value() {
      return value;
    },
    attach(ticker) {
      if (listening) this.detach();
      tickerRef = ticker;
      rect = null; // measured lazily in READ
      if (pointerTarget) {
        pointerTarget.addEventListener('pointermove', onMove, { passive: true } as AddEventListenerOptions);
        pointerTarget.addEventListener('pointerleave', onLeave, { passive: true } as AddEventListenerOptions);
        pointerTarget.addEventListener('pointercancel', onLeave, { passive: true } as AddEventListenerOptions);
      }
      if (scrollTarget) {
        scrollTarget.addEventListener('scroll', invalidate, { passive: true } as AddEventListenerOptions);
      }
      ro = makeRO(invalidate);
      ro?.observe(el);
      unsubRead = ticker.read(onRead);
      unsubUpdate = ticker.update(onUpdate);
      listening = true;
    },
    detach() {
      if (pointerTarget) {
        pointerTarget.removeEventListener('pointermove', onMove);
        pointerTarget.removeEventListener('pointerleave', onLeave);
        pointerTarget.removeEventListener('pointercancel', onLeave);
      }
      if (scrollTarget) scrollTarget.removeEventListener('scroll', invalidate);
      ro?.disconnect();
      ro = null;
      unsubRead?.();
      unsubUpdate?.();
      unsubRead = null;
      unsubUpdate = null;
      tickerRef = null;
      pointers.clear();
      rect = null;
      value = 0;
      listening = false;
    },
  };
}

/**
 * stimuli/scroll-velocity.ts — scroll velocity in px/s, exponentially smoothed.
 *
 * `value` is SIGNED scroll velocity (px/s); the controller maps its magnitude
 * through `velocityToStretch`. The scroll handler records raw velocity only —
 * reading `scrollY` is cheap and forces no layout (R3). Smoothing and decay
 * happen in the UPDATE phase; velocity decays to 0 when scrolling stops so the
 * spring settles and the ticker sleeps.
 */
import type { Ticker } from '../ticker';
import type { NowMs, Stimulus } from './types';
import { defaultNow } from './types';

export interface ScrollVelocityOptions {
  /** Event target that emits scroll (default: window). */
  target?: EventTarget;
  /** Read the current scroll offset (default: window.scrollY). Cheap, no layout. */
  getScrollY?: () => number;
  /** Exponential smoothing factor toward raw velocity (0..1). Default 0.12. */
  smoothing?: number;
  /** Per-frame decay of raw velocity toward 0 when idle. Default 0.86. */
  decay?: number;
  /** Scroll event name (default 'scroll'). */
  eventName?: string;
  /** Injectable clock (default performance.now). */
  now?: NowMs;
}

function resolveWindow(): (Window & typeof globalThis) | undefined {
  return typeof window !== 'undefined' ? window : undefined;
}

export function createScrollVelocityStimulus(opts: ScrollVelocityOptions = {}): Stimulus {
  const win = resolveWindow();
  const target: EventTarget | undefined = opts.target ?? win;
  const getScrollY = opts.getScrollY ?? (() => (win ? win.scrollY : 0));
  const smoothing = opts.smoothing ?? 0.12;
  const decay = opts.decay ?? 0.86;
  const eventName = opts.eventName ?? 'scroll';
  const now = opts.now ?? defaultNow;

  let raw = 0;
  let value = 0;
  let lastY = 0;
  let lastT = 0;
  let tickerRef: Ticker | null = null;
  let unsubUpdate: (() => void) | null = null;
  let listening = false;

  const onScroll = (): void => {
    const t = now();
    const y = getScrollY(); // scroll offset read is cheap; forces no layout (R3)
    const dt = Math.max(1, t - lastT);
    raw = ((y - lastY) / dt) * 1000; // px/s
    lastY = y;
    lastT = t;
    tickerRef?.wake();
  };

  const onUpdate = (): void => {
    value += (raw - value) * smoothing;
    raw *= decay;
    if (Math.abs(raw) < 1e-3) raw = 0;
    if (Math.abs(value) < 1e-3) value = 0;
  };

  return {
    get value() {
      return value;
    },
    attach(ticker) {
      if (listening) this.detach();
      tickerRef = ticker;
      lastT = now();
      lastY = getScrollY();
      if (target) target.addEventListener(eventName, onScroll, { passive: true } as AddEventListenerOptions);
      unsubUpdate = ticker.update(onUpdate);
      listening = true;
    },
    detach() {
      if (target) target.removeEventListener(eventName, onScroll);
      unsubUpdate?.();
      unsubUpdate = null;
      tickerRef = null;
      listening = false;
      raw = 0;
      value = 0;
    },
  };
}

/**
 * stimuli/types.ts — the shared stimulus contract.
 *
 * A stimulus turns raw input into a normalized signal read by the controller
 * in the UPDATE phase. Semantics of `value` differ per stimulus (documented on
 * each factory) and the controller maps it per `trigger`:
 *   - scroll-velocity → signed px/s (mapped via `velocityToStretch`)
 *   - mouse-proximity → 0..1 proximity
 *   - hover           → 0 | 1 target
 *
 * R3 (critical): raw event handlers record input ONLY — never read layout.
 * Derivation happens in a ticker phase. R4: rects are cached and invalidated by
 * ResizeObserver + scroll delta, measured in the READ phase.
 */
import type { Ticker } from '../ticker';

export interface Stimulus {
  /** Normalized signal; meaning is stimulus-specific (see each factory). */
  readonly value: number;
  /** Wire DOM listeners + ticker phases. Idempotent-safe. */
  attach(ticker: Ticker): void;
  /** Remove listeners, observers and ticker subscriptions. */
  detach(): void;
}

/** Minimal structural rect source (an Element, or a test double). */
export interface RectSource {
  getBoundingClientRect(): {
    left: number;
    right: number;
    top: number;
    bottom: number;
  };
}

/** Structural disposable for injected observers. */
export interface Disposable {
  observe(target: unknown): void;
  disconnect(): void;
}

/** Current-time source in milliseconds (injectable for deterministic tests). */
export type NowMs = () => number;

export function defaultNow(): number {
  return typeof performance !== 'undefined' ? performance.now() : Date.now();
}

/**
 * stretch-controller.ts — composes a stimulus + a smoother into the per-frame
 * stretch scalar that feeds the core `buildRemap`/`layoutRun`.
 *
 * This layer OWNS ticker + stimuli + springs + gating. It does NOT render:
 * renderers subscribe to the ticker's RENDER phase and read `.value` (R2).
 *
 * Honors the README config fields: `trigger`, `axis`, `maxStretchRatio`,
 * `minStretchRatio`, `velocityToStretch`, `proximityRadius`,
 * `physics{stiffness,damping}` OR `easingCurve`/`easingDuration`,
 * `respectReducedMotion`.
 * Target is clamped to [minStretchRatio, maxStretchRatio]; under reduced motion
 * output is pinned to the resting value (R7).
 *
 * Sleep (R5/battery): the controller registers a liveness predicate
 * `() => !smoother.settled`, so once the stretch settles the ticker stops.
 * Input handlers in the stimuli call `ticker.wake()`.
 */
import type { Ticker } from './ticker';
import { ticker as sharedTicker } from './ticker';
import type { Smoother } from './spring';
import { createSpring } from './spring';
import { createBezierSmoother } from './easing';
import { prefersReducedMotion } from './reduced-motion';
import { observeVisibility } from './gating';
import type { IntersectionObserverLike, IntersectionEntryLike } from './gating';
import type { RectSource, Stimulus } from './stimuli/types';
import { createScrollVelocityStimulus } from './stimuli/scroll-velocity';
import { createProximityStimulus } from './stimuli/proximity';
import { createHoverStimulus } from './stimuli/hover';

export type Trigger = 'scroll-velocity' | 'mouse-proximity' | 'hover' | 'custom';
export type StretchAxis = 'horizontal' | 'vertical' | 'dual';

export interface StretchControllerConfig {
  trigger?: Trigger;
  axis?: StretchAxis;

  maxStretchRatio?: number;
  minStretchRatio?: number;
  velocityToStretch?: number;
  proximityRadius?: number;

  /** Critically-damped spring params (default). Mutually exclusive with easingCurve. */
  physics?: { stiffness?: number; damping?: number };
  /** cubic-bezier easing string (alternative to physics). */
  easingCurve?: string;
  /** Tween duration for easingCurve, seconds (default 0.3). */
  easingDuration?: number;

  respectReducedMotion?: boolean;

  // ---- injectable deps (not part of the README schema) ----
  /** Element for pointer/proximity/hover stimuli and visibility gating. */
  element?: (RectSource & EventTarget) | null;
  /** Ticker to bind to (default: the shared library ticker). */
  ticker?: Ticker;
  /** Provide a stimulus explicitly (overrides `trigger`-based construction). */
  stimulus?: Stimulus | null;
  /** Override reduced-motion detection (for tests). */
  isReducedMotion?: () => boolean;
  /** Resting (no-stretch) value. Default 1. */
  restingValue?: number;
  /** Enable IntersectionObserver gating when an element is present. Default true. */
  gate?: boolean;
  /** Injectable IO factory for gating (tests / custom roots). */
  intersectionObserverFactory?: (
    cb: (entries: IntersectionEntryLike[]) => void,
  ) => IntersectionObserverLike;
}

export interface StretchController {
  /** Current smoothed stretch scalar. Read in the RENDER phase. */
  readonly value: number;
  /** Current (clamped) target the smoother is chasing. */
  readonly target: number;
  readonly axis: StretchAxis;
  readonly trigger: Trigger;
  /** Manual drive (trigger: 'custom'). Value is clamped to [min,max]. */
  set(value: number): void;
  /** True while attached to the ticker (visible). */
  readonly active: boolean;
  /** Tear down: stimulus, subscriptions, gate. Leaks nothing. */
  destroy(): void;
}

const MAX_DT = 0.064;

export function createStretchController(config: StretchControllerConfig = {}): StretchController {
  const ticker = config.ticker ?? sharedTicker;
  const axis: StretchAxis = config.axis ?? 'horizontal';
  const trigger: Trigger = config.trigger ?? 'custom';
  const resting = config.restingValue ?? 1;
  const min = config.minStretchRatio ?? 1;
  const max = config.maxStretchRatio ?? 4.5;
  const velocityToStretch = config.velocityToStretch ?? 0.002;
  const respectRM = config.respectReducedMotion ?? true;
  const isRM = config.isReducedMotion ?? prefersReducedMotion;

  const clamp = (t: number): number => (t < min ? min : t > max ? max : t);

  const smoother: Smoother = config.easingCurve
    ? createBezierSmoother({
        curve: config.easingCurve,
        duration: config.easingDuration ?? 0.3,
        initial: resting,
      })
    : createSpring({
        stiffness: config.physics?.stiffness ?? 170,
        damping: config.physics?.damping,
        initial: resting,
      });

  const stimulus: Stimulus | null =
    config.stimulus !== undefined ? config.stimulus : buildStimulus();

  function buildStimulus(): Stimulus | null {
    switch (trigger) {
      case 'scroll-velocity':
        return createScrollVelocityStimulus();
      case 'mouse-proximity':
        return config.element
          ? createProximityStimulus({ element: config.element, radius: config.proximityRadius })
          : null;
      case 'hover':
        return config.element ? createHoverStimulus({ element: config.element }) : null;
      case 'custom':
      default:
        return null;
    }
  }

  let manualTarget = resting;
  let lastT = 0;
  let active = false;
  const phaseUnsubs: Array<() => void> = [];

  function deriveTarget(): number {
    if (respectRM && isRM()) return clamp(resting);
    switch (trigger) {
      case 'scroll-velocity': {
        const vraw = stimulus ? stimulus.value : 0;
        const extra = Math.min(max - resting, Math.abs(vraw) * velocityToStretch);
        return clamp(resting + extra);
      }
      case 'mouse-proximity':
      case 'hover': {
        const p = stimulus ? stimulus.value : 0;
        return clamp(resting + p * (max - resting));
      }
      case 'custom':
      default:
        return clamp(manualTarget);
    }
  }

  function onUpdate(now: number): void {
    const dt = lastT ? Math.min(MAX_DT, (now - lastT) / 1000) : 1 / 60;
    lastT = now;
    smoother.set(deriveTarget());
    smoother.step(dt);
  }

  function activate(): void {
    if (active) return;
    active = true;
    lastT = 0;
    // Stimulus subscribes its phases FIRST so its value is fresh before onUpdate reads it.
    stimulus?.attach(ticker);
    phaseUnsubs.push(ticker.update(onUpdate));
    phaseUnsubs.push(ticker.onActivity(() => !smoother.settled));
    ticker.wake();
  }

  function deactivate(): void {
    if (!active) return;
    active = false;
    for (const u of phaseUnsubs) u();
    phaseUnsubs.length = 0;
    stimulus?.detach();
  }

  // ---- lifecycle: gate on visibility if we have an element ----
  const gateEnabled = (config.gate ?? true) && !!config.element;
  let gateDispose: () => void = () => {};

  if (gateEnabled && config.element) {
    gateDispose = observeVisibility(
      config.element,
      (visible) => (visible ? activate() : deactivate()),
      config.intersectionObserverFactory ? { factory: config.intersectionObserverFactory } : {},
    );
  } else {
    activate();
  }

  return {
    get value() {
      return smoother.value;
    },
    get target() {
      return smoother.target;
    },
    axis,
    trigger,
    get active() {
      return active;
    },
    set(value: number) {
      manualTarget = value;
      ticker.wake();
    },
    destroy() {
      gateDispose();
      deactivate();
    },
  };
}

/**
 * ticker.ts — the single shared ticker for the whole library.
 *
 * Decision-record rules enforced here:
 *  R1  ONE loop for every instance/stimulus/renderer. Never a per-element rAF.
 *  R2  Strict phase order every frame: READ → UPDATE → RENDER. All DOM
 *      measurement in READ, all pure math in UPDATE, all writes in RENDER.
 *  R8  External driver support: `drive()` hands the loop to GSAP's ticker or
 *      Lenis' raf; the internal rAF is disabled while driven.
 *
 * Battery/perf: the ticker sleeps when no registered activity predicate is
 * live (all springs settled, all stimuli idle) — no idle rAF churn — and wakes
 * on input via `wake()`. A settled-but-still-attached instance keeps its
 * `() => !settled` predicate registered, so the loop PARKS (running, 0 pending
 * rAF) and resumes on `wake()`. If no activity predicate is registered, the
 * loop stops after its pending frame even when a gated renderer still has phase
 * subscribers. A later `attach()`/`drive()`/`onActivity` restarts it.
 *
 * Testability: `frame(now)` is directly invokable and the scheduler/clock is
 * injectable, so phase ordering and sleep behaviour are deterministic with NO
 * real rAF (Node has none). `createTicker(scheduler)` builds an isolated ticker
 * for tests; the module-level `ticker` singleton is what the library shares.
 */

export type FrameCallback = (now: number) => void;
export type Phase = (now: number) => void;
export type ActivityPredicate = () => boolean;

/** Injectable clock + frame scheduler (defaults to rAF / performance.now). */
export interface FrameScheduler {
  requestFrame(cb: FrameCallback): number;
  cancelFrame(handle: number): void;
  now(): number;
}

export interface Ticker {
  /** READ phase: DOM measurement only (getBoundingClientRect, scrollY). */
  read(fn: Phase): () => void;
  /** UPDATE phase: pure math only (springs, target derivation, LUT rebuilds). */
  update(fn: Phase): () => void;
  /** RENDER phase: writes only (GL draw, `d` attr, style). Renderers subscribe here. */
  render(fn: Phase): () => void;
  /**
   * Register a liveness predicate. While ANY predicate returns true the loop
   * keeps scheduling frames; when all are false the loop sleeps. Returns an
   * unsubscribe fn.
   */
  onActivity(pred: ActivityPredicate): () => void;
  /** Ensure the loop is running/awake (called by input handlers — cheap, no layout). */
  wake(): void;
  /** Start the internal rAF loop (no-op while externally driven). */
  start(): void;
  /** Stop the loop and cancel any pending frame. */
  stop(): void;
  /**
   * Hand the loop to an external driver (GSAP ticker / Lenis raf). The internal
   * rAF is disabled; call the returned `frame(now)` once per external tick:
   *   const tick = ticker.drive();
   *   gsap.ticker.add((t) => tick(t * 1000)); // GSAP time is seconds
   */
  drive(): FrameCallback;
  /** Re-enable the internal rAF after `drive()` (undoes external mode). */
  undrive(): void;
  /** Run one frame deterministically. Exposed for external drivers and tests. */
  frame(now: number): void;
  readonly running: boolean;
  readonly awake: boolean;
  readonly external: boolean;
}

function makeDefaultScheduler(): FrameScheduler {
  return {
    requestFrame(cb) {
      return typeof requestAnimationFrame !== 'undefined'
        ? requestAnimationFrame(cb)
        : 0;
    },
    cancelFrame(handle) {
      if (typeof cancelAnimationFrame !== 'undefined') cancelAnimationFrame(handle);
    },
    now() {
      return typeof performance !== 'undefined' ? performance.now() : Date.now();
    },
  };
}

export function createTicker(scheduler: FrameScheduler = makeDefaultScheduler()): Ticker {
  const reads = new Set<Phase>();
  const updates = new Set<Phase>();
  const renders = new Set<Phase>();
  const activity = new Set<ActivityPredicate>();

  let running = false;
  let external = false;
  let awake = false;
  let handle = 0;

  function hasLiveActivity(): boolean {
    for (const p of activity) if (p()) return true;
    return false;
  }

  function schedule(): void {
    if (external || !running || awake) return;
    awake = true;
    handle = scheduler.requestFrame(frame);
  }

  function frame(now: number): void {
    // R2: strict phase order. Never interleave reads and writes.
    for (const f of reads) f(now);
    for (const f of updates) f(now);
    for (const f of renders) f(now);

    if (external) return; // the external owner reschedules
    awake = false;
    if (running && hasLiveActivity()) {
      awake = true;
      handle = scheduler.requestFrame(frame);
    } else if (activity.size === 0) {
      // No activity owner remains: fully stop even if a gated renderer keeps
      // inert READ/RENDER subscriptions. A later controller activation restarts
      // the loop through onActivity()/wake().
      // A settled-but-still-attached instance keeps its `() => !settled`
      // predicate registered (activity.size > 0), so it PARKS here with
      // running=true and resumes on wake() — it never reaches this branch.
      running = false;
    }
  }

  function start(): void {
    if (running) return;
    running = true;
    if (!external) schedule();
  }

  function stop(): void {
    running = false;
    awake = false;
    if (handle) scheduler.cancelFrame(handle);
    handle = 0;
  }

  function wake(): void {
    if (external) return;
    if (!running) {
      start();
      return;
    }
    schedule();
  }

  function subscribe(set: Set<Phase>, fn: Phase): () => void {
    set.add(fn);
    start();
    return () => set.delete(fn);
  }

  return {
    read: (fn) => subscribe(reads, fn),
    update: (fn) => subscribe(updates, fn),
    render: (fn) => subscribe(renders, fn),
    onActivity(pred) {
      activity.add(pred);
      // A newly live instance should be able to wake a sleeping loop.
      wake();
      return () => activity.delete(pred);
    },
    wake,
    start,
    stop,
    drive() {
      external = true;
      if (handle) scheduler.cancelFrame(handle);
      handle = 0;
      awake = false;
      running = true;
      return frame;
    },
    undrive() {
      if (!external) return;
      external = false;
      // Resume the internal loop if there is work to do.
      if (running) {
        awake = false;
        schedule();
      }
    },
    frame,
    get running() {
      return running;
    },
    get awake() {
      return awake;
    },
    get external() {
      return external;
    },
  };
}

/** The one shared ticker every Fontuccine instance uses (R1). */
export const ticker: Ticker = createTicker();

/**
 * svg/renderer.ts — Fontuccine Tier 2 (SVG path remap) renderer.
 *
 * RESEARCH §3: the no-WebGL / vector-fidelity fallback. Exact vectors, best
 * possible fidelity, headline-scale only (SVG `d` mutation paints every frame —
 * C-tier). Consumes the SAME per-glyph flex profiles as every other tier and
 * the SAME shared ticker + StretchController as the interaction layer.
 *
 * Discipline enforced here (CLAUDE.md rules 4, 6, 7):
 *  - ONE `<path>` per glyph, created once; per frame only its `d` is rewritten.
 *  - Writes happen ONLY in the ticker RENDER phase (`draw`). DOM measurement
 *    happens ONLY in the READ phase (`readPhase` → overlay.measure), cached and
 *    invalidated via ResizeObserver + scroll. No layout reads in `draw`.
 *  - Static per glyph: outline splitting (`splitGlyph`) runs once at build.
 *  - Reduced motion / print: draw ONCE at the resting stretch and register NO
 *    per-frame callback (no animation, zero ongoing engine work).
 *  - `contain: layout paint` + `isolation: isolate` on the host (via the shared
 *    overlay) keep per-frame paints scoped.
 *
 * Scale without a per-frame read: the <svg> carries a fixed font-unit `viewBox`
 * and its width/height are expressed in `em`, so it tracks the host font-size
 * through CSS alone — no getComputedStyle in the hot path.
 *
 * Tier interface (attach/resize/draw/destroy) mirrors the GPU renderer's so the
 * engine can swap tiers behind one shape. Final unification is the architect's
 * call (CLAUDE.md rule: cross-module contracts go through the architect).
 */
import type { PathCommand, Bounds1D, BBox } from '../core/types';
import type { LayoutGlyph } from '../core/kerning';
import { layoutRun } from '../core/kerning';
import type { Ticker } from '../interaction/ticker';
import { ticker as sharedTicker } from '../interaction/ticker';
import { prefersReducedMotion } from '../interaction/reduced-motion';
import type { SplitContour } from './split';
import { splitGlyph, serializeGlyph } from './split';
import { createOverlay } from '../dom/overlay';
import type { Overlay, WrapMode } from '../dom/overlay';

const SVG_NS = 'http://www.w3.org/2000/svg';
const DEFAULT_BUDGET = 64;

/** Minimal shape the renderer reads from a StretchController. */
export interface StretchSource {
  readonly value: number;
}

/** One glyph's static render inputs (outline + its analysis). */
export interface SvgGlyph {
  /** Character (diagnostics only). */
  char?: string;
  /** Outline commands in font units (SVG-down), e.g. opentype getPath(0,0,upm). */
  commands: PathCommand[];
  /** Static flex profile for the x axis (length === slice count). */
  flex: Float32Array;
  /** Ink bounds along x (must match the profile the flex was computed for). */
  bounds: Bounds1D;
  /** Advance width in font units. */
  advanceWidth: number;
  /** Glyph bbox in font units (for the vertical extent of the viewBox). */
  bbox: BBox;
  /** Kerning applied before this glyph (font units, 0 for the first). */
  kernBefore?: number;
}

export interface SvgRendererOptions {
  host: HTMLElement;
  glyphs: SvgGlyph[];
  /** Per-frame stretch source (a StretchController or anything with `.value`). */
  controller: StretchSource;
  /** Source text (defaults to host.textContent). */
  text?: string;
  wrap?: WrapMode;
  maxStretchRatio?: number;
  /** Resting stretch used for the static reduced-motion draw. Default 1. */
  restingStretch?: number;
  /** Font units per em used by `commands` (opentype getPath size). Default 1000. */
  unitsPerEm?: number;
  /** `d` coordinate precision. Default 2. */
  precision?: number;
  /** Glyphs above this warn (headline budget). Default 64. */
  glyphBudget?: number;
  ticker?: Ticker;
  document?: Document;
  respectReducedMotion?: boolean;
  /** Override reduced-motion detection (tests). */
  isReducedMotion?: () => boolean;
}

export interface SvgRenderer {
  /** Build subscriptions and paint. Idempotent. */
  attach(): void;
  /** Invalidate cached measurements (re-measured next READ phase). */
  resize(): void;
  /** One-shot render (write phase). Also the subscribed RENDER callback. */
  draw(now?: number): void;
  /** Tear down subscriptions, observers, nodes; restore original text. */
  destroy(): void;
  readonly element: SVGSVGElement;
  readonly overlay: Overlay;
}

interface PreparedGlyph {
  path: SVGPathElement;
  contours: SplitContour[];
  layout: LayoutGlyph;
}

export function createSvgRenderer(options: SvgRendererOptions): SvgRenderer {
  const {
    host,
    glyphs,
    controller,
    wrap = 'nowrap',
    maxStretchRatio = 4.5,
    restingStretch = 1,
    unitsPerEm = 1000,
    precision = 2,
    glyphBudget = DEFAULT_BUDGET,
  } = options;

  const ticker = options.ticker ?? sharedTicker;
  const doc = options.document ?? host.ownerDocument;
  if (!doc) throw new Error('createSvgRenderer: no document available');
  const respectRM = options.respectReducedMotion ?? true;
  const isRM = options.isReducedMotion ?? prefersReducedMotion;

  // --- build the <svg> render layer + one reusable <path> per glyph.
  const svg = doc.createElementNS(SVG_NS, 'svg') as SVGSVGElement;
  svg.setAttribute('data-fontuccine', 'svg-tier');
  svg.setAttribute('fill', 'currentColor');
  svg.setAttribute('preserveAspectRatio', 'xMinYMin meet');

  const prepared: PreparedGlyph[] = glyphs.map((g) => {
    const path = doc.createElementNS(SVG_NS, 'path') as SVGPathElement;
    if (g.char) path.setAttribute('data-char', g.char);
    svg.appendChild(path);
    return {
      path,
      contours: splitGlyph(g.commands, g.bounds, g.flex.length),
      layout: {
        profile: g.flex,
        bounds: g.bounds,
        advanceWidth: g.advanceWidth,
        kernBefore: g.kernBefore,
      },
    };
  });

  // --- static viewBox sized to the MAX-stretch run so per-frame widths always
  //     fit (only `d` changes per frame; the viewBox never does).
  const layoutGlyphs = prepared.map((p) => p.layout);
  const maxRun = layoutRun(layoutGlyphs, { stretch: maxStretchRatio, axis: 'x', origin: 0 });
  let minY = Infinity;
  let maxY = -Infinity;
  for (const g of glyphs) {
    if (g.bbox.minY < minY) minY = g.bbox.minY;
    if (g.bbox.maxY > maxY) maxY = g.bbox.maxY;
  }
  if (!Number.isFinite(minY)) {
    minY = 0;
    maxY = unitsPerEm;
  }
  const vbW = Math.max(1, maxRun.width);
  const vbH = Math.max(1, maxY - minY);
  svg.setAttribute('viewBox', `0 ${minY} ${vbW} ${vbH}`);
  // em sizing → tracks host font-size through CSS (no per-frame read).
  svg.style.setProperty('width', `${vbW / unitsPerEm}em`);
  svg.style.setProperty('height', `${vbH / unitsPerEm}em`);

  const overlay = createOverlay({
    host,
    renderLayer: svg,
    text: options.text,
    wrap,
    maxStretchRatio,
    document: doc,
  });

  // --- lifecycle state.
  let attached = false;
  let dirty = true;
  let lastStretch = Number.NaN;
  const unsubs: Array<() => void> = [];
  let resizeObserver: ResizeObserver | null = null;
  let scrollHandler: (() => void) | null = null;

  function readPhase(): void {
    if (!dirty) return; // cached — nothing changed since last measure
    dirty = false;
    overlay.measure();
  }

  /** Lay out at `stretch` and rewrite every glyph's `d` (WRITE only). */
  function paint(stretch: number): void {
    lastStretch = stretch;
    const run = layoutRun(layoutGlyphs, { stretch, axis: 'x', origin: 0 });
    for (let i = 0; i < prepared.length; i++) {
      const p = prepared[i];
      const r = run.glyphs[i];
      p.path.setAttribute('d', serializeGlyph(p.contours, r.remap, r.penX, precision));
    }
  }

  function draw(): void {
    // RENDER phase. `controller.value` is a plain number, not a DOM read.
    const stretch = controller.value;
    if (stretch === lastStretch) return; // settled → skip the paint entirely
    paint(stretch);
  }

  function attach(): void {
    if (attached) return;
    attached = true;

    if (glyphs.length > glyphBudget) {
      // eslint-disable-next-line no-console
      console.warn(
        `[fontuccine/svg] ${glyphs.length} glyphs exceeds the headline budget of ${glyphBudget}. ` +
          `The SVG tier repaints every frame — long runs belong on the WebGL tier.`,
      );
    }

    if (respectRM && isRM()) {
      // Reduced motion / print: measure once, paint once at rest, NO per-frame
      // subscription (register no RENDER callback — zero ongoing engine work).
      overlay.measure();
      paint(restingStretch);
      return;
    }

    // Animated path: READ (measure, cached) + RENDER (draw) on the shared ticker.
    unsubs.push(ticker.read(readPhase));
    unsubs.push(ticker.render(draw));

    // Invalidate cached measurements on resize + scroll (re-measured in READ).
    if (typeof ResizeObserver !== 'undefined') {
      resizeObserver = new ResizeObserver(() => {
        dirty = true;
        ticker.wake();
      });
      resizeObserver.observe(host);
    }
    const view = doc.defaultView;
    if (view) {
      scrollHandler = () => {
        dirty = true;
      };
      view.addEventListener('scroll', scrollHandler, { passive: true });
    }

    ticker.wake();
  }

  function resize(): void {
    dirty = true;
    ticker.wake();
  }

  function destroy(): void {
    for (const u of unsubs) u();
    unsubs.length = 0;
    if (resizeObserver) {
      resizeObserver.disconnect();
      resizeObserver = null;
    }
    if (scrollHandler && doc.defaultView) {
      doc.defaultView.removeEventListener('scroll', scrollHandler);
      scrollHandler = null;
    }
    overlay.destroy(); // moves real text back, removes the <svg>, restores styles
    attached = false;
  }

  return {
    attach,
    resize,
    draw,
    destroy,
    element: svg,
    overlay,
  };
}

/**
 * svg/split.ts — the EXACT SVG-tier geometry (RESEARCH §3 Tier 2,
 * refs/examples/05-svg-tier.mjs).
 *
 * Two phases, cleanly separated:
 *
 *  STATIC (once per glyph, on prepare):  `splitGlyph`
 *    Split every outline segment at each slice boundary it crosses so that each
 *    resulting sub-segment lies entirely within ONE slice. Splitting depends
 *    only on the ORIGINAL-space slice grid (bounds + slice count) — NOT on the
 *    stretch amount — so it is computed once and reused for every frame.
 *
 *  PER FRAME (in the ticker RENDER phase):  `remapContours` / `contoursToPathData`
 *    Map each pre-split sub-segment through the current frame's remap and
 *    serialize to an SVG `d`. Because the remap is piecewise AFFINE (linear
 *    within a slice), a sub-segment that lives in one slice is remapped EXACTLY
 *    by applying that slice's single affine map to its control points — Bézier
 *    curves are affine-invariant. `test/svg-exactness.test.ts` proves this.
 *
 * EXACTNESS SUBTLETY (why we do NOT call `remap.remap()` per control point):
 *    A Bézier's control points can lie OUTSIDE the on-curve x-range (convex
 *    hull ⊇ curve), so a sub-segment whose *curve* stays inside slice i can
 *    still have a control point whose x falls in slice i±1. `remap.remap()` is
 *    piecewise and would map that stray control point with the WRONG slice's
 *    affine, distorting the curve. Instead we pick the slice from the
 *    sub-segment's on-curve midpoint and apply THAT slice's affine *extension*
 *    (valid for all x) to every control point. The two agree on-curve (where
 *    the remap is sampled/tested) but only the single-affine form is exact for
 *    the control polygon. This is the correctness refinement over the literal
 *    `serializeStretched` sketch in 05-svg-tier.mjs.
 *
 * ROOT-FINDING: boundary crossings are found by CLOSED-FORM axis-root solving
 * (quadratic/Cardano) + Newton polish, then split with the frozen de Casteljau
 * (`splitSegment` from core geometry). The 05 sketch reached for bezier-js
 * `.intersects(line)`, but that numeric routine empirically DROPS crossings on
 * near-flat quadratics (e.g. Georgia 'S'), leaving a sub-segment spanning a
 * slice and breaking exactness — so we solve analytically instead.
 */
import type { PathCommand, Bounds1D, Remap } from '../core/types';
import type { Segment, Point } from '../core/geometry/segments';
import { commandsToContours, evalSegment, splitSegment as deCasteljau } from '../core/geometry/segments';

/** A contour of sub-segments, each guaranteed to lie within one x-slice. */
export type SplitContour = Segment[];

const EPS = 1e-7;

/** Interior slice boundaries in ORIGINAL space (endpoints excluded). */
export function interiorBoundaries(bounds: Bounds1D, slices: number): number[] {
  const w = (bounds.max - bounds.min) / slices;
  const out: number[] = [];
  for (let i = 1; i < slices; i++) out.push(bounds.min + i * w);
  return out;
}

// ── closed-form axis-root solving ────────────────────────────────────────────
// We split at every t where the segment's x(t) equals a slice boundary. Doing
// this analytically (not via a numeric curve/line intersection) is exact and
// finds ALL crossings — including the near-flat quadratics that a generic
// intersection routine drops, which would leave a sub-segment spanning a slice
// and break the affine-per-slice exactness proof.

function realQuadRoots(a: number, b: number, c: number): number[] {
  if (Math.abs(a) < 1e-12) return Math.abs(b) < 1e-12 ? [] : [-c / b];
  const disc = b * b - 4 * a * c;
  if (disc < 0) return [];
  const sq = Math.sqrt(disc);
  return [(-b + sq) / (2 * a), (-b - sq) / (2 * a)];
}

/** Real roots of A t³ + B t² + C t + D = 0 (degrades to quadratic if A≈0). */
function realCubicRoots(A: number, B: number, C: number, D: number): number[] {
  if (Math.abs(A) < 1e-12) return realQuadRoots(B, C, D);
  const b = B / A;
  const c = C / A;
  const d = D / A;
  // depressed cubic  x = t + b/3  →  t³ + p t + q = 0
  const p = c - (b * b) / 3;
  const q = (2 * b * b * b) / 27 - (b * c) / 3 + d;
  const shift = b / 3;
  const disc = (q * q) / 4 + (p * p * p) / 27;
  const roots: number[] = [];
  if (disc > 1e-14) {
    const sq = Math.sqrt(disc);
    const u = Math.cbrt(-q / 2 + sq);
    const v = Math.cbrt(-q / 2 - sq);
    roots.push(u + v - shift);
  } else if (disc < -1e-14) {
    const r = Math.sqrt(-(p * p * p) / 27);
    const phi = Math.acos(Math.max(-1, Math.min(1, -q / (2 * r))));
    const m = 2 * Math.cbrt(r);
    roots.push(m * Math.cos(phi / 3) - shift);
    roots.push(m * Math.cos((phi + 2 * Math.PI) / 3) - shift);
    roots.push(m * Math.cos((phi + 4 * Math.PI) / 3) - shift);
  } else {
    // disc ≈ 0 → multiple root
    const u = Math.cbrt(-q / 2);
    roots.push(2 * u - shift, -u - shift);
  }
  return roots;
}

/** t-values in (0,1) where seg.x(t) === bound, Newton-polished for precision. */
function axisCrossings(seg: Segment, bound: number): number[] {
  let raw: number[];
  if (seg.type === 'L') {
    const dx = seg.p1.x - seg.p0.x;
    raw = Math.abs(dx) < 1e-12 ? [] : [(bound - seg.p0.x) / dx];
  } else if (seg.type === 'Q') {
    const { p0, p1, p2 } = seg;
    // x(t) = a t² + b t + c
    const a = p0.x - 2 * p1.x + p2.x;
    const b = 2 * (p1.x - p0.x);
    raw = realQuadRoots(a, b, p0.x - bound);
  } else {
    const { p0, p1, p2, p3 } = seg;
    const A = -p0.x + 3 * p1.x - 3 * p2.x + p3.x;
    const B = 3 * p0.x - 6 * p1.x + 3 * p2.x;
    const C = -3 * p0.x + 3 * p1.x;
    raw = realCubicRoots(A, B, C, p0.x - bound);
  }
  const out: number[] = [];
  for (let t of raw) {
    if (!Number.isFinite(t)) continue;
    // polish against x(t) - bound using the exact analytic derivative
    for (let it = 0; it < 3; it++) {
      const e = evalSegment(seg, t);
      const f = e.x - bound;
      if (Math.abs(e.tx) < 1e-12) break;
      t -= f / e.tx;
    }
    if (t > EPS && t < 1 - EPS) out.push(t);
  }
  return out;
}

/** Split one segment at every slice boundary it crosses (frozen de Casteljau). */
function splitSegment(seg: Segment, boundaries: number[]): Segment[] {
  const ts: number[] = [];
  for (const bound of boundaries) {
    for (const t of axisCrossings(seg, bound)) ts.push(t);
  }
  ts.sort((a, z) => a - z);

  const out: Segment[] = [];
  let rest = seg;
  let consumed = 0;
  for (const t of ts) {
    if (t <= consumed + EPS) continue; // duplicate / already consumed
    const local = (t - consumed) / (1 - consumed);
    if (local <= EPS || local >= 1 - EPS) continue;
    const { left, right } = deCasteljau(rest, local);
    out.push(left);
    rest = right;
    consumed = t;
  }
  out.push(rest);
  return out;
}

/**
 * STATIC: split a glyph's outline against its own slice grid.
 * `bounds` and `slices` MUST match the analysis profile the frame remap is
 * built from (profile.length === slices, profile bounds === bounds), so the
 * split boundaries and the remap boundaries coincide exactly.
 */
export function splitGlyph(commands: PathCommand[], bounds: Bounds1D, slices: number): SplitContour[] {
  const boundaries = interiorBoundaries(bounds, slices);
  const contours = commandsToContours(commands);
  const out: SplitContour[] = [];
  for (const segs of contours) {
    const pieces: Segment[] = [];
    for (const seg of segs) {
      for (const p of splitSegment(seg, boundaries)) pieces.push(p);
    }
    if (pieces.length) out.push(pieces);
  }
  return out;
}

/**
 * Build the affine map for the slice a sub-segment belongs to.
 * `x'(x) = penX + sb[i] + (x - boundaries[i]) * (w + e[i]) / w`, which equals
 * `remap.remap(x)` (offset by penX) for x within slice i, and extends it to
 * all x (the exactness requirement above). Slice index is chosen from the
 * on-curve midpoint so stray control points cannot mis-select it.
 */
function sliceAffineForSegment(
  seg: Segment,
  remap: Remap,
  penX: number,
): (x: number) => number {
  const { boundaries, stretchedBoundaries: sb, extras: e, sliceWidth: w } = remap;
  const N = e.length;
  const min = boundaries[0];
  const W = boundaries[N] - min;
  const mid = evalSegment(seg, 0.5).x;
  let i = Math.floor(((mid - min) / W) * N);
  if (i < 0) i = 0;
  else if (i >= N) i = N - 1;
  const slope = (w + e[i]) / w;
  const base = penX + sb[i];
  const bnd = boundaries[i];
  return (x: number) => base + (x - bnd) * slope;
}

/**
 * PER FRAME: map pre-split contours through the frame remap (+ pen offset).
 * Horizontal axis only: x is remapped, y is identity. Returns numeric
 * remapped segments (no formatting) — the exactness test consumes these.
 */
export function remapContours(
  contours: SplitContour[],
  remap: Remap,
  penX = 0,
): SplitContour[] {
  const out: SplitContour[] = [];
  for (const segs of contours) {
    const mapped: Segment[] = [];
    for (const seg of segs) {
      const rx = sliceAffineForSegment(seg, remap, penX);
      switch (seg.type) {
        case 'L':
          mapped.push({ type: 'L', p0: { x: rx(seg.p0.x), y: seg.p0.y }, p1: { x: rx(seg.p1.x), y: seg.p1.y } });
          break;
        case 'Q':
          mapped.push({
            type: 'Q',
            p0: { x: rx(seg.p0.x), y: seg.p0.y },
            p1: { x: rx(seg.p1.x), y: seg.p1.y },
            p2: { x: rx(seg.p2.x), y: seg.p2.y },
          });
          break;
        case 'C':
          mapped.push({
            type: 'C',
            p0: { x: rx(seg.p0.x), y: seg.p0.y },
            p1: { x: rx(seg.p1.x), y: seg.p1.y },
            p2: { x: rx(seg.p2.x), y: seg.p2.y },
            p3: { x: rx(seg.p3.x), y: seg.p3.y },
          });
          break;
      }
    }
    out.push(mapped);
  }
  return out;
}

const num = (v: number, p: number): string => {
  const s = v.toFixed(p);
  return s === `-${(0).toFixed(p)}` ? (0).toFixed(p) : s; // avoid "-0.00"
};

/** Serialize remapped contours to an SVG path `d` string. */
export function contoursToPathData(contours: SplitContour[], precision = 3): string {
  const f = (p: Point): string => `${num(p.x, precision)},${num(p.y, precision)}`;
  let d = '';
  for (const segs of contours) {
    if (!segs.length) continue;
    segs.forEach((seg, i) => {
      if (i === 0) d += `M${f(seg.p0)}`;
      if (seg.type === 'L') d += `L${f(seg.p1)}`;
      else if (seg.type === 'Q') d += `Q${f(seg.p1)} ${f(seg.p2)}`;
      else d += `C${f(seg.p1)} ${f(seg.p2)} ${f(seg.p3)}`;
    });
    d += 'Z';
  }
  return d;
}

/** Convenience: remap + serialize in one call (per-frame render helper). */
export function serializeGlyph(
  contours: SplitContour[],
  remap: Remap,
  penX = 0,
  precision = 3,
): string {
  return contoursToPathData(remapContours(contours, remap, penX), precision);
}

/**
 * vf/detect.ts — Tier-0 fvar `wdth` axis detection.
 *
 * Productionizes `getWdthAxis` from refs/examples/07-variable-font-tier.mjs.
 * We read the axis straight out of the parsed `fvar` table — no rendering
 * heuristics. This is PURE (no DOM) and Node-testable against a real VF.
 *
 * NOTE ON UNITS: per the OpenType spec the registered `wdth` axis is expressed
 * as a PERCENTAGE of normal width (default 100, typical range 50–200), which is
 * exactly what CSS `font-stretch: <percentage>` consumes. A minority of legacy
 * GX fonts (e.g. Apple's Skia) instead report `wdth` in a 1.0-based multiplier
 * scale (0.62 / 1 / 1.3). We faithfully return whatever the font declares here;
 * the percentage MAPPING + support decision (probe.ts) is written to the spec
 * convention. The frozen `src/font/parser.ts` does not surface `fvar`, so this
 * module reads it structurally off the opentype.js Font object without touching
 * the parser (CLAUDE.md: frozen surfaces are consumed, not modified).
 */

/** A single fvar axis record as opentype.js exposes it. */
export interface FvarAxisRecord {
  tag: string;
  minValue: number;
  defaultValue: number;
  maxValue: number;
}

/** The minimal structural shape we read off an opentype.js Font for fvar. */
export interface FvarBearingFont {
  tables?: {
    fvar?: {
      axes?: FvarAxisRecord[];
    };
  };
}

/** Designed bounds of the `wdth` axis, in the font's declared axis units. */
export interface WdthAxis {
  readonly min: number;
  readonly default: number;
  readonly max: number;
}

/**
 * Extract the `wdth` axis bounds from a parsed font's `fvar` table.
 * Returns null when the font is not variable or exposes no `wdth` axis.
 */
export function getWdthAxis(font: FvarBearingFont | null | undefined): WdthAxis | null {
  const axes = font?.tables?.fvar?.axes;
  if (!axes || axes.length === 0) return null;
  const wdth = axes.find((a) => a.tag === 'wdth');
  if (!wdth) return null;
  return { min: wdth.minValue, default: wdth.defaultValue, max: wdth.maxValue };
}

/** True when the font is variable and exposes a horizontal-width (`wdth`) axis. */
export function hasWdthAxis(font: FvarBearingFont | null | undefined): boolean {
  return getWdthAxis(font) !== null;
}

/**
 * vf/probe.ts — Tier-0 capability probe + stretch→wdth mapping.
 *
 * The `tier: 'auto'` dispatcher calls `probeTier0(axis, cfg)` to decide whether
 * the opportunistic variable-font tier can honor the requested configuration.
 * SUPPORTED only when the font exposes a `wdth` axis AND the requested stretch
 * range fits INSIDE the designed axis range (no 4.5× beyond what the designer
 * drew) AND the axis is horizontal (`wdth` is horizontal by definition).
 * Otherwise the probe DECLINES with an explicit reason so `auto` falls through
 * to the WebGL/SVG tiers. All pure — no DOM (RESEARCH §3; refs/examples/07).
 *
 * UNITS: the registered `wdth` axis and CSS `font-stretch` are both PERCENTAGES
 * of normal (default 100). A stretch RATIO of r maps to r×100 %. So a config
 * `maxStretchRatio` of R fits the axis iff R ≤ axis.max/100, and the (optional)
 * `minStretchRatio` m fits iff m ≥ axis.min/100. This is the spec convention;
 * legacy multiplier-scale fonts (Skia) are out of scope for the percentage path.
 */
import type { WdthAxis } from './detect';

/** The stretch-range fields the probe reads (subset of the README config). */
export interface StretchRangeConfig {
  /** Widest ratio the engine may reach (1 = normal). Default 4.5. */
  maxStretchRatio?: number;
  /** Narrowest ratio the engine may reach (1 = normal). Default 1. */
  minStretchRatio?: number;
  /** Stretch axis. `wdth` only satisfies 'horizontal'. Default 'horizontal'. */
  axis?: 'horizontal' | 'vertical' | 'dual';
}

/** Why Tier 0 declined — lets the dispatcher log/branch precisely. */
export type Tier0DeclineReason =
  | 'no-wdth-axis'
  | 'non-horizontal-axis'
  | 'range-exceeds-axis';

/** ratio → clamped `wdth`/`font-stretch` percentage, bound to one axis. */
export interface WdthMapping {
  readonly axis: WdthAxis;
  /**
   * Map a stretch RATIO (1 = normal) to a `font-stretch` PERCENTAGE, clamped to
   * the designed axis range. `font-stretch` and the numeric `wdth` axis value
   * are the same number by spec, so this doubles as the `font-variation-settings`
   * 'wdth' coordinate.
   */
  toPercent(ratio: number): number;
}

export type Tier0Decision =
  | { readonly supported: true; readonly axis: WdthAxis; readonly mapping: WdthMapping }
  | { readonly supported: false; readonly reason: Tier0DeclineReason };

const DEFAULT_MAX_STRETCH = 4.5;
const DEFAULT_MIN_STRETCH = 1;

/** Build the ratio→percentage mapping for a given `wdth` axis (spec units). */
export function createWdthMapping(axis: WdthAxis): WdthMapping {
  return {
    axis,
    toPercent(ratio: number): number {
      const pct = ratio * 100;
      // clamp into the designed axis range — never drive beyond what exists.
      if (pct < axis.min) return axis.min;
      if (pct > axis.max) return axis.max;
      return pct;
    },
  };
}

/**
 * Decide whether Tier 0 can honor `cfg` for a font whose `wdth` axis is `axis`
 * (or null when the font has none). Cheap, pure, total.
 */
export function probeTier0(
  axis: WdthAxis | null | undefined,
  cfg: StretchRangeConfig = {},
): Tier0Decision {
  if (!axis) return { supported: false, reason: 'no-wdth-axis' };

  // `wdth` is horizontal by definition; vertical/dual requests can't use it.
  const requestedAxis = cfg.axis ?? 'horizontal';
  if (requestedAxis !== 'horizontal') {
    return { supported: false, reason: 'non-horizontal-axis' };
  }

  const maxRatio = cfg.maxStretchRatio ?? DEFAULT_MAX_STRETCH;
  const minRatio = cfg.minStretchRatio ?? DEFAULT_MIN_STRETCH;
  const axisMaxRatio = axis.max / 100;
  const axisMinRatio = axis.min / 100;

  // The full requested range must fit inside the designed axis range.
  // A tiny epsilon absorbs float noise on clean values (e.g. 125/100 = 1.25).
  const EPS = 1e-9;
  if (maxRatio > axisMaxRatio + EPS || minRatio < axisMinRatio - EPS) {
    return { supported: false, reason: 'range-exceeds-axis' };
  }

  return { supported: true, axis, mapping: createWdthMapping(axis) };
}

/**
 * Runtime feature check (browser only): does the engine support
 * `font-stretch: <percentage>`? Kept OUT of the pure probe so `probeTier0`
 * stays Node-testable; the dispatcher calls this alongside the probe. Returns
 * true when `CSS.supports` is unavailable (assume support rather than
 * needlessly declining).
 */
export function cssSupportsFontStretchPercentage(): boolean {
  const css = (globalThis as { CSS?: { supports?(p: string, v: string): boolean } }).CSS;
  if (!css || typeof css.supports !== 'function') return true;
  return css.supports('font-stretch', '150%');
}

/**
 * vf/renderer.ts — Fontuccine Tier 0 (opportunistic variable-font `wdth`).
 *
 * The cheapest tier: when the active font is a variable font exposing a `wdth`
 * axis AND the requested range fits the designed axis (see probe.ts), we map the
 * shared per-frame stretch scalar straight to CSS `font-stretch: <percentage>`.
 *
 * ⚠ PERF REALITY (RESEARCH §2; CLAUDE.md rule 5): this is NOT compositor
 * accelerated. Changing `wdth`/`font-stretch` re-runs LAYOUT + PAINT on the main
 * thread every frame, element-scoped. It is D-tier work — fine for ONE headline,
 * never the perf headline claim. Its virtue is TYPOGRAPHIC quality (widths drawn
 * by the type designer) and near-zero setup, not throughput.
 *
 * A11y model DIFFERS from Tiers 1/2 (important):
 *  - Tier 0 stretches the REAL native text directly, so the text itself IS the
 *    render. There is NO hidden-text overlay and NO `aria-hidden` render layer to
 *    manage. The text never leaves the flow, never loses selection, find-in-page
 *    or screen-reader access — it is simply drawn at a different width. Hence
 *    `overlay` is `null` (documented no-op): the shared overlay pattern exists to
 *    re-expose text that a canvas/SVG layer would otherwise hide; Tier 0 hides
 *    nothing, so mounting it would be wrong (it would transparent-out live text).
 *
 * Discipline (CLAUDE.md rules 4, 5, 6, 7):
 *  - `font-stretch` is written directly from JS in the RENDER phase — NOT driven
 *    through an inherited CSS custom property (rule 4 trap).
 *  - We register NO liveness predicate: StretchController owns `onActivity`. We
 *    only subscribe READ (cached measurement for `reserve`) + RENDER (the write).
 *  - Reduced motion / print ⇒ apply the resting width ONCE, register no per-frame
 *    callback (rule 6). No live reflow: `wrap` is 'nowrap' | 'reserve' (rule 7).
 *
 * Tier interface (attach/resize/draw/destroy + readonly element/overlay) mirrors
 * the SVG/WebGL renderers so the engine can swap tiers behind one shape.
 */
import type { Ticker } from '../interaction/ticker';
import { ticker as sharedTicker } from '../interaction/ticker';
import { prefersReducedMotion } from '../interaction/reduced-motion';
import type { WdthAxis } from './detect';
import type { WrapMode, ReserveBasis } from '../dom/overlay';
import type { Overlay } from '../dom/overlay';
import type { WdthMapping } from './probe';
import { createWdthMapping } from './probe';

/** Minimal shape the renderer reads from a StretchController. */
export interface StretchSource {
  readonly value: number;
}

/** Which CSS property carries the width. `font-stretch` is preferred (it
 *  composes with the font-matching algorithm — MDN Variable Fonts guide);
 *  `font-variation-settings` is offered for engines/fonts that need the raw
 *  axis. Both take the same numeric value. */
export type WdthApplyMode = 'font-stretch' | 'font-variation-settings';

export interface VfRendererOptions {
  /** Element whose real text is stretched. Text is NOT moved or hidden. */
  host: HTMLElement;
  /** The designed `wdth` axis bounds (from getWdthAxis). */
  axis: WdthAxis;
  /** Per-frame stretch source (a StretchController or anything with `.value`). */
  controller: StretchSource;
  /** Prebuilt mapping (from the probe). Defaults to createWdthMapping(axis). */
  mapping?: WdthMapping;
  /** Wrap behavior. Default 'nowrap'. No live reflow (rule 7). */
  wrap?: WrapMode;
  /**
   * How `wrap:'reserve'` sizes the reserved box. Default 'tier-capability'.
   *  - 'tier-capability': reserve what THIS tier can actually paint —
   *    `naturalWidth × (axis.max / restingPercent)` (axis-bounded).
   *  - 'uniform': reserve `naturalWidth × maxStretchRatio`, matching the
   *    overlay tiers for cross-tier visual consistency. VF cannot stretch past
   *    its axis, so this leaves a permanent unused gap — the accepted tradeoff.
   */
  reserveBasis?: ReserveBasis;
  /**
   * Max stretch ratio used to size `reserve` under the 'uniform' basis (must
   * match the overlay tiers). Default 4.5. Unused under 'tier-capability'.
   */
  maxStretchRatio?: number;
  /** Which property to write. Default 'font-stretch'. */
  apply?: WdthApplyMode;
  /** Resting stretch ratio for the static reduced-motion draw. Default 1. */
  restingStretch?: number;
  ticker?: Ticker;
  document?: Document;
  respectReducedMotion?: boolean;
  /** Override reduced-motion detection (tests). */
  isReducedMotion?: () => boolean;
}

export interface VfRenderer {
  /** Apply styles + subscribe. Idempotent. */
  attach(): void;
  /** Invalidate cached measurements (re-measured next READ phase). */
  resize(): void;
  /** One-shot render (write phase). Also the subscribed RENDER callback. */
  draw(now?: number): void;
  /** Tear down subscriptions/observers; restore the host's inline style. */
  destroy(): void;
  /** The stretched element (the real text lives here — never hidden). */
  readonly element: HTMLElement;
  /**
   * Tier 0 hides nothing, so there is no a11y overlay to manage — `null` by
   * design (see file header). The cross-tier field is kept for interface parity.
   */
  readonly overlay: Overlay | null;
}

function writeWidth(el: HTMLElement, mode: WdthApplyMode, pct: number, precision = 3): void {
  const n = Number(pct.toFixed(precision));
  if (mode === 'font-variation-settings') {
    el.style.setProperty('font-variation-settings', `"wdth" ${n}`);
  } else {
    el.style.setProperty('font-stretch', `${n}%`);
  }
}

export function createVfRenderer(options: VfRendererOptions): VfRenderer {
  const {
    host,
    axis,
    controller,
    wrap = 'nowrap',
    apply = 'font-stretch',
    restingStretch = 1,
    reserveBasis = 'tier-capability',
    maxStretchRatio = 4.5,
  } = options;

  const ticker = options.ticker ?? sharedTicker;
  const doc = options.document ?? host.ownerDocument;
  if (!doc) throw new Error('createVfRenderer: no document available');
  const respectRM = options.respectReducedMotion ?? true;
  const isRM = options.isReducedMotion ?? prefersReducedMotion;
  const mapping = options.mapping ?? createWdthMapping(axis);

  // --- save the host's inline style so destroy() restores it exactly.
  const savedCssText = host.getAttribute('style') ?? '';

  // Static wrap style — set once, never per frame (rule 7: no live reflow).
  //  'nowrap'  → the line never wraps at any width.
  //  'reserve' → keep nowrap AND reserve the widest box up front (min-width),
  //              measured in the READ phase, so following content never reflows.
  host.style.setProperty('white-space', 'nowrap');

  // --- lifecycle state.
  let attached = false;
  let subscribed = false;
  let dirty = wrap === 'reserve'; // only 'reserve' needs a measurement
  let reservedFrom: number | null = null;
  let lastPct = Number.NaN;
  const unsubs: Array<() => void> = [];
  let resizeObserver: ResizeObserver | null = null;
  let scrollHandler: (() => void) | null = null;

  /** READ phase: measure natural width once (for 'reserve'), cached. */
  function readPhase(): void {
    if (wrap !== 'reserve' || !dirty) return;
    dirty = false;
    // Measure at natural width: reserve BEFORE the first stretch is painted,
    // then reserve the widest box the axis can reach (axis.max %) so downstream
    // layout never shifts mid-interaction. Approximate (advance widths are
    // designer-drawn, not linear), matching the overlay's reserve semantics.
    const w = host.getBoundingClientRect().width;
    if (Number.isFinite(w) && w > 0) {
      reservedFrom = w;
      let factor: number;
      if (reserveBasis === 'uniform') {
        // Match the overlay tiers exactly: reserve the full max-ratio box even
        // though VF cannot stretch past its axis (leaves a permanent gap).
        factor = maxStretchRatio;
      } else {
        // 'tier-capability': reserve only the widest box the axis can reach.
        const restPct = mapping.toPercent(restingStretch);
        factor = restPct > 0 ? axis.max / restPct : axis.max / 100;
      }
      host.style.setProperty('min-width', `${w * factor}px`);
    }
  }

  /** WRITE only: map the ratio → clamped percentage and set the style. */
  function paint(ratio: number): void {
    const pct = mapping.toPercent(ratio);
    if (pct === lastPct) return;
    lastPct = pct;
    writeWidth(host, apply, pct);
  }

  function draw(): void {
    // RENDER phase. `controller.value` is a plain number, not a DOM read.
    paint(controller.value);
  }

  function attach(): void {
    if (attached) return;
    attached = true;

    if (respectRM && isRM()) {
      // Reduced motion / print: reserve (if asked) + paint once at rest, and
      // register NO per-frame callback — zero ongoing engine work (rule 6).
      readPhase();
      paint(restingStretch);
      return;
    }

    // Animated: READ (cached reserve measure) + RENDER (the write). We do NOT
    // register an activity predicate — the StretchController owns liveness.
    unsubs.push(ticker.read(readPhase));
    unsubs.push(ticker.render(draw));
    subscribed = true;

    // Invalidate cached measurement on resize + scroll (re-measured in READ).
    if (wrap === 'reserve') {
      if (typeof ResizeObserver !== 'undefined') {
        resizeObserver = new ResizeObserver(() => {
          dirty = true;
          ticker.wake();
        });
        resizeObserver.observe(host);
      }
      const view = doc.defaultView;
      if (view) {
        scrollHandler = () => {
          dirty = true;
        };
        view.addEventListener('scroll', scrollHandler, { passive: true });
      }
    }

    ticker.wake();
  }

  function resize(): void {
    dirty = wrap === 'reserve';
    ticker.wake();
  }

  function destroy(): void {
    for (const u of unsubs) u();
    unsubs.length = 0;
    subscribed = false;
    if (resizeObserver) {
      resizeObserver.disconnect();
      resizeObserver = null;
    }
    if (scrollHandler && doc.defaultView) {
      doc.defaultView.removeEventListener('scroll', scrollHandler);
      scrollHandler = null;
    }
    // Restore the host's inline style exactly (text was never moved/hidden).
    if (savedCssText) host.setAttribute('style', savedCssText);
    else host.removeAttribute('style');
    attached = false;
    reservedFrom = null;
    lastPct = Number.NaN;
  }

  return {
    attach,
    resize,
    draw,
    destroy,
    element: host,
    overlay: null,
    // internal diagnostics (not part of the cross-tier interface)
    get _subscribed() {
      return subscribed;
    },
    get _reservedFrom() {
      return reservedFrom;
    },
  } as VfRenderer & { readonly _subscribed: boolean; readonly _reservedFrom: number | null };
}

/**
 * webgl/gl/capability.ts — WebGL2 support probe (obligation 4: degrade cleanly).
 *
 * The engine calls this BEFORE choosing Tier 1. When it returns unsupported the
 * engine must drop to the SVG tier — Tier 1 NEVER renders nothing. We also
 * require the pieces this tier depends on: R32F texture storage (the LUT) and
 * instanced drawing (drawElementsInstanced is core in WebGL2, but we still
 * verify context creation and a float-color texture format).
 */

export interface WebGL2Support {
  supported: boolean;
  reason?: string;
}

/**
 * Probe WebGL2 availability using a throwaway canvas. Safe in SSR/Node (returns
 * unsupported when no document/canvas exists). Does NOT retain any context.
 */
export function detectWebGL2(createCanvas?: () => HTMLCanvasElement): WebGL2Support {
  try {
    const make =
      createCanvas ??
      (typeof document !== 'undefined'
        ? () => document.createElement('canvas')
        : null);
    if (!make) return { supported: false, reason: 'no-document' };

    const canvas = make();
    const gl = canvas.getContext('webgl2', {
      alpha: true,
      premultipliedAlpha: true,
      antialias: false,
      depth: false,
      stencil: false,
    }) as WebGL2RenderingContext | null;

    if (!gl) return { supported: false, reason: 'no-webgl2-context' };

    try {
      // R32F is core-renderable-optional but core-TEXTURABLE in WebGL2; verify the
      // enum path exists (older polyfills lie about being WebGL2).
      if (typeof gl.texStorage2D !== 'function' || typeof gl.drawElementsInstanced !== 'function') {
        return { supported: false, reason: 'missing-webgl2-entrypoints' };
      }

      return { supported: true };
    } finally {
      // The comment above promises "does NOT retain any context" — without this
      // the throwaway context stays alive until GC, and every attach() call (the
      // engine probes on each one) leaks a live context. Browsers cap concurrent
      // WebGL contexts (~8-16), so repeated attach()/detach() cycles quickly hit
      // "Too many active WebGL contexts" and the real shared context can get
      // silently evicted. Force it lost immediately; the real shared backend
      // (gl/shared.ts) creates its own context separately.
      gl.getExtension('WEBGL_lose_context')?.loseContext();
    }
  } catch (e) {
    return { supported: false, reason: `probe-threw:${(e as Error)?.message ?? 'unknown'}` };
  }
}

/**
 * webgl/gl/device.ts — the shared WebGL2 backend + an injectable interface.
 *
 * `RenderBackend` is the seam between the renderer's (testable) orchestration
 * and the (headless-untestable) GL calls: the renderer holds a backend and one
 * `RunHandle` per text instance and never touches `gl` directly. The real
 * `WebGL2Backend` owns ONE shared canvas + context + program + shared slice-grid
 * geometry + the shared MSDF atlas texture for the WHOLE page (RESEARCH §2:
 * layer-memory discipline — never a context per element). A `NullBackend`-shaped
 * mock in tests verifies single-context reuse, context-loss re-init, and draw
 * scheduling without a GPU.
 *
 * Design recommendation to the architect (benchmark deferred — no GPU here):
 * ONE fixed full-viewport shared canvas + per-instance viewport+scissor from the
 * host's screen rect. The alternative (a positioned canvas per element) forces a
 * context per element, which is exactly the layer-memory cost RESEARCH §2 warns
 * against — so a shared context REQUIRES the single-canvas+scissor design.
 */
import type { PackedLUTAtlas } from '../lut-texture';
import type { MSDFBitmap } from '../msdf/generator';
import type { RGBAColor } from '../types';
import { buildSliceGrid } from '../slice-grid';
import { VERTEX_SHADER, FRAGMENT_SHADER } from './shaders';

export interface Region {
  /** CSS px, origin top-left of the shared canvas viewport. */
  x: number;
  y: number;
  w: number;
  h: number;
}

/** Static per-run GPU inputs — provided at build AND rebuilt on context restore. */
export interface GlyphRunData {
  /** Interleaved static per-glyph instance attributes (9 floats/glyph). */
  instances: Float32Array;
  instanceCount: number;
  /** This run's cumulative-flex LUTs, packed row-per-glyph. */
  lutAtlas: PackedLUTAtlas;
  /** Slice count (grid resolution). */
  slices: number;
}

export interface FrameParams {
  region: Region;
  /** Device pixel ratio (CSS px region → device-px scissor/viewport). */
  dpr: number;
  stretch: number;
  origin: number;
  color: RGBAColor;
  pxRange: number;
  atlasSize: number;
  grain: number;
  aberration: number;
  stretchDir: [number, number];
  time: number;
  dispIntensity: number;
  dispScale: [number, number];
}

export interface RunHandle {
  /** (Re)upload static run data. Called at build and on context restore. */
  upload(data: GlyphRunData): void;
  /** Issue the instanced, scissored draw for this run. */
  draw(params: FrameParams): void;
  dispose(): void;
}

export interface RenderBackend {
  readonly supported: boolean;
  readonly canvas: HTMLCanvasElement | null;
  isContextLost(): boolean;
  /** Size the shared drawing buffer to the viewport at the given DPR. */
  ensureSize(cssWidth: number, cssHeight: number, dpr: number): void;
  /** Ensure the shared MSDF atlas texture exists at `size` texels (square). */
  ensureAtlas(size: number): void;
  /** Upload one MSDF glyph cell into the shared atlas at device-texel (x,y). */
  uploadAtlasCell(x: number, y: number, bitmap: MSDFBitmap): void;
  /**
   * Clear the shared drawing buffer ONCE per frame. Instances share one canvas,
   * so the first instance to draw this frame (unique `token`, e.g. the ticker
   * `now`) clears the whole buffer; later instances with the same token are
   * no-ops. Avoids instances erasing each other and prevents scroll trails.
   */
  beginFrame(token: number): void;
  /**
   * Upload (or clear) the shared displacement noise texture. Optional: a mock
   * backend may omit it. `null` clears. Zero-cost until a renderer with an
   * enabled `displacement` effect decodes its image (obligation 3).
   */
  setNoise?(image: TexImageSource | null): void;
  createRun(): RunHandle;
  onContextLost(cb: () => void): () => void;
  onContextRestored(cb: () => void): () => void;
  /** Number of GL contexts created (single-context invariant test). */
  readonly contextCreationCount: number;
  destroy(): void;
}

// ── real WebGL2 backend (inspection-verified; no headless GL to run it) ───────

const FLOATS_PER_INSTANCE = 9;

interface GlProgramState {
  program: WebGLProgram;
  gridBuffer: WebGLBuffer;
  indexBuffer: WebGLBuffer;
  indexCount: number;
  atlasTex: WebGLTexture | null;
  atlasSize: number;
  uniforms: Record<string, WebGLUniformLocation | null>;
}

class WebGL2Run implements RunHandle {
  private vao: WebGLVertexArrayObject | null = null;
  private instanceBuffer: WebGLBuffer | null = null;
  private lutTex: WebGLTexture | null = null;
  private lutWidth = 0;
  private lutHeight = 0;
  private instanceCount = 0;
  private slices = 0;
  private readonly backend: WebGL2Backend;

  constructor(backend: WebGL2Backend) {
    this.backend = backend;
  }

  upload(data: GlyphRunData): void {
    const gl = this.backend.glOrNull;
    if (!gl) return;
    const st = this.backend.state;
    if (!st) return;

    this.instanceCount = data.instanceCount;
    this.slices = data.slices;

    if (!this.vao) this.vao = gl.createVertexArray();
    gl.bindVertexArray(this.vao);

    // shared grid geometry (position + element buffer live on the backend)
    gl.bindBuffer(gl.ARRAY_BUFFER, st.gridBuffer);
    const aBox = gl.getAttribLocation(st.program, 'a_boxCoord');
    gl.enableVertexAttribArray(aBox);
    gl.vertexAttribPointer(aBox, 2, gl.FLOAT, false, 0, 0);
    gl.vertexAttribDivisor(aBox, 0);
    gl.bindBuffer(gl.ELEMENT_ARRAY_BUFFER, st.indexBuffer);

    // instanced static per-glyph attributes
    if (!this.instanceBuffer) this.instanceBuffer = gl.createBuffer();
    gl.bindBuffer(gl.ARRAY_BUFFER, this.instanceBuffer);
    gl.bufferData(gl.ARRAY_BUFFER, data.instances, gl.STATIC_DRAW);
    const stride = FLOATS_PER_INSTANCE * 4;
    const attr = (name: string, size: number, offsetFloats: number): void => {
      const loc = gl.getAttribLocation(st.program, name);
      if (loc < 0) return;
      gl.enableVertexAttribArray(loc);
      gl.vertexAttribPointer(loc, size, gl.FLOAT, false, stride, offsetFloats * 4);
      gl.vertexAttribDivisor(loc, 1);
    };
    attr('a_glyphOrigin', 1, 0);
    attr('a_glyphWidth', 1, 1);
    attr('a_glyphY', 2, 2);
    attr('a_atlasUVOrigin', 2, 4);
    attr('a_atlasUVSize', 2, 6);
    attr('a_lutRow', 1, 8);

    // per-run LUT texture (R32F, width=N+1, height=glyphCount), NEAREST
    if (!this.lutTex) this.lutTex = gl.createTexture();
    this.lutWidth = data.lutAtlas.width;
    this.lutHeight = data.lutAtlas.height;
    gl.bindTexture(gl.TEXTURE_2D, this.lutTex);
    gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_MIN_FILTER, gl.NEAREST);
    gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_MAG_FILTER, gl.NEAREST);
    gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_WRAP_S, gl.CLAMP_TO_EDGE);
    gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_WRAP_T, gl.CLAMP_TO_EDGE);
    if (this.lutWidth > 0 && this.lutHeight > 0) {
      gl.texImage2D(
        gl.TEXTURE_2D, 0, gl.R32F, this.lutWidth, this.lutHeight, 0, gl.RED, gl.FLOAT,
        data.lutAtlas.data,
      );
    }
    gl.bindVertexArray(null);
  }

  draw(p: FrameParams): void {
    const gl = this.backend.glOrNull;
    const st = this.backend.state;
    if (!gl || !st || !this.vao || this.instanceCount === 0) return;

    gl.useProgram(st.program);
    gl.bindVertexArray(this.vao);

    // scissor + viewport to this instance's screen rect (shared canvas).
    // Region is CSS px; scissor/viewport are device px (GL y-up origin).
    const dpr = p.dpr;
    const bufH = gl.drawingBufferHeight;
    const dx = Math.round(p.region.x * dpr);
    const dw = Math.round(p.region.w * dpr);
    const dh = Math.round(p.region.h * dpr);
    const sy = bufH - Math.round((p.region.y + p.region.h) * dpr); // GL y-up origin
    gl.enable(gl.SCISSOR_TEST);
    gl.scissor(dx, sy, dw, dh);
    gl.viewport(dx, sy, dw, dh);

    // premultiplied-alpha blending over arbitrary page backgrounds.
    gl.enable(gl.BLEND);
    gl.blendFunc(gl.ONE, gl.ONE_MINUS_SRC_ALPHA);

    const u = st.uniforms;
    gl.uniform1f(u.u_stretch!, p.stretch);
    gl.uniform1f(u.u_origin!, p.origin); // region-relative; viewport positions the region
    gl.uniform2f(u.u_viewport!, p.region.w, p.region.h); // CSS px, matches posX/posY units
    gl.uniform4f(u.u_color!, p.color.r, p.color.g, p.color.b, p.color.a);
    gl.uniform1f(u.u_pxRange!, p.pxRange);
    gl.uniform2f(u.u_atlasSize!, st.atlasSize, st.atlasSize);
    gl.uniform1f(u.u_grainIntensity!, p.grain);
    gl.uniform1f(u.u_aberration!, p.aberration);
    gl.uniform2f(u.u_stretchDir!, p.stretchDir[0], p.stretchDir[1]);
    gl.uniform1f(u.u_time!, p.time);
    gl.uniform1f(u.u_dispIntensity!, p.dispIntensity);
    gl.uniform2f(u.u_dispScale!, p.dispScale[0], p.dispScale[1]);
    gl.uniform2i(u.u_lutSize!, this.lutWidth, this.lutHeight);

    // texture units: 0 = MSDF atlas, 1 = LUT, 2 = noise (bound by backend if any)
    gl.activeTexture(gl.TEXTURE0);
    gl.bindTexture(gl.TEXTURE_2D, st.atlasTex);
    gl.uniform1i(u.u_msdfAtlas!, 0);
    gl.activeTexture(gl.TEXTURE1);
    gl.bindTexture(gl.TEXTURE_2D, this.lutTex);
    gl.uniform1i(u.u_lut!, 1);
    this.backend.bindNoise(2, u.u_noise, u.u_hasNoise);

    gl.drawElementsInstanced(gl.TRIANGLES, st.indexCount, gl.UNSIGNED_SHORT, 0, this.instanceCount);

    gl.disable(gl.SCISSOR_TEST);
    gl.bindVertexArray(null);
  }

  dispose(): void {
    const gl = this.backend.glOrNull;
    if (!gl) return;
    if (this.vao) gl.deleteVertexArray(this.vao);
    if (this.instanceBuffer) gl.deleteBuffer(this.instanceBuffer);
    if (this.lutTex) gl.deleteTexture(this.lutTex);
    this.vao = null;
    this.instanceBuffer = null;
    this.lutTex = null;
  }
}

export class WebGL2Backend implements RenderBackend {
  readonly canvas: HTMLCanvasElement;
  private gl: WebGL2RenderingContext | null = null;
  state: GlProgramState | null = null;
  private lostCbs = new Set<() => void>();
  private restoredCbs = new Set<() => void>();
  private _creations = 0;
  private noiseTex: WebGLTexture | null = null;
  private readonly gridSlices: number;

  constructor(canvas: HTMLCanvasElement, slices: number) {
    this.canvas = canvas;
    this.gridSlices = slices;
    canvas.addEventListener('webglcontextlost', this.onLost as EventListener, false);
    canvas.addEventListener('webglcontextrestored', this.onRestored as EventListener, false);
    this.initContext();
  }

  get glOrNull(): WebGL2RenderingContext | null {
    return this.gl;
  }
  get supported(): boolean {
    return this.gl !== null;
  }
  get contextCreationCount(): number {
    return this._creations;
  }

  isContextLost(): boolean {
    return !this.gl || this.gl.isContextLost();
  }

  private onLost = (e: Event): void => {
    e.preventDefault(); // REQUIRED so the context can be restored (obligation 1)
    this.state = null;
    for (const cb of this.lostCbs) cb();
  };

  private onRestored = (): void => {
    this.initContext();
    for (const cb of this.restoredCbs) cb(); // renderers re-upload run data + atlas
  };

  private initContext(): void {
    const gl = this.canvas.getContext('webgl2', {
      alpha: true,
      premultipliedAlpha: true,
      antialias: false,
      depth: false,
      stencil: false,
    }) as WebGL2RenderingContext | null;
    if (!gl) {
      this.gl = null;
      return;
    }
    this.gl = gl;
    this._creations++;
    this.buildProgram();
  }

  private buildProgram(): void {
    const gl = this.gl!;
    const compile = (type: number, src: string): WebGLShader => {
      const sh = gl.createShader(type)!;
      gl.shaderSource(sh, src);
      gl.compileShader(sh);
      if (!gl.getShaderParameter(sh, gl.COMPILE_STATUS)) {
        const log = gl.getShaderInfoLog(sh);
        gl.deleteShader(sh);
        throw new Error(`[fontuccine/webgl] shader compile failed: ${log}`);
      }
      return sh;
    };
    const program = gl.createProgram()!;
    gl.attachShader(program, compile(gl.VERTEX_SHADER, VERTEX_SHADER));
    gl.attachShader(program, compile(gl.FRAGMENT_SHADER, FRAGMENT_SHADER));
    gl.linkProgram(program);
    if (!gl.getProgramParameter(program, gl.LINK_STATUS)) {
      throw new Error(`[fontuccine/webgl] link failed: ${gl.getProgramInfoLog(program)}`);
    }

    const grid = buildSliceGrid(this.gridSlices);
    const gridBuffer = gl.createBuffer()!;
    gl.bindBuffer(gl.ARRAY_BUFFER, gridBuffer);
    gl.bufferData(gl.ARRAY_BUFFER, grid.boxCoords, gl.STATIC_DRAW);
    const indexBuffer = gl.createBuffer()!;
    gl.bindBuffer(gl.ELEMENT_ARRAY_BUFFER, indexBuffer);
    gl.bufferData(gl.ELEMENT_ARRAY_BUFFER, grid.indices, gl.STATIC_DRAW);

    const uNames = [
      'u_lut', 'u_lutSize', 'u_stretch', 'u_origin', 'u_viewport', 'u_msdfAtlas',
      'u_color', 'u_pxRange', 'u_atlasSize', 'u_grainIntensity', 'u_aberration',
      'u_stretchDir', 'u_time', 'u_dispIntensity', 'u_dispScale', 'u_noise', 'u_hasNoise',
    ];
    const uniforms: Record<string, WebGLUniformLocation | null> = {};
    for (const n of uNames) uniforms[n] = gl.getUniformLocation(program, n);

    this.state = {
      program,
      gridBuffer,
      indexBuffer,
      indexCount: grid.indices.length,
      atlasTex: null,
      atlasSize: 0,
      uniforms,
    };
  }

  ensureSize(cssWidth: number, cssHeight: number, dpr: number): void {
    const w = Math.max(1, Math.round(cssWidth * dpr));
    const h = Math.max(1, Math.round(cssHeight * dpr));
    if (this.canvas.width !== w) this.canvas.width = w;
    if (this.canvas.height !== h) this.canvas.height = h;
  }

  ensureAtlas(size: number): void {
    const gl = this.gl;
    const st = this.state;
    if (!gl || !st) return;
    if (st.atlasTex && st.atlasSize === size) return;
    if (st.atlasTex) gl.deleteTexture(st.atlasTex);
    const tex = gl.createTexture()!;
    gl.bindTexture(gl.TEXTURE_2D, tex);
    gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_MIN_FILTER, gl.LINEAR);
    gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_MAG_FILTER, gl.LINEAR);
    gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_WRAP_S, gl.CLAMP_TO_EDGE);
    gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_WRAP_T, gl.CLAMP_TO_EDGE);
    gl.texImage2D(gl.TEXTURE_2D, 0, gl.RGBA8, size, size, 0, gl.RGBA, gl.UNSIGNED_BYTE, null);
    st.atlasTex = tex;
    st.atlasSize = size;
  }

  uploadAtlasCell(x: number, y: number, bitmap: MSDFBitmap): void {
    const gl = this.gl;
    const st = this.state;
    if (!gl || !st || !st.atlasTex) return;
    gl.bindTexture(gl.TEXTURE_2D, st.atlasTex);
    gl.pixelStorei(gl.UNPACK_FLIP_Y_WEBGL, false);
    gl.texSubImage2D(
      gl.TEXTURE_2D, 0, x, y, bitmap.width, bitmap.height, gl.RGBA, gl.UNSIGNED_BYTE,
      new Uint8Array(bitmap.data.buffer),
    );
  }

  /** Bind the (optional) displacement noise texture to a unit; sets u_hasNoise. */
  bindNoise(unit: number, uNoise: WebGLUniformLocation | null, uHas: WebGLUniformLocation | null): void {
    const gl = this.gl;
    if (!gl) return;
    if (this.noiseTex && uNoise) {
      gl.activeTexture(gl.TEXTURE0 + unit);
      gl.bindTexture(gl.TEXTURE_2D, this.noiseTex);
      gl.uniform1i(uNoise, unit);
      if (uHas) gl.uniform1i(uHas, 1);
    } else if (uHas) {
      gl.uniform1i(uHas, 0);
    }
  }

  /** Upload a decoded displacement noise image (RGBA, repeat-wrapped). */
  setNoise(image: TexImageSource | null): void {
    const gl = this.gl;
    if (!gl) return;
    if (!image) {
      if (this.noiseTex) gl.deleteTexture(this.noiseTex);
      this.noiseTex = null;
      return;
    }
    if (!this.noiseTex) this.noiseTex = gl.createTexture();
    gl.bindTexture(gl.TEXTURE_2D, this.noiseTex);
    gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_WRAP_S, gl.REPEAT);
    gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_WRAP_T, gl.REPEAT);
    gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_MIN_FILTER, gl.LINEAR);
    gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_MAG_FILTER, gl.LINEAR);
    gl.texImage2D(gl.TEXTURE_2D, 0, gl.RGBA, gl.RGBA, gl.UNSIGNED_BYTE, image);
  }

  private lastFrameToken = Number.NaN;
  beginFrame(token: number): void {
    const gl = this.gl;
    if (!gl) return;
    if (token === this.lastFrameToken) return; // already cleared this frame
    this.lastFrameToken = token;
    gl.viewport(0, 0, gl.drawingBufferWidth, gl.drawingBufferHeight);
    gl.disable(gl.SCISSOR_TEST);
    gl.clearColor(0, 0, 0, 0); // premultiplied transparent
    gl.clear(gl.COLOR_BUFFER_BIT);
  }

  createRun(): RunHandle {
    return new WebGL2Run(this);
  }

  onContextLost(cb: () => void): () => void {
    this.lostCbs.add(cb);
    return () => this.lostCbs.delete(cb);
  }
  onContextRestored(cb: () => void): () => void {
    this.restoredCbs.add(cb);
    return () => this.restoredCbs.delete(cb);
  }

  destroy(): void {
    this.canvas.removeEventListener('webglcontextlost', this.onLost as EventListener);
    this.canvas.removeEventListener('webglcontextrestored', this.onRestored as EventListener);
    const gl = this.gl;
    if (gl && this.state) {
      gl.deleteProgram(this.state.program);
      gl.deleteBuffer(this.state.gridBuffer);
      gl.deleteBuffer(this.state.indexBuffer);
      if (this.state.atlasTex) gl.deleteTexture(this.state.atlasTex);
    }
    if (gl && this.noiseTex) gl.deleteTexture(this.noiseTex);
    this.lostCbs.clear();
    this.restoredCbs.clear();
    this.state = null;
    this.gl = null;
  }
}

/**
 * webgl/gl/shaders.ts — Tier-1 GLSL ES 3.00 program source.
 *
 * Derived from refs/examples/03 (vertex) + 04 (fragment). Two DELIBERATE changes
 * from 03, both required by this tier's obligations (flagged in the report):
 *   1. STRETCH-INDEPENDENT LUT: the texture stores normalized cumulative FLEX
 *      C(u); the ratio is applied via `u_stretch` so nothing is re-uploaded per
 *      frame (parity.ts explains the algebra & exactness envelope). This keeps
 *      the locked "remap through a cumulative LUT texture; UVs original" design.
 *   2. INSTANCED, static per-glyph attributes + a per-glyph LUT ROW packed into
 *      ONE texture, so a whole run draws with zero rebinds and zero per-frame
 *      buffer uploads — only `u_stretch`/`u_origin` (+ effect scalars) change.
 *
 * The LUT is sampled with an explicit two-tap texelFetch `mix()` (not hardware
 * LINEAR) so we never depend on OES_texture_float_linear for R32F.
 *
 * Post-fx (fragment) are branchless when their intensity is 0 (obligation 3):
 * grain, chromatic aberration (∝ velocity, along the stretch axis), and a
 * displacement noise-texture UV warp. Output is PREMULTIPLIED alpha for correct
 * compositing over arbitrary page backgrounds (obligation 2).
 */

export const VERTEX_SHADER = /* glsl */ `#version 300 es
precision highp float;

// Shared subdivided-quad grid (slice-grid.ts): box coords in [0,1]^2.
in vec2 a_boxCoord;

// Instanced, STATIC per-glyph attributes (uploaded once; never per frame).
in float a_glyphOrigin;   // origin factor: inkLeft = u_origin + u_stretch*a_glyphOrigin
in float a_glyphWidth;    // W = bounds.max - bounds.min (unstretched ink width, px)
in vec2  a_glyphY;        // (yTop_px from run top, height_px) SVG-down placement (no stretch)
in vec2  a_atlasUVOrigin; // atlas UV at box (0,0)  (image-space, may carry flipped V)
in vec2  a_atlasUVSize;   // atlas UV delta across the box (size.y may be negative)
in float a_lutRow;        // this glyph's row in the packed LUT texture

uniform sampler2D u_lut;      // R32F, (N+1) x glyphCount, NEAREST; holds C(u)
uniform ivec2 u_lutSize;      // (N+1, glyphCount)
uniform float u_stretch;      // horizontal stretch ratio (1 = identity)
uniform float u_origin;       // run origin in device px
uniform vec2  u_viewport;     // device px viewport (for clip mapping)

out vec2 v_atlasUV;

// Two-tap linear sample of the cumulative-flex LUT at normalized u for this row.
float sampleCumFlex(float u, int row) {
  int N = u_lutSize.x - 1;              // boundary count
  float f = clamp(u, 0.0, 1.0) * float(N);
  int i = int(floor(f));
  i = min(i, N - 1);
  float t = f - float(i);
  float a = texelFetch(u_lut, ivec2(i, row), 0).r;
  float b = texelFetch(u_lut, ivec2(i + 1, row), 0).r;
  return mix(a, b, t);
}

void main() {
  float uOrig = a_boxCoord.x;                       // original normalized column
  float C = sampleCumFlex(uOrig, int(a_lutRow + 0.5));
  // remapped normalized position: identity at stretch=1, flex-weighted growth.
  float remapped = uOrig + (u_stretch - 1.0) * C;

  float inkLeft = u_origin + u_stretch * a_glyphOrigin;
  float posX = inkLeft + a_glyphWidth * remapped;
  // Glyph geometry is SVG-down (y increases downward, like the SVG tier): box y=0
  // is the glyph's visual top (bbox.minY), box y=1 its visual bottom (bbox.maxY).
  // a_glyphY = (yTop_px = top offset from run top, height_px); place straight down.
  float posY = a_glyphY.x + a_boxCoord.y * a_glyphY.y;

  v_atlasUV = a_atlasUVOrigin + a_boxCoord * a_atlasUVSize;

  vec2 clip = vec2(posX / u_viewport.x * 2.0 - 1.0, 1.0 - posY / u_viewport.y * 2.0);
  gl_Position = vec4(clip, 0.0, 1.0);
}
`;

export const FRAGMENT_SHADER = /* glsl */ `#version 300 es
precision highp float;

in vec2 v_atlasUV;
out vec4 fragColor;

uniform sampler2D u_msdfAtlas;
uniform vec4  u_color;         // straight-alpha ink color
uniform float u_pxRange;       // msdf distance range in atlas texels
uniform vec2  u_atlasSize;     // atlas texture size (texels)

// Post-fx (all optional; each is a no-op branch when its scalar is ~0).
uniform float u_grainIntensity;   // 0..1 film grain
uniform float u_aberration;       // channel split (px), ∝ velocity
uniform vec2  u_stretchDir;       // unit vector of the active stretch axis
uniform float u_time;
uniform float u_dispIntensity;    // displacement warp strength (px)
uniform vec2  u_dispScale;        // noise sampling scale
uniform sampler2D u_noise;        // displacement noise texture
uniform int   u_hasNoise;         // 1 when a displacement texture is bound

float median3(vec3 v) { return max(min(v.r, v.g), min(max(v.r, v.g), v.b)); }
float sampleSD(vec2 uv) { return median3(texture(u_msdfAtlas, uv).rgb) - 0.5; }
float hash(vec2 p) { return fract(sin(dot(p, vec2(127.1, 311.7)) + u_time) * 43758.5453); }

void main() {
  vec2 uv = v_atlasUV;

  // Displacement: warp the sampling UV by a noise texture BEFORE distance
  // sampling — the distance field stays continuous so edges do not tear.
  if (u_dispIntensity > 0.001 && u_hasNoise == 1) {
    vec2 n = texture(u_noise, uv * u_dispScale + u_time * 0.05).rg - 0.5;
    uv += n * (u_dispIntensity / u_atlasSize);
  }

  vec2 unitRange = vec2(u_pxRange) / u_atlasSize;
  vec2 screenTexSize = vec2(1.0) / fwidth(uv);
  float screenPxRange = max(0.5 * dot(unitRange, screenTexSize), 1.0);

  float alpha;
  if (u_aberration > 0.001) {
    // Chromatic aberration: split channels along the stretch axis.
    vec2 off = u_stretchDir * u_aberration / u_atlasSize;
    float r = clamp(sampleSD(uv - off) * screenPxRange + 0.5, 0.0, 1.0);
    float g = clamp(sampleSD(uv)       * screenPxRange + 0.5, 0.0, 1.0);
    float b = clamp(sampleSD(uv + off) * screenPxRange + 0.5, 0.0, 1.0);
    float a = max(max(r, g), b) * u_color.a;
    // premultiplied output
    fragColor = vec4(u_color.rgb * vec3(r, g, b) * u_color.a, a);
    alpha = a;
  } else {
    float d = clamp(sampleSD(uv) * screenPxRange + 0.5, 0.0, 1.0);
    alpha = d * u_color.a;
    fragColor = vec4(u_color.rgb * alpha, alpha); // premultiplied
  }

  if (u_grainIntensity > 0.001 && alpha > 0.0) {
    float g = (hash(gl_FragCoord.xy) - 0.5) * u_grainIntensity;
    fragColor.rgb += g * alpha; // stays premultiplied (scaled by coverage)
  }
}
`;

/**
 * webgl/gl/shared.ts — the ONE shared WebGL2 backend for the whole page.
 *
 * RESEARCH §2: one shared canvas/context for every instance (layer-memory
 * discipline) — NEVER a context per element. This ref-counted singleton creates
 * exactly one fixed, full-viewport, pointer-inert canvas + one WebGL2 backend;
 * every renderer draws into its own screen region via scissor. The single
 * `contextCreationCount` is asserted by test/webgl-context.test.ts.
 *
 * A backend factory is injectable so tests substitute a mock (no GPU in Node).
 */
import type { RenderBackend } from './device';
import { WebGL2Backend } from './device';

/** Page-global slice-grid resolution (all instances share one grid). */
export const DEFAULT_GRID_SLICES = 96;

export type BackendFactory = (slices: number) => RenderBackend | null;

let factory: BackendFactory | null = null;
let backend: RenderBackend | null = null;
let refCount = 0;
let gridSlices = DEFAULT_GRID_SLICES;
/** Requested resolutions we've already warned about (dedupe: warn once each). */
const warnedFinerSlices = new Set<number>();

/** Inject a backend factory (tests). Pass null to restore the default. */
export function setBackendFactory(fn: BackendFactory | null): void {
  factory = fn;
}

function defaultFactory(slices: number): RenderBackend | null {
  if (typeof document === 'undefined') return null;
  const canvas = document.createElement('canvas');
  canvas.setAttribute('data-fontuccine', 'webgl-shared');
  canvas.setAttribute('aria-hidden', 'true');
  Object.assign(canvas.style, {
    position: 'fixed',
    inset: '0',
    width: '100%',
    height: '100%',
    pointerEvents: 'none',
    zIndex: '2147483646',
  } as CSSStyleDeclaration);
  document.body?.appendChild(canvas);
  const b = new WebGL2Backend(canvas, slices);
  return b.supported ? b : null;
}

/**
 * Acquire the shared backend (creating it once). `slices` is the caller's grid
 * resolution; the shared grid is sized to the MAX requested so a coarser
 * instance is always exact and a finer one never under-samples a stretch bend.
 * Returns null when WebGL2 is unavailable (engine drops to the SVG tier).
 */
export function acquireSharedBackend(slices = DEFAULT_GRID_SLICES): RenderBackend | null {
  if (slices > gridSlices && backend && !warnedFinerSlices.has(slices)) {
    // A finer instance arrived after the grid was built. The grid is page-global
    // and rebuilding it mid-session is out of scope for this phase, so the coarser
    // existing grid is kept. Warn once per distinct requested resolution so a page
    // with many instances doesn't flood the console. Coarser instances are fine.
    warnedFinerSlices.add(slices);
    // eslint-disable-next-line no-console
    console.warn(
      `[fontuccine/webgl] requested lutResolution ${slices} is finer than the active ` +
        `shared grid resolution ${gridSlices}. The WebGL tier's slice grid is page-global ` +
        `(shared across all instances), so the coarser existing grid of ${gridSlices} is used ` +
        `for this instance. Raise DEFAULT_GRID_SLICES if a finer grid is needed page-wide.`,
    );
  }
  if (!backend) {
    gridSlices = Math.max(gridSlices, slices);
    backend = (factory ?? defaultFactory)(gridSlices);
  }
  if (backend) refCount++;
  return backend;
}

/** Release one reference; destroys the backend when the last instance leaves. */
export function releaseSharedBackend(): void {
  if (!backend) return;
  refCount = Math.max(0, refCount - 1);
  if (refCount === 0) {
    backend.destroy();
    backend = null;
    gridSlices = DEFAULT_GRID_SLICES;
    warnedFinerSlices.clear();
  }
}

/** Test hook: force-reset the singleton (does NOT run destroy). */
export function __resetSharedBackend(): void {
  backend = null;
  refCount = 0;
  gridSlices = DEFAULT_GRID_SLICES;
  warnedFinerSlices.clear();
}

/**
 * webgl/lut-texture.ts — pack per-glyph cumulative-flex LUTs into ONE texture.
 *
 * RESEARCH §2 / obligation "zero rebinds mid-draw": every glyph's LUT lives on
 * its own ROW of a single (width × glyphCount) R32F texture; the glyph's row
 * index is an instanced attribute, so a whole run draws with the LUT texture
 * bound ONCE. The data is stretch-INDEPENDENT (see parity.ts), so this texture
 * is uploaded once at build and again only on context-restore — never per frame.
 *
 * Storage: R32F, single channel (the LUT is a scalar field 0→1). WebGL2 samples
 * R32F with `texelFetch` (NEAREST) in core — no float-linear extension needed —
 * and the vertex shader does its OWN two-tap `mix()`, so we never depend on
 * OES_texture_float_linear. All entries pass the FlexLUT contract (assertLUT).
 *
 * This module is PURE (no GL handle): it produces the Float32Array a caller
 * uploads via texImage2D(gl.R32F, ...). Tested for round-trip + contract.
 */
import type { FlexLUT } from '../core/types';
import { assertLUT } from '../core/lut';

export interface PackedLUTAtlas {
  /** Row-major R32F data, length = width * height. */
  data: Float32Array;
  /** Texels per row = N+1 (LUT entry count). Uniform across glyphs. */
  width: number;
  /** Rows = glyph count. */
  height: number;
}

/**
 * Pack cumulative-flex LUTs (one per glyph) into a single row-major buffer.
 * Every LUT MUST share the same length (uniform slice count) and satisfy the
 * FlexLUT contract. Row `g` holds glyph `g`'s LUT.
 */
export function packLUTAtlas(luts: FlexLUT[], validate = true): PackedLUTAtlas {
  if (luts.length === 0) {
    return { data: new Float32Array(0), width: 0, height: 0 };
  }
  const width = luts[0].length;
  if (width < 2) throw new RangeError(`packLUTAtlas: LUT width ${width} < 2`);
  const height = luts.length;
  const data = new Float32Array(width * height);
  for (let g = 0; g < height; g++) {
    const lut = luts[g];
    if (lut.length !== width) {
      throw new RangeError(
        `packLUTAtlas: LUT ${g} width ${lut.length} ≠ ${width} (slice count must be uniform)`,
      );
    }
    if (validate) assertLUT(lut);
    data.set(lut, g * width);
  }
  return { data, width, height };
}

/** Read back one glyph's LUT row (round-trip / test helper). */
export function unpackLUTRow(atlas: PackedLUTAtlas, glyphIndex: number): Float32Array {
  const { data, width, height } = atlas;
  if (glyphIndex < 0 || glyphIndex >= height) {
    throw new RangeError(`unpackLUTRow: row ${glyphIndex} out of range [0,${height})`);
  }
  return data.slice(glyphIndex * width, (glyphIndex + 1) * width);
}

/** Texel V-coordinate (row center) for a glyph's LUT row — matches texelFetch. */
export function lutRowCoord(glyphIndex: number, height: number): number {
  return height > 0 ? (glyphIndex + 0.5) / height : 0.5;
}

/**
 * webgl/msdf/atlas.ts — the shared MSDF glyph atlas: a fixed grid of uniform
 * cells with LRU eviction (RESEARCH §5.4 — GPU memory on mobile). PURE slot
 * bookkeeping + UV math; it holds NO GL handle, so LRU behaviour and packing are
 * Node-testable. The renderer owns the actual texture and flushes `dirtyCells`.
 *
 * Uniform grid cells (sized from a DPR-aware raster size) trade a little texel
 * waste for O(1) allocation, O(1) eviction, and a stable UV per slot — exactly
 * the discipline "one shared canvas/context, atlas LRU eviction, DPR-aware
 * sizing". A DPR change recomputes the cell size ⇒ the atlas is rebuilt and
 * glyphs re-rastered lazily (obligation 6).
 */

export interface AtlasCellUV {
  /** Slot index [0, capacity). */
  slot: number;
  /** Atlas UV rect (0..1) for the glyph's raster sub-region within its cell. */
  u0: number;
  v0: number;
  u1: number;
  v1: number;
}

export interface AtlasEntry extends AtlasCellUV {
  key: string;
  /** True the frame it was (re)assigned a slot — the renderer must upload it. */
  isNew: boolean;
}

export interface MsdfAtlasOptions {
  /** Atlas texture size in texels (square). Default 1024. */
  size?: number;
  /** Uniform cell size in texels (raster + padding fits inside). Default 64. */
  cellSize?: number;
  /** Device pixel ratio this atlas was sized for (for lazy re-raster on change). */
  dpr?: number;
}

export interface DirtyCell {
  slot: number;
  /** Texel origin of the cell in the atlas. */
  x: number;
  y: number;
  key: string;
}

export class MsdfAtlas {
  readonly size: number;
  readonly cellSize: number;
  readonly cols: number;
  readonly capacity: number;
  dpr: number;

  private readonly byKey = new Map<string, AtlasEntry>();
  /** slot → key (null = free). */
  private readonly slotKey: Array<string | null>;
  /** LRU order: keys, most-recently-used last. */
  private readonly lru: string[] = [];
  private readonly dirty: DirtyCell[] = [];

  constructor(opts: MsdfAtlasOptions = {}) {
    this.size = opts.size ?? 1024;
    this.cellSize = opts.cellSize ?? 64;
    this.dpr = opts.dpr ?? 1;
    this.cols = Math.max(1, Math.floor(this.size / this.cellSize));
    this.capacity = this.cols * this.cols;
    this.slotKey = new Array(this.capacity).fill(null);
  }

  /** Texel origin (x,y) of a slot's cell. */
  cellOrigin(slot: number): { x: number; y: number } {
    const c = slot % this.cols;
    const r = Math.floor(slot / this.cols);
    return { x: c * this.cellSize, y: r * this.cellSize };
  }

  private touch(key: string): void {
    const i = this.lru.indexOf(key);
    if (i >= 0) this.lru.splice(i, 1);
    this.lru.push(key);
  }

  /**
   * Get (or assign) a slot for `key`. `rasterW/H` are the glyph raster size in
   * texels (≤ cellSize); they set the UV sub-rect. Marks the entry `isNew` and
   * queues a dirty upload when a (re)assignment happens. Touches LRU.
   */
  acquire(key: string, rasterW: number, rasterH: number): AtlasEntry {
    const existing = this.byKey.get(key);
    if (existing) {
      this.touch(key);
      existing.isNew = false;
      return existing;
    }

    let slot = this.slotKey.indexOf(null);
    if (slot < 0) {
      // Evict least-recently-used.
      const victim = this.lru.shift();
      if (victim === undefined) throw new Error('MsdfAtlas: no slot and no LRU victim');
      const v = this.byKey.get(victim)!;
      slot = v.slot;
      this.byKey.delete(victim);
      this.slotKey[slot] = null;
    }

    const { x, y } = this.cellOrigin(slot);
    const w = Math.min(rasterW, this.cellSize);
    const h = Math.min(rasterH, this.cellSize);
    const entry: AtlasEntry = {
      key,
      slot,
      isNew: true,
      u0: x / this.size,
      v0: y / this.size,
      u1: (x + w) / this.size,
      v1: (y + h) / this.size,
    };
    this.slotKey[slot] = key;
    this.byKey.set(key, entry);
    this.touch(key);
    this.dirty.push({ slot, x, y, key });
    return entry;
  }

  /** Entries queued for GPU upload since the last flush. */
  takeDirty(): DirtyCell[] {
    const d = this.dirty.slice();
    this.dirty.length = 0;
    return d;
  }

  has(key: string): boolean {
    return this.byKey.has(key);
  }

  get count(): number {
    return this.byKey.size;
  }

  /** Full reset — used on DPR change / context loss (renderer re-rasterizes). */
  clear(): void {
    this.byKey.clear();
    this.slotKey.fill(null);
    this.lru.length = 0;
    this.dirty.length = 0;
  }
}

/**
 * webgl/msdf/client.ts — main-thread MSDF generation client.
 *
 * Mirrors the analysis-core `AnalysisClient` (src/worker/client.ts): spawns the
 * MSDF worker (or a caller-injected one), matches responses by id, LRU-caches
 * generated bitmaps keyed by (glyphId, fontSize, pxRange, dpr), and falls back
 * to a synchronous INLINE call when no Worker is available (SSR / tests). MSDF
 * for a glyph at a raster size is static, so cache hits are always valid; a DPR
 * change changes the key, which drives the lazy re-raster (obligation 6).
 */
import type { PathCommand } from '../../core/types';
import type { MSDFOptions, MSDFBitmap } from './generator';
import type { MsdfRequest, MsdfResponse } from './worker';
import { handleMsdfRequest } from './worker';

export interface MsdfClientOptions {
  workerFactory?: () => Worker;
  inline?: boolean;
  /** Max cached bitmaps (LRU). Default 512. */
  cacheSize?: number;
}

export interface MsdfGlyphInput {
  glyphId: string;
  commands: PathCommand[];
  options: MSDFOptions;
  /** Device pixel ratio (part of the cache key so DPR changes re-raster). */
  dpr?: number;
}

interface Pending {
  resolve: (b: MSDFBitmap) => void;
  reject: (e: unknown) => void;
}

function keyOf(input: MsdfGlyphInput): string {
  const o = input.options;
  return `${input.glyphId}|${o.fontSize}|${o.pxRange ?? 4}|${o.unitsPerEm ?? 1000}|${input.dpr ?? 1}`;
}

export class MsdfClient {
  private worker: Worker | null = null;
  private readonly pending = new Map<number, Pending>();
  private readonly cache = new Map<string, MSDFBitmap>();
  private readonly cacheSize: number;
  private nextId = 1;
  private inline: boolean;
  private readonly opts: MsdfClientOptions;

  constructor(opts: MsdfClientOptions = {}) {
    this.opts = opts;
    this.cacheSize = opts.cacheSize ?? 512;
    const canSpawn = !!opts.workerFactory || (typeof Worker !== 'undefined' && !opts.inline);
    this.inline = !canSpawn || !!opts.inline;
  }

  private ensureWorker(): Worker | null {
    if (this.inline) return null;
    if (this.worker) return this.worker;
    try {
      this.worker = this.opts.workerFactory
        ? this.opts.workerFactory()
        : new Worker(new URL('./worker.ts', import.meta.url), { type: 'module' });
      this.worker.onmessage = (ev: MessageEvent) => {
        const res = ev.data as MsdfResponse;
        const p = this.pending.get(res.id);
        if (p) {
          this.pending.delete(res.id);
          p.resolve(res.bitmap);
        }
      };
      this.worker.onerror = (err: unknown) => {
        for (const [, p] of this.pending) p.reject(err);
        this.pending.clear();
      };
    } catch {
      this.inline = true;
      this.worker = null;
    }
    return this.worker;
  }

  private cacheGet(key: string): MSDFBitmap | undefined {
    const v = this.cache.get(key);
    if (v) {
      this.cache.delete(key);
      this.cache.set(key, v);
    }
    return v;
  }

  private cacheSet(key: string, v: MSDFBitmap): void {
    this.cache.set(key, v);
    while (this.cache.size > this.cacheSize) {
      const oldest = this.cache.keys().next().value as string | undefined;
      if (oldest === undefined) break;
      this.cache.delete(oldest);
    }
  }

  /** Synchronously return a cached bitmap, or undefined if not yet generated. */
  peek(input: MsdfGlyphInput): MSDFBitmap | undefined {
    return this.cache.get(keyOf(input));
  }

  /** Generate (or fetch cached) MSDF for a glyph at a raster size. */
  generate(input: MsdfGlyphInput): Promise<MSDFBitmap> {
    const key = keyOf(input);
    const cached = this.cacheGet(key);
    if (cached) return Promise.resolve(cached);

    const id = this.nextId++;
    const req: MsdfRequest = {
      id,
      glyphId: input.glyphId,
      commands: input.commands,
      options: input.options,
    };

    const worker = this.ensureWorker();
    if (!worker) {
      const res = handleMsdfRequest(req);
      this.cacheSet(key, res.bitmap);
      return Promise.resolve(res.bitmap);
    }

    return new Promise<MSDFBitmap>((resolve, reject) => {
      this.pending.set(id, {
        resolve: (b) => {
          this.cacheSet(key, b);
          resolve(b);
        },
        reject,
      });
      worker.postMessage(req);
    });
  }

  get cacheCount(): number {
    return this.cache.size;
  }

  clearCache(): void {
    this.cache.clear();
  }

  destroy(): void {
    if (this.worker) {
      this.worker.terminate();
      this.worker = null;
    }
    this.pending.clear();
    this.cache.clear();
  }
}

/**
 * webgl/msdf/generator.ts — runtime MULTI-CHANNEL signed distance field builder
 * for ARBITRARY outline fonts (troika-class), the Tier-1 analog of the static
 * flex analysis. Runs OFF the main thread (worker.ts) and NEVER per frame
 * (CLAUDE.md rule 1); results are cached + LRU-evicted by the atlas.
 *
 * ── Why MSDF (3-channel), not single-channel SDF ──
 * A single-channel SDF stores distance-to-nearest-edge, so a sharp corner
 * becomes the max/min of two edges → a rounded arc (RESEARCH §2: "single-channel
 * SDF rounds corners — unacceptable"). MSDF (Chlumsky/msdfgen) colours edges so
 * that at a corner the two edges live in DIFFERENT channels; the per-pixel
 * MEDIAN of the three channels reconstructs the corner as the intersection of
 * the two edge half-planes → sharp at any magnification. The fragment shader
 * takes `median(r,g,b)` exactly (refs/examples/04).
 *
 * ── Generation approach chosen: pure-TS msdfgen-style field ──
 * JUSTIFICATION (state-and-justify, global 3D rule): the workload is per-pixel
 * nearest-edge distance over a handful of edges — pure scalar math, no GPU, no
 * native/wasm binary. A wasm-msdfgen dependency would add a binary asset + build
 * step (contra "no pre-baked assets, any font"); a GPU jump-flood needs a live
 * GL context in the worker and multi-channel JFA is more complex than the exact
 * analytic distance. A self-contained TS generator is any-font, worker-safe,
 * dependency-free, and — crucially — Node-TESTABLE without a GPU (field range,
 * median sign vs winding, corner preservation vs single-channel). It reuses the
 * FROZEN core geometry (`commandsToContours`, `evalSegment`) and winding
 * (`WindingIndex`) — no forking.
 */
import type { PathCommand, BBox } from '../../core/types';
import type { Segment } from '../../core/geometry/segments';
import { commandsToContours, evalSegment } from '../../core/geometry/segments';
import { WindingIndex } from '../../core/winding';

// Channel bit masks. Secondary colours each carry exactly two channels so that
// consecutive runs around a corner share exactly one channel.
const R = 1, G = 2, B = 4, WHITE = 7;
const YELLOW = R | G; // 3
const CYAN = G | B; // 6
const MAGENTA = R | B; // 5
const PALETTE = [YELLOW, CYAN, MAGENTA];

export interface ColoredEdge {
  seg: Segment;
  mask: number; // channel bitmask
}

export interface MSDFOptions {
  /** Glyph bbox in font units (from analysis / opentype). */
  bbox: BBox;
  /** Pixels per em (raster size). Cell is sized from bbox·scale + padding. */
  fontSize: number;
  /** Font units per em (opentype getPath size). Default 1000. */
  unitsPerEm?: number;
  /** Distance range in TEXELS (msdfgen `-pxrange`). Default 4. */
  pxRange?: number;
  /** Padding texels around the glyph (≥ pxRange/2 so the field isn't clipped). Default = ceil(pxRange/2)+1. */
  padding?: number;
  /** Corner angle threshold in degrees; junctions sharper than this get coloured. Default 3. */
  cornerThresholdDeg?: number;
  /** Single-channel mode (all edges WHITE) — for the corner-rounding comparison test. */
  singleChannel?: boolean;
}

export interface MSDFBitmap {
  /** RGBA8, row-major, top-left origin. length = width*height*4 (A=255). */
  data: Uint8ClampedArray;
  width: number;
  height: number;
  /** Distance range in texels (goes to the shader as u_pxRange). */
  pxRange: number;
  /** Padding texels used (for UV rect derivation). */
  padding: number;
  /** Scale font-units → texels. */
  scale: number;
  /** Glyph bbox echoed back. */
  bbox: BBox;
}

// ── edge coloring ────────────────────────────────────────────────────────────

function unit(x: number, y: number): [number, number] {
  const l = Math.hypot(x, y);
  return l > 1e-12 ? [x / l, y / l] : [0, 0];
}

/** Is the junction between edge `a` (its end) and `b` (its start) a corner? */
function isCorner(a: Segment, b: Segment, cosThreshold: number): boolean {
  const ta = evalSegment(a, 1);
  const tb = evalSegment(b, 0);
  const [ax, ay] = unit(ta.tx, ta.ty);
  const [bx, by] = unit(tb.tx, tb.ty);
  const dot = ax * bx + ay * by;
  const cross = ax * by - ay * bx;
  // corner if direction turns more than the threshold (either sign)
  return dot < cosThreshold || Math.abs(cross) > Math.sin(Math.acos(Math.max(-1, Math.min(1, cosThreshold))));
}

/**
 * Colour a glyph's edges (msdfgen "simple" scheme): split each contour into
 * runs at its corners and cycle run colours through the two-channel palette so
 * adjacent runs share exactly one channel. Smooth loops (no corners) stay WHITE.
 */
export function colorEdges(
  commands: PathCommand[],
  cornerThresholdDeg = 3,
  singleChannel = false,
): ColoredEdge[] {
  const contours = commandsToContours(commands);
  const cosT = Math.cos((cornerThresholdDeg * Math.PI) / 180);
  const out: ColoredEdge[] = [];

  for (const segs of contours) {
    const n = segs.length;
    if (n === 0) continue;
    if (singleChannel) {
      for (const seg of segs) out.push({ seg, mask: WHITE });
      continue;
    }

    // Corner flags at the START of each edge (junction from previous edge).
    const cornerAt: boolean[] = new Array(n);
    for (let i = 0; i < n; i++) {
      const prev = segs[(i - 1 + n) % n];
      cornerAt[i] = isCorner(prev, segs[i], cosT);
    }
    const cornerCount = cornerAt.filter(Boolean).length;

    if (cornerCount === 0) {
      // Fully smooth contour (e.g. 'O'): single-channel-equivalent is correct.
      for (const seg of segs) out.push({ seg, mask: WHITE });
      continue;
    }

    // Rotate so index 0 begins a run (starts at a corner) for stable coloring.
    let start = 0;
    for (let i = 0; i < n; i++) if (cornerAt[i]) { start = i; break; }

    let run = 0;
    for (let s = 0; s < n; s++) {
      const i = (start + s) % n;
      if (s > 0 && cornerAt[i]) run++;
      out.push({ seg: segs[i], mask: PALETTE[run % PALETTE.length] });
    }
  }
  return out;
}

// ── per-edge signed distance ─────────────────────────────────────────────────

/** Nearest parameter t∈[0,1] on a segment to point (px,py): coarse scan + refine. */
function nearestT(seg: Segment, px: number, py: number): number {
  if (seg.type === 'L') {
    const dx = seg.p1.x - seg.p0.x;
    const dy = seg.p1.y - seg.p0.y;
    const len2 = dx * dx + dy * dy;
    if (len2 < 1e-18) return 0;
    let t = ((px - seg.p0.x) * dx + (py - seg.p0.y) * dy) / len2;
    return t < 0 ? 0 : t > 1 ? 1 : t;
  }
  // Curves: coarse scan then parabolic/bisection refine on squared distance.
  const K = 24;
  let bestT = 0;
  let bestD = Infinity;
  for (let i = 0; i <= K; i++) {
    const t = i / K;
    const p = evalSegment(seg, t);
    const d = (p.x - px) ** 2 + (p.y - py) ** 2;
    if (d < bestD) { bestD = d; bestT = t; }
  }
  // refine with a few golden-section-ish bisections around bestT
  let lo = Math.max(0, bestT - 1 / K);
  let hi = Math.min(1, bestT + 1 / K);
  for (let it = 0; it < 20; it++) {
    const m1 = lo + (hi - lo) / 3;
    const m2 = hi - (hi - lo) / 3;
    const p1 = evalSegment(seg, m1);
    const p2 = evalSegment(seg, m2);
    const d1 = (p1.x - px) ** 2 + (p1.y - py) ** 2;
    const d2 = (p2.x - px) ** 2 + (p2.y - py) ** 2;
    if (d1 < d2) hi = m2; else lo = m1;
  }
  return (lo + hi) / 2;
}

interface EdgeDist {
  /** |true distance| to the segment (for nearest-edge selection). */
  abs: number;
  /** signed PERPENDICULAR (pseudo) distance to the edge's tangent line at the nearest point. */
  pseudo: number;
  /** orthogonality (1 = perpendicular hit, →0 = grazing endpoint) — tie-break. */
  ortho: number;
}

function edgeDistance(seg: Segment, px: number, py: number): EdgeDist {
  const t = nearestT(seg, px, py);
  const e = evalSegment(seg, t);
  const dpx = px - e.x;
  const dpy = py - e.y;
  const abs = Math.hypot(dpx, dpy);
  const [ux, uy] = unit(e.tx, e.ty);
  // signed perpendicular distance to the tangent line (extends past endpoints
  // → linear field that reconstructs corners when channels are combined).
  const pseudo = ux * dpy - uy * dpx;
  // orthogonality: how perpendicular the hit is (1 at interior, small at grazing).
  const ortho = abs > 1e-9 ? Math.abs((ux * dpy - uy * dpx) / abs) : 1;
  return { abs, pseudo, ortho };
}

/** Signed pseudo-distance for one channel = winner (min |true dist|) among its edges. */
function channelDistance(edges: ColoredEdge[], channelBit: number, px: number, py: number): number {
  let best: EdgeDist | null = null;
  for (const ce of edges) {
    if ((ce.mask & channelBit) === 0) continue;
    const d = edgeDistance(ce.seg, px, py);
    if (
      best === null ||
      d.abs < best.abs - 1e-6 ||
      (Math.abs(d.abs - best.abs) <= 1e-6 && d.ortho > best.ortho)
    ) {
      best = d;
    }
  }
  return best ? best.pseudo : 0;
}

/**
 * TRUE (clamped Euclidean) unsigned min-distance to any edge — the field a
 * SINGLE-channel SDF stores. At a convex corner this equals the distance to the
 * VERTEX, so the iso-contour rounds off. Used only for `singleChannel` mode as
 * the honest rounding baseline the MSDF path is compared against.
 */
function minTrueDistance(edges: ColoredEdge[], px: number, py: number): number {
  let m = Infinity;
  for (const ce of edges) {
    const d = edgeDistance(ce.seg, px, py).abs;
    if (d < m) m = d;
  }
  return Number.isFinite(m) ? m : 0;
}

// ── bitmap generation ────────────────────────────────────────────────────────

export function generateMSDF(commands: PathCommand[], options: MSDFOptions): MSDFBitmap {
  const upm = options.unitsPerEm ?? 1000;
  const pxRange = options.pxRange ?? 4;
  const scale = options.fontSize / upm;
  const pad = options.padding ?? Math.ceil(pxRange / 2) + 1;
  const { bbox } = options;

  const glyphW = Math.max(1e-3, bbox.maxX - bbox.minX);
  const glyphH = Math.max(1e-3, bbox.maxY - bbox.minY);
  const width = Math.max(1, Math.ceil(glyphW * scale) + 2 * pad);
  const height = Math.max(1, Math.ceil(glyphH * scale) + 2 * pad);

  const edges = colorEdges(commands, options.cornerThresholdDeg ?? 3, options.singleChannel ?? false);
  const rangeGlyph = pxRange / scale; // distance range in font units

  // Winding index resolves the GLOBAL sign (inside → positive) so the per-edge
  // cross-sign convention (which depends on contour orientation) is corrected
  // uniformly across all three channels — this does NOT flatten the per-channel
  // magnitudes that reconstruct corners.
  const contours = commandsToContours(commands);
  const rings = contours.map((segs) => segs.map((s) => [s.p0.x, s.p0.y] as [number, number]));
  const windingIdx = new WindingIndex(rings);

  const data = new Uint8ClampedArray(width * height * 4);

  // pixel (i,j) → glyph coords. Image is y-down; glyph y is up, so invert row.
  const toGlyphX = (i: number): number => bbox.minX + (i + 0.5 - pad) / scale;
  const toGlyphY = (j: number): number => bbox.maxY - (j + 0.5 - pad) / scale;

  // Determine global orientation sign by agreement with winding over a sample.
  let agree = 0;
  const sampleStep = Math.max(1, Math.floor(Math.min(width, height) / 8));
  for (let j = 0; j < height; j += sampleStep) {
    for (let i = 0; i < width; i += sampleStep) {
      const gx = toGlyphX(i);
      const gy = toGlyphY(j);
      const r = channelDistance(edges, R, gx, gy);
      const g = channelDistance(edges, G, gx, gy);
      const b = channelDistance(edges, B, gx, gy);
      const med = median3(r, g, b);
      const inside = windingIdx.inside(gx, gy);
      // want sign(med)>0 when inside
      if ((med > 0) === inside) agree++;
      else agree--;
    }
  }
  const orient = agree >= 0 ? 1 : -1;

  const single = options.singleChannel ?? false;

  for (let j = 0; j < height; j++) {
    for (let i = 0; i < width; i++) {
      const gx = toGlyphX(i);
      const gy = toGlyphY(j);
      const o = (j * width + i) * 4;
      if (single) {
        // Honest single-channel SDF: sign from winding, magnitude = TRUE min
        // distance (rounds at corners). All channels equal ⇒ median = itself.
        const signed = (windingIdx.inside(gx, gy) ? 1 : -1) * minTrueDistance(edges, gx, gy);
        const v = encode(signed, rangeGlyph);
        data[o + 0] = v;
        data[o + 1] = v;
        data[o + 2] = v;
      } else {
        const r = orient * channelDistance(edges, R, gx, gy);
        const g = orient * channelDistance(edges, G, gx, gy);
        const b = orient * channelDistance(edges, B, gx, gy);
        data[o + 0] = encode(r, rangeGlyph);
        data[o + 1] = encode(g, rangeGlyph);
        data[o + 2] = encode(b, rangeGlyph);
      }
      data[o + 3] = 255;
    }
  }

  return { data, width, height, pxRange, padding: pad, scale, bbox };
}

/** msdfgen median of three channels (matches the fragment shader). */
export function median3(a: number, b: number, c: number): number {
  return Math.max(Math.min(a, b), Math.min(Math.max(a, b), c));
}

/** signed distance (font units) → [0,255], 0.5·255 at the edge (msdfgen encoding). */
function encode(signed: number, rangeGlyph: number): number {
  const v = 0.5 + signed / rangeGlyph;
  return Math.round(Math.max(0, Math.min(1, v)) * 255);
}

/**
 * webgl/msdf/worker.ts — off-main-thread MSDF rasterization entry.
 *
 * CLAUDE.md rule 1: atlas generation is the Tier-1 analog of static analysis and
 * MUST run in a worker, never on the main thread, never per frame. This is a
 * thin transport wrapper around the pure `generateMSDF`; the client (client.ts)
 * matches responses by id and falls back to an inline synchronous call when no
 * Worker exists (SSR / tests). The heavy pixel loop is CPU-only, so it runs the
 * same code in either context. Where `OffscreenCanvas` is available a future
 * revision can move the raster to a GPU jump-flood behind this same message
 * contract — the client does not care.
 */
import type { PathCommand } from '../../core/types';
import type { MSDFOptions, MSDFBitmap } from './generator';
import { generateMSDF } from './generator';

export interface MsdfRequest {
  id: number;
  glyphId: string;
  commands: PathCommand[];
  options: MSDFOptions;
}

export interface MsdfResponse {
  id: number;
  glyphId: string;
  bitmap: MSDFBitmap;
}

/** Run one request (shared by worker + inline fallback). */
export function handleMsdfRequest(req: MsdfRequest): MsdfResponse {
  const bitmap = generateMSDF(req.commands, req.options);
  return { id: req.id, glyphId: req.glyphId, bitmap };
}

// Wire up as a module worker when running in a Worker global scope. Guarded so
// importing this module on the main thread (for `handleMsdfRequest`) is inert.
declare const self: {
  onmessage?: (ev: { data: MsdfRequest }) => void;
  postMessage?: (msg: MsdfResponse, transfer?: unknown[]) => void;
} | undefined;

if (
  typeof self !== 'undefined' &&
  typeof (self as { postMessage?: unknown }).postMessage === 'function' &&
  typeof (globalThis as { window?: unknown }).window === 'undefined'
) {
  self.onmessage = (ev: { data: MsdfRequest }) => {
    const res = handleMsdfRequest(ev.data);
    // Transfer the pixel buffer to avoid a copy.
    self.postMessage?.(res, [res.bitmap.data.buffer]);
  };
}

/**
 * webgl/parity.ts — the JS MIRROR of the Tier-1 vertex shader's LUT remap.
 *
 * This is the load-bearing cross-tier parity contract (CLAUDE.md rule 3). The
 * GPU never runs in Node, so the ONLY way to prove the WebGL tier reproduces the
 * SVG tier's stretched geometry is to mirror the exact arithmetic the vertex
 * shader performs and diff it against `buildRemap().remap` (which the SVG tier's
 * on-curve positions equal). `test/webgl-parity.test.ts` does exactly that on
 * real glyphs at 1×/2.5×/4.5×.
 *
 * ── Design note (STRETCH-INDEPENDENT LUT) — flagged decision, see report ──
 * refs/examples/03 bakes the FULLY-normalized remap (`toNormalizedLUT()`) into
 * the texture and multiplies by `stretch` in the shader. That baked LUT is
 * stretch-DEPENDENT (its texels move as the ratio changes), so shipping 03
 * verbatim forces a per-glyph LUT rebuild + re-upload EVERY frame — which
 * violates this tier's perf obligation ("no buffer re-uploads during
 * steady-state animation; frame JS ≤ 2ms"; RESEARCH §2 "keep per-frame JS
 * thin").
 *
 * We keep the locked design ("vertex remap through a cumulative LUT texture;
 * UVs original; MSDF median+fwidth in the fragment") but store the
 * stretch-INDEPENDENT normalized cumulative FLEX  C(u) = cumsum(flex)/sum(flex)
 * in the texture and apply the ratio via the `u_stretch` uniform:
 *
 *     remapped(u) = u + (stretch - 1) · C(u)                    // shader
 *     pos.x       = inkLeft + W · remapped(u)
 *     inkLeft     = u_origin + stretch · glyphOrigin_i          // static attr
 *
 * This is ALGEBRAICALLY identical to the core's `min + W·(u + (stretch-1)·C)`
 * remap, so the LUT texture, geometry buffers and per-glyph attributes are ALL
 * static — only the `u_stretch` / `u_origin` scalars change per frame.
 *
 * Exactness envelope (measured, test/webgl-parity):
 *   • stretch ≥ 1  → exact vs SVG tier (float-noise ~1e-12 font units).
 *   • stretch < 1  → exact WHILE the core compression guard is inactive; once
 *     the guard clamps a rigid slice (strong compression) the linear-in-stretch
 *     form cannot reproduce the guard's nonlinear redistribution and the GPU
 *     tier diverges from the SVG tier. Heavy compression belongs on the SVG
 *     (vector-fidelity) tier. `C` still satisfies the FlexLUT contract shape
 *     (Float32 N+1, 0→1, monotonic) so nothing about the cross-tier contract is
 *     forked — this is a different, contract-shaped texture derived from the
 *     SAME frozen flex profile.
 */
import type { FlexLUT } from '../core/types';

/**
 * Normalized cumulative flex  C(u) = cumsum(flex)/sum(flex)  as an (N+1) LUT.
 * Mirrors the core's own per-slice distribution (`lut.ts`: e[i] = E·flex[i]/ΣF
 * ⇒ C[i+1]-C[i] = flex[i]/ΣF), so it is exactly the flex portion of the remap.
 * Fully-rigid glyphs (ΣF≈0) degrade to the uniform ramp C[i]=i/N (matching the
 * core's uniform-scaling fallback). Endpoints are pinned 0/1 for assertLUT.
 */
export function buildFlexCumulative(flex: Float32Array | number[]): FlexLUT {
  const N = flex.length;
  const C = new Float32Array(N + 1);
  let sum = 0;
  for (let i = 0; i < N; i++) sum += flex[i];
  if (sum < 1e-9) {
    for (let i = 0; i <= N; i++) C[i] = i / N; // uniform fallback
  } else {
    let acc = 0;
    for (let i = 0; i < N; i++) {
      acc += flex[i] / sum;
      C[i + 1] = acc;
    }
  }
  C[0] = 0;
  C[N] = 1; // pin against float drift (assertLUT-exact)
  return C;
}

/**
 * Sample a normalized LUT with piecewise-linear interpolation — the CPU
 * equivalent of the vertex shader's two-tap `mix(lut[i], lut[i+1], frac)` on an
 * (N+1)-wide texture. u ∈ [0,1] addresses boundary 0..N.
 */
export function sampleNormalizedLUT(lut: FlexLUT, u: number): number {
  const N = lut.length - 1;
  if (N <= 0) return 0;
  if (u <= 0) return lut[0];
  if (u >= 1) return lut[N];
  const f = u * N;
  const i = Math.min(N - 1, Math.floor(f));
  const t = f - i;
  return lut[i] * (1 - t) + lut[i + 1] * t;
}

/**
 * CPU mirror of the vertex shader's horizontal position for an ORIGINAL glyph
 * x-coordinate, through the static cumulative-flex LUT path the GPU uses.
 *
 * @param cumFlex  normalized cumulative flex LUT (buildFlexCumulative)
 * @param x        original glyph x-coordinate (font units)
 * @param min      ink bounds.min (font units)
 * @param max      ink bounds.max (font units)
 * @param inkLeft  glyph frame left edge in run space (== layoutRun inkLeft = penX + min)
 * @param stretch  current stretch ratio
 */
export function gpuRemapX(
  cumFlex: FlexLUT,
  x: number,
  min: number,
  max: number,
  inkLeft: number,
  stretch: number,
): number {
  const W = max - min;
  if (W <= 0) return inkLeft;
  const u = (x - min) / W;
  const C = sampleNormalizedLUT(cumFlex, u);
  return inkLeft + W * (u + (stretch - 1) * C);
}

/**
 * Static per-glyph horizontal origin factor so the shader can compute
 * `inkLeft = u_origin + stretch · glyphOrigin` with NO per-frame attribute
 * upload. Derived to match `layoutRun` exactly:
 *   inkLeft_i = origin + stretch·(prefixAdvance_i + min_i)
 * where prefixAdvance_i = kernBefore_i + Σ_{j<i}(advanceWidth_j + kernBefore_j).
 */
export function glyphOriginFactor(prefixAdvance: number, min: number): number {
  return prefixAdvance + min;
}

/**
 * webgl/renderer.ts — Fontuccine Tier 1 (WebGL2 + runtime MSDF atlas) renderer.
 *
 * PRIMARY tier (RESEARCH §3). Consumes the SAME frozen surfaces as the SVG tier
 * — `layoutRun` prefix metrics, the flex profiles, the shared overlay, the
 * shared ticker + StretchController — so GPU and SVG geometry match within
 * tolerance (test/webgl-parity). Interface mirrors createSvgRenderer EXACTLY
 * (attach/resize/draw/destroy + element + overlay) so the engine swaps tiers
 * behind one shape.
 *
 * Discipline (CLAUDE.md rules 1,4,6; obligations):
 *  - ONE shared canvas/context for all instances (gl/shared.ts); this renderer
 *    draws into its own screen region via scissor — never a context per element.
 *  - Static-per-glyph work (flex→cumulative-flex LUT, MSDF raster, instance
 *    attributes) is built ONCE off the main thread (MSDF in a worker) and NEVER
 *    per frame. Per frame only `u_stretch`/`u_origin` (+ effect scalars) change:
 *    zero buffer re-uploads in steady state.
 *  - Writes happen only in the RENDER phase; the only DOM read (host rect) is a
 *    cached READ-phase measure, invalidated by ResizeObserver + scroll.
 *  - Reduced motion / print ⇒ ONE static draw, NO per-frame callback.
 *  - Offscreen ⇒ IntersectionObserver deactivates the instance (RESEARCH §2).
 *  - Context loss ⇒ atlas + LUT + geometry buffers fully restored (obligation 1).
 *
 * The a11y/overlay reconciliation (flagged): "one shared canvas for all
 * instances" and "mount the canvas as the overlay renderLayer" are mutually
 * exclusive for N>1 (a canvas node can live in one host only). The shared-canvas
 * architecture wins; each host gets a transparent, inert PROXY layer through
 * `createOverlay` so ALL the frozen a11y/wrap/containment/destroy behavior is
 * reused, while the pixels come from the shared canvas aligned by scissor.
 */
import type { LayoutGlyph } from '../core/kerning';
import { layoutRun } from '../core/kerning';
import type { Ticker } from '../interaction/ticker';
import { ticker as sharedTicker } from '../interaction/ticker';
import { prefersReducedMotion } from '../interaction/reduced-motion';
import { observeVisibility } from '../interaction/gating';
import type { VisibilityOptions } from '../interaction/gating';
import { createOverlay } from '../dom/overlay';
import type { Overlay, WrapMode } from '../dom/overlay';
import type { WebglGlyph, EffectsConfig, RGBAColor } from './types';
import { buildFlexCumulative } from './parity';
import { packLUTAtlas } from './lut-texture';
import { MsdfAtlas } from './msdf/atlas';
import { MsdfClient } from './msdf/client';
import type { MSDFBitmap } from './msdf/generator';
import type { RenderBackend, RunHandle, GlyphRunData } from './gl/device';
import { acquireSharedBackend, releaseSharedBackend, DEFAULT_GRID_SLICES } from './gl/shared';

const DEFAULT_ATLAS_SIZE = 1024;
const DEFAULT_CELL = 64;
const FLOATS_PER_INSTANCE = 9;

export interface StretchSource {
  readonly value: number;
  /** Optional velocity (for aberration ∝ velocity); 0 when absent. */
  readonly velocity?: number;
}

export interface WebglRendererOptions {
  host: HTMLElement;
  glyphs: WebglGlyph[];
  controller: StretchSource;
  text?: string;
  wrap?: WrapMode;
  maxStretchRatio?: number;
  restingStretch?: number;
  unitsPerEm?: number;
  /** Ink color (straight alpha, 0..1). Default opaque black. */
  color?: RGBAColor;
  effects?: EffectsConfig;
  /** MSDF raster size in px per em. Default 48. */
  fontSizeRaster?: number;
  /** MSDF distance range in texels. Default 4. */
  pxRange?: number;
  ticker?: Ticker;
  document?: Document;
  respectReducedMotion?: boolean;
  isReducedMotion?: () => boolean;
  /** Device pixel ratio source (default: window.devicePixelRatio or 1). */
  dpr?: number;
  /** Injected backend (tests). Omit to use the shared page-global backend. */
  backend?: RenderBackend;
  /** Injected MSDF client (tests / shared). Omit to create one. */
  msdfClient?: MsdfClient;
  /** Visibility gate factory (tests). */
  visibilityFactory?: VisibilityOptions['factory'];
}

export interface WebglRenderer {
  attach(): void;
  resize(): void;
  draw(now?: number): void;
  destroy(): void;
  /** True when WebGL2 is available; false ⇒ engine must drop to the SVG tier. */
  readonly supported: boolean;
  /** The shared render surface (canvas), or null when unsupported. */
  readonly element: HTMLCanvasElement | null;
  readonly overlay: Overlay;
}

interface GlyphStatic {
  originFactor: number; // font units (prefixAdvance + bounds.min)
  width: number; // font units (bounds.max - bounds.min)
  bounds: { min: number; max: number };
  yTop: number; // font units from run top
  height: number; // font units
  cumFlex: Float32Array; // normalized cumulative flex LUT
  glyphKey: string;
  bitmap?: MSDFBitmap;
  uv?: { origin: [number, number]; size: [number, number] };
}

export function createWebglRenderer(options: WebglRendererOptions): WebglRenderer {
  const {
    host,
    glyphs,
    controller,
    wrap = 'nowrap',
    maxStretchRatio = 4.5,
    restingStretch = 1,
    unitsPerEm = 1000,
    fontSizeRaster = 48,
    pxRange = 4,
  } = options;

  const ticker = options.ticker ?? sharedTicker;
  const doc = options.document ?? host.ownerDocument;
  if (!doc) throw new Error('createWebglRenderer: no document available');
  const respectRM = options.respectReducedMotion ?? true;
  const isRM = options.isReducedMotion ?? prefersReducedMotion;
  const color: RGBAColor = options.color ?? { r: 0, g: 0, b: 0, a: 1 };
  const effects = options.effects ?? {};
  const slices = glyphs[0]?.flex.length ?? DEFAULT_GRID_SLICES;

  // Acquire the shared backend (or the injected one). Null ⇒ unsupported.
  const backend = options.backend ?? acquireSharedBackend(slices);
  const usingShared = !options.backend;
  const supported = !!backend && backend.supported;

  const msdf = options.msdfClient ?? new MsdfClient();
  const ownsMsdf = !options.msdfClient;

  // Shared MSDF atlas (slot LRU). One per renderer instance's glyph set; the
  // backend's atlas texture is shared, cells are packed here.
  const atlas = new MsdfAtlas({ size: DEFAULT_ATLAS_SIZE, cellSize: DEFAULT_CELL, dpr: options.dpr ?? 1 });

  // --- proxy render layer (inert) so the frozen overlay machinery applies.
  const proxy = doc.createElement('div');
  proxy.setAttribute('data-fontuccine', 'webgl');
  const overlay = createOverlay({
    host,
    renderLayer: proxy,
    text: options.text,
    wrap,
    maxStretchRatio,
    document: doc,
  });

  // --- STATIC per-glyph layout + LUT (computed once; never per frame).
  const layoutGlyphs: LayoutGlyph[] = glyphs.map((g) => ({
    profile: g.flex,
    bounds: g.bounds,
    advanceWidth: g.advanceWidth,
    kernBefore: g.kernBefore,
  }));

  // prefixAdvance_i in font units (matches layoutRun's cursor derivation).
  let maxAscent = -Infinity;
  let minDescent = Infinity;
  for (const g of glyphs) {
    if (g.bbox.maxY > maxAscent) maxAscent = g.bbox.maxY;
    if (g.bbox.minY < minDescent) minDescent = g.bbox.minY;
  }
  if (!Number.isFinite(maxAscent)) {
    maxAscent = unitsPerEm;
    minDescent = 0;
  }

  const statics: GlyphStatic[] = [];
  let prefix = 0;
  for (let i = 0; i < glyphs.length; i++) {
    const g = glyphs[i];
    const kb = g.kernBefore ?? 0;
    prefix += kb; // prefixAdvance_i = kernBefore_i + Σ_{j<i}(adv_j + kern_j)
    statics.push({
      originFactor: prefix + g.bounds.min,
      width: g.bounds.max - g.bounds.min,
      bounds: { min: g.bounds.min, max: g.bounds.max },
      yTop: g.bbox.minY - minDescent,
      height: g.bbox.maxY - g.bbox.minY,
      cumFlex: buildFlexCumulative(g.flex),
      glyphKey: g.char ?? `g${i}`,
    });
    prefix += g.advanceWidth; // advance for the NEXT glyph's prefix
  }
  const runFontUnitsHeight = maxAscent - minDescent;

  // --- lifecycle state
  let attached = false;
  let ready = false;
  let visible = true;
  let lastStretch = Number.NaN;
  let rectDirty = true;
  let hostRect: { x: number; y: number; w: number; h: number } | null = null;
  let fontSizePx = fontSizeRaster; // css px/em; refined from the host in READ
  let run: RunHandle | null = null;
  const unsubs: Array<() => void> = [];
  let resizeObserver: ResizeObserver | null = null;
  let scrollHandler: (() => void) | null = null;
  let visibilityStop: (() => void) | null = null;
  let lostUnsub: (() => void) | null = null;
  let restoredUnsub: (() => void) | null = null;
  let destroyed = false;

  const dpr = (): number => options.dpr ?? (typeof window !== 'undefined' ? window.devicePixelRatio || 1 : 1);

  // --- lazy displacement-noise load (zero-cost until an enabled effect asks).
  let noiseLoaded = false;
  function loadNoiseIfNeeded(): void {
    if (noiseLoaded || destroyed) return;
    const disp = effects.displacement;
    if (!disp || !disp.texture || (disp.intensity ?? 0) <= 0) return;
    if (!backend || typeof backend.setNoise !== 'function') return;
    if (typeof Image === 'undefined') return; // SSR / headless: skip silently
    noiseLoaded = true; // guard against duplicate in-flight loads
    const img = new Image();
    img.crossOrigin = 'anonymous';
    img.onload = () => {
      if (destroyed || !backend) return;
      backend.setNoise?.(img);
      lastStretch = Number.NaN; // force a repaint now that warp is available
      ticker.wake();
    };
    img.onerror = () => {
      noiseLoaded = false; // allow a later retry; displacement stays disabled
    };
    img.src = disp.texture;
  }

  // --- assemble the packed LUT atlas (static; row per glyph).
  function buildLUTAtlas() {
    return packLUTAtlas(statics.map((s) => s.cumFlex));
  }

  // --- build/refresh the atlas cells + instance buffer, then upload the run.
  function assembleAndUpload(): void {
    if (!backend || destroyed) return;
    backend.ensureAtlas(DEFAULT_ATLAS_SIZE);
    atlas.clear(); // fresh slot assignment (also used on context restore)

    const instances = new Float32Array(statics.length * FLOATS_PER_INSTANCE);
    const emPx = fontSizePx / unitsPerEm; // font units → css px

    for (let i = 0; i < statics.length; i++) {
      const s = statics[i];
      const bmp = s.bitmap;
      if (!bmp) continue;
      const cell = atlas.acquire(s.glyphKey, bmp.width, bmp.height);
      if (cell.isNew) {
        const { x, y } = atlas.cellOrigin(cell.slot);
        backend.uploadAtlasCell(x, y, bmp);
      }
      // atlas UV rect for this glyph's INK region (box [0,1]² → ink texels).
      const { x: cx, y: cy } = atlas.cellOrigin(cell.slot);
      const S = DEFAULT_ATLAS_SIZE;
      const pad = bmp.padding;
      const uvOx = (cx + pad) / S;
      const uvOy = (cy + bmp.height - pad) / S; // box y=0 (bottom) → image bottom
      const uvSx = (bmp.width - 2 * pad) / S;
      const uvSy = -(bmp.height - 2 * pad) / S; // signed: box y=1 (top) → image top
      s.uv = { origin: [uvOx, uvOy], size: [uvSx, uvSy] };

      const o = i * FLOATS_PER_INSTANCE;
      instances[o + 0] = s.originFactor * emPx; // css px
      instances[o + 1] = s.width * emPx;
      instances[o + 2] = s.yTop * emPx;
      instances[o + 3] = s.height * emPx;
      instances[o + 4] = uvOx;
      instances[o + 5] = uvOy;
      instances[o + 6] = uvSx;
      instances[o + 7] = uvSy;
      instances[o + 8] = i; // lut row
    }

    const data: GlyphRunData = {
      instances,
      instanceCount: statics.length,
      lutAtlas: buildLUTAtlas(),
      slices,
    };
    if (!run) run = backend.createRun();
    run.upload(data);
  }

  // --- kick off MSDF generation for all glyphs (worker / inline). Static.
  function generateAtlas(): Promise<void> {
    const jobs = statics.map((s, i) => {
      const g = glyphs[i];
      return msdf
        .generate({
          glyphId: `${s.glyphKey}@${fontSizeRaster}`,
          commands: g.commands,
          options: { bbox: g.bbox, fontSize: fontSizeRaster, unitsPerEm, pxRange },
          dpr: options.dpr ?? 1,
        })
        .then((bmp) => {
          s.bitmap = bmp;
        });
    });
    return Promise.all(jobs).then(() => void 0);
  }

  function readPhase(): void {
    if (!rectDirty) return;
    rectDirty = false;
    overlay.measure();
    // Host screen rect in CSS px (single getBoundingClientRect).
    const r = host.getBoundingClientRect();
    hostRect = { x: r.left, y: r.top, w: r.width, h: r.height };
    // Track the host's rendered em size so glyph metrics scale with CSS.
    const view = doc.defaultView;
    if (view) {
      const fs = parseFloat(view.getComputedStyle(host).fontSize);
      if (Number.isFinite(fs) && fs > 0 && Math.abs(fs - fontSizePx) > 0.01) {
        fontSizePx = fs;
        if (ready) assembleAndUpload(); // font-size changed → rebuild static px attrs
      }
    }
  }

  function frameEffects(velocity: number): {
    grain: number;
    aberration: number;
    disp: number;
    dispScale: [number, number];
  } {
    const grain = effects.grain ?? 0;
    let aberration = 0;
    if (effects.aberration) {
      aberration = effects.aberration.fromVelocity
        ? Math.min(effects.aberration.max, Math.abs(velocity) * effects.aberration.max)
        : effects.aberration.max;
    }
    const disp = effects.displacement?.intensity ?? 0;
    const dispScale = effects.displacement?.scale ?? [1, 1];
    return { grain, aberration, disp, dispScale };
  }

  function paint(rawStretch: number, now: number): void {
    if (!backend || !run || !ready || !visible || !hostRect) return;
    if (backend.isContextLost()) return;
    // ── Tier-safety guard: WebGL is a STRETCH-ONLY tier ──────────────────────
    // The stretch-independent LUT form `uOrig + (u_stretch-1)·C(u)` is exact and
    // monotonic for stretch ≥ 1, but has NO lower guard: for stretch < 1 it folds
    // geometry over (inverts) on high-flex glyphs, violating the I5/monotonicity
    // invariant. The core's nonlinear water-fill compression guard (core/lut.ts)
    // lives on the frozen CPU side and is NOT reproducible by this linear-in-
    // stretch shader, so compression is the SVG (vector-fidelity) tier's job
    // (RESEARCH §3). We therefore clamp any stretch < 1 to identity (1) at the
    // GPU draw boundary — the shader renders identity-or-stretch and can never
    // fold. This covers BOTH reachable sub-unity paths: a config `minStretchRatio
    // < 1`, and an underdamped spring undershooting below its resting target
    // (stretch-controller emits unclamped `.value`).
    //
    // FUTURE HOOK (do NOT implement here — pending architect/user decision): when
    // effective stretch < 1, dispatch this run to the SVG tier for true
    // compression fidelity instead of clamping to identity. That routing belongs
    // at the engine/tier-selection layer, not inside the GPU renderer.
    const stretch = Math.max(1, rawStretch);
    lastStretch = stretch;
    const d = dpr();
    backend.ensureSize(
      hostRect ? Math.max(hostRect.x + hostRect.w, viewportW()) : viewportW(),
      viewportH(),
      d,
    );
    backend.beginFrame(now);

    const velocity = controller.velocity ?? 0;
    const fx = frameEffects(velocity);
    run.draw({
      region: hostRect,
      dpr: d,
      stretch,
      origin: 0,
      color,
      pxRange,
      atlasSize: DEFAULT_ATLAS_SIZE,
      grain: fx.grain,
      aberration: fx.aberration,
      stretchDir: [1, 0], // horizontal axis only
      time: now * 0.001,
      dispIntensity: fx.disp,
      dispScale: fx.dispScale,
    });
  }

  function viewportW(): number {
    return doc.defaultView?.innerWidth ?? (hostRect ? hostRect.x + hostRect.w : 1);
  }
  function viewportH(): number {
    return doc.defaultView?.innerHeight ?? (hostRect ? hostRect.y + hostRect.h : 1);
  }

  function draw(now = 0): void {
    if (!ready || !visible) return;
    // Clamp to the tier-safe floor (see paint()) BEFORE the settle-skip compare:
    // a sub-unity controller value (config minStretchRatio<1, or an underdamped
    // spring undershooting toward a resting target) maps to identity here, so a
    // run resting below 1 settles/skips instead of re-drawing an identity frame
    // every frame, and sub-unity spring wiggle draws nothing.
    const stretch = Math.max(1, controller.value);
    const hasVelocityFx = !!effects.aberration?.fromVelocity && (controller.velocity ?? 0) !== 0;
    if (stretch === lastStretch && !hasVelocityFx) return; // settled → skip
    paint(stretch, now);
  }

  function onRestore(): void {
    // Context restored: atlas texture, LUT texture, geometry + instance buffers
    // are all gone. Re-ensure + re-upload everything from cached statics/bitmaps.
    if (!backend || destroyed) return;
    assembleAndUpload();
    lastStretch = Number.NaN; // force a repaint
    ticker.wake();
  }

  function subscribeAnimated(): void {
    unsubs.push(ticker.read(readPhase));
    unsubs.push(ticker.render((now) => draw(now)));

    if (typeof ResizeObserver !== 'undefined') {
      resizeObserver = new ResizeObserver(() => {
        rectDirty = true;
        ticker.wake();
      });
      resizeObserver.observe(host);
    }
    const view = doc.defaultView;
    if (view) {
      scrollHandler = () => {
        rectDirty = true;
        ticker.wake();
      };
      view.addEventListener('scroll', scrollHandler, { passive: true });
    }

    // Offscreen ⇒ idle (RESEARCH §2). observeVisibility fires true synchronously
    // when no IO is available (headless), so work still runs.
    visibilityStop = observeVisibility(
      host,
      (v) => {
        visible = v;
        if (v) {
          rectDirty = true;
          ticker.wake();
        }
      },
      options.visibilityFactory ? { factory: options.visibilityFactory } : {},
    );
  }

  function attach(): void {
    if (attached || destroyed) return;
    attached = true;
    if (!supported || !backend) return; // engine drops to SVG tier

    lostUnsub = backend.onContextLost(() => {
      /* preventDefault handled in backend; nothing to draw while lost */
    });
    restoredUnsub = backend.onContextRestored(onRestore);

    // Build atlas + run, then paint. Static work; async only for the raster.
    generateAtlas().then(() => {
      if (destroyed) return;
      ready = true;
      // First measure (host rect + font-size) then assemble with real px.
      overlay.measure();
      const r = host.getBoundingClientRect();
      hostRect = { x: r.left, y: r.top, w: r.width, h: r.height };
      const view = doc.defaultView;
      if (view) {
        const fs = parseFloat(view.getComputedStyle(host).fontSize);
        if (Number.isFinite(fs) && fs > 0) fontSizePx = fs;
      }
      assembleAndUpload();
      loadNoiseIfNeeded();

      if (respectRM && isRM()) {
        // Reduced motion / print: ONE static draw, NO per-frame subscription.
        paint(restingStretch, 0);
        return;
      }
      subscribeAnimated();
      ticker.wake();
    });
  }

  function resize(): void {
    rectDirty = true;
    ticker.wake();
  }

  function destroy(): void {
    destroyed = true;
    for (const u of unsubs) u();
    unsubs.length = 0;
    if (resizeObserver) {
      resizeObserver.disconnect();
      resizeObserver = null;
    }
    if (scrollHandler && doc.defaultView) {
      doc.defaultView.removeEventListener('scroll', scrollHandler);
      scrollHandler = null;
    }
    if (visibilityStop) {
      visibilityStop();
      visibilityStop = null;
    }
    if (lostUnsub) lostUnsub();
    if (restoredUnsub) restoredUnsub();
    if (run) {
      run.dispose();
      run = null;
    }
    overlay.destroy();
    if (ownsMsdf) msdf.destroy();
    if (usingShared && backend) releaseSharedBackend();
    attached = false;
  }

  return {
    attach,
    resize,
    draw,
    destroy,
    supported,
    get element() {
      return backend?.canvas ?? null;
    },
    overlay,
  };
}

/**
 * webgl/slice-grid.ts — the SHARED, subdivided per-glyph quad geometry.
 *
 * Every glyph is a quad subdivided into `slices` columns horizontally (×1 row —
 * horizontal axis ONLY, per the phase scope) so the piecewise-linear LUT remap
 * is evaluated at each slice boundary and the geometry bends exactly at the
 * texel boundaries (refs/examples/03 header). Because box coordinates are
 * normalized [0,1]² and IDENTICAL for every glyph, this buffer is built ONCE
 * and drawn with `drawElementsInstanced`; per-glyph data (origin, width, atlas
 * UV rect, LUT row) rides on instanced attributes. Zero per-frame geometry.
 *
 * Grid resolution MUST equal the LUT slice count so remap breakpoints land on
 * vertices — a coarser grid would linearize across a stretch boundary and lose
 * stroke protection; a finer grid is wasted vertices.
 *
 * Atlas UV is NOT baked here: the vertex shader derives it as
 *   uv = a_atlasUVOrigin + a_boxCoord * a_atlasUVSize
 * from the instanced UV rect, keeping UVs "original" (never remapped) exactly as
 * the locked design requires.
 *
 * PURE (no GL). Tested for vertex/index counts, column monotonicity, UV mapping
 * and in-range, consistently-wound triangulation.
 */

export interface SliceGrid {
  /** Interleaved box coords (x,y) ∈ [0,1]², length = (slices+1)*2*2. */
  boxCoords: Float32Array;
  /** Triangle indices (Uint16), length = slices*6. */
  indices: Uint16Array;
  /** Distinct columns = slices+1. */
  columns: number;
  /** Vertices = (slices+1)*2. */
  vertexCount: number;
  /** Slice count this grid was built for. */
  slices: number;
}

/**
 * Build the shared subdivided-quad grid for `slices` columns.
 * Vertex order: column-major, bottom (y=0) then top (y=1) per column.
 *   v(col, row) index = col*2 + row      (row 0 = bottom, 1 = top)
 */
export function buildSliceGrid(slices: number): SliceGrid {
  if (!Number.isInteger(slices) || slices < 1) {
    throw new RangeError(`buildSliceGrid: slices must be a positive integer (got ${slices})`);
  }
  const columns = slices + 1;
  const vertexCount = columns * 2;
  const boxCoords = new Float32Array(vertexCount * 2);

  for (let c = 0; c < columns; c++) {
    const x = c / slices; // 0 → 1, exact at endpoints
    // bottom (y=0)
    boxCoords[(c * 2 + 0) * 2 + 0] = x;
    boxCoords[(c * 2 + 0) * 2 + 1] = 0;
    // top (y=1)
    boxCoords[(c * 2 + 1) * 2 + 0] = x;
    boxCoords[(c * 2 + 1) * 2 + 1] = 1;
  }

  // Two triangles per column between adjacent column pairs.
  const indices = new Uint16Array(slices * 6);
  let k = 0;
  for (let c = 0; c < slices; c++) {
    const b0 = c * 2 + 0; // bottom-left
    const t0 = c * 2 + 1; // top-left
    const b1 = (c + 1) * 2 + 0; // bottom-right
    const t1 = (c + 1) * 2 + 1; // top-right
    // CCW winding in a y-up box: (b0, b1, t1) then (b0, t1, t0)
    indices[k++] = b0;
    indices[k++] = b1;
    indices[k++] = t1;
    indices[k++] = b0;
    indices[k++] = t1;
    indices[k++] = t0;
  }

  return { boxCoords, indices, columns, vertexCount, slices };
}

/**
 * webgl/types.ts — Tier-1 public-facing config surface + glyph inputs.
 *
 * The `effects` block mirrors README.md EXACTLY (packaging owns the schema; this
 * tier only consumes it — CLAUDE.md: no schema change). All effects are Tier-1
 * only and every one is zero-cost when its scalar is 0 / absent (obligation 3).
 */
import type { Bounds1D, BBox } from '../core/types';
import type { PathCommand } from '../core/types';

/** README `effects.aberration`. */
export interface AberrationConfig {
  /** Max channel-split in px. */
  max: number;
  /** Scale the split by scroll velocity. */
  fromVelocity?: boolean;
}

/** README `effects.displacement`. */
export interface DisplacementConfig {
  /** URL of the noise texture (loaded lazily; disabled until decoded). */
  texture: string;
  /** Warp strength in px. */
  intensity: number;
  /** Noise sampling scale (u,v). Default (1,1). */
  scale?: [number, number];
}

/** README `effects` block (Tier-1 only). */
export interface EffectsConfig {
  /** Film-grain intensity 0..1. */
  grain?: number;
  aberration?: AberrationConfig;
  displacement?: DisplacementConfig;
}

/** One glyph's static render inputs (outline + analysis), matching SvgGlyph. */
export interface WebglGlyph {
  char?: string;
  /** Outline commands in font units. */
  commands: PathCommand[];
  /** Static x-axis flex profile (length === slice count). */
  flex: Float32Array;
  /** Ink bounds along x. */
  bounds: Bounds1D;
  /** Advance width in font units. */
  advanceWidth: number;
  /** Glyph bbox in font units (vertical extent + MSDF raster region). */
  bbox: BBox;
  /** Kerning applied before this glyph (font units, 0 for the first). */
  kernBefore?: number;
}

/** Ink color as straight-alpha RGBA in 0..1 (renderer premultiplies). */
export interface RGBAColor {
  r: number;
  g: number;
  b: number;
  a: number;
}

/**
 * worker/analysis-worker.ts — thin Worker wrapper (off-main-thread analysis).
 *
 * troika precedent: all heavy glyph analysis runs here. Flex-profile
 * Float32Array buffers are TRANSFERRED back (zero-copy) in postMessage.
 *
 * Import-safe: guarded so bundling / SSR importing this module is a no-op when
 * there is no Worker scope.
 */
import { analyzeGlyph, collectTransferables } from './analyze';
import type { AnalyzeRequest } from '../core/types';

// `self` exists in a DedicatedWorkerGlobalScope. Guard for other environments.
declare const self: {
  onmessage: ((ev: { data: AnalyzeRequest }) => void) | null;
  postMessage: (msg: unknown, transfer?: ArrayBuffer[]) => void;
} | undefined;

if (typeof self !== 'undefined' && self && 'postMessage' in self) {
  self.onmessage = (ev: { data: AnalyzeRequest }) => {
    const res = analyzeGlyph(ev.data);
    self.postMessage(res, collectTransferables(res));
  };
}

/**
 * worker/analyze.ts — the PURE analysis entry point.
 *
 * No DOM, no Worker globals: this is what BOTH the tests and the worker call.
 * Given an AnalyzeRequest it samples the outline ONCE, then computes a flex
 * profile per requested axis (static — stretch amount is never an input).
 */
import type { AnalyzeRequest, AnalyzeResponse, AxisProfile, Axis } from '../core/types';
import { sampleOutline, sampleBounds } from '../core/sampling/outline';
import { computeFlexProfile, buildFlexField } from '../core/flex-profile';

export function analyzeGlyph(req: AnalyzeRequest): AnalyzeResponse {
  const { params } = req;
  const outline = sampleOutline(req.commands, { samplesPerSegment: params.samplesPerSegment });
  const bb = sampleBounds(outline);
  const bbox =
    Number.isFinite(bb.minX)
      ? bb
      : { minX: 0, minY: 0, maxX: 0, maxY: 0 }; // blank/empty glyph

  // Sample, winding-filter and build the k-d tree ONCE; both axes share it.
  const field = buildFlexField(outline);
  const profiles: { x?: AxisProfile; y?: AxisProfile } = {};

  for (const axis of req.axes as Axis[]) {
    const bounds =
      axis === 'x' ? { min: bbox.minX, max: bbox.maxX } : { min: bbox.minY, max: bbox.maxY };
    const crossBounds =
      axis === 'x' ? { min: bbox.minY, max: bbox.maxY } : { min: bbox.minX, max: bbox.maxX };
    const flex = computeFlexProfile(outline, {
      axis,
      slices: params.slices,
      k: params.k,
      bounds,
      crossBounds,
      interiorSamples: params.interiorSamples,
      smooth: params.smooth,
      field,
    });
    profiles[axis] = { flex, bounds };
  }

  return {
    id: req.id,
    glyphId: req.glyphId,
    advanceWidth: req.advanceWidth,
    bbox,
    profiles,
  };
}

/** Collect the transferable ArrayBuffers in a response (flex profiles). */
export function collectTransferables(res: AnalyzeResponse): ArrayBuffer[] {
  const buffers: ArrayBuffer[] = [];
  if (res.profiles.x) buffers.push(res.profiles.x.flex.buffer as ArrayBuffer);
  if (res.profiles.y) buffers.push(res.profiles.y.flex.buffer as ArrayBuffer);
  return buffers;
}

/**
 * worker/client.ts — main-thread AnalysisClient.
 *
 *  - Spawns the analysis Worker (or a caller-injected one) and matches
 *    responses to requests by id.
 *  - LRU cache keyed by (glyphId, axes, params) so a glyph/axis is analyzed
 *    once. Analysis is static, so cache hits are always valid.
 *  - Synchronous INLINE FALLBACK (calls analyzeGlyph directly) when no Worker
 *    is available — SSR, tests, or environments without Worker support.
 *  - Never touches the DOM and never forces layout.
 */
import type { AnalyzeRequest, AnalyzeResponse, AnalyzeParams, Axis, PathCommand } from '../core/types';
import { DEFAULT_PARAMS } from '../core/types';
import { analyzeGlyph } from './analyze';

export interface AnalysisClientOptions {
  /** Provide a Worker instance factory; omit to use the inline fallback. */
  workerFactory?: () => Worker;
  /** Force the synchronous inline path even if a Worker exists. */
  inline?: boolean;
  /** Max cached glyph/axis analyses (LRU). Default 512. */
  cacheSize?: number;
}

export interface AnalyzeGlyphInput {
  glyphId: string;
  commands: PathCommand[];
  advanceWidth: number;
  axes: Axis[];
  params?: Partial<AnalyzeParams>;
}

interface Pending {
  resolve: (r: AnalyzeResponse) => void;
  reject: (e: unknown) => void;
}

function paramsKey(p: AnalyzeParams): string {
  return `${p.slices}:${p.k}:${p.interiorSamples}:${p.smooth}:${p.samplesPerSegment}`;
}

export class AnalysisClient {
  private worker: Worker | null = null;
  private readonly pending = new Map<number, Pending>();
  private readonly cache = new Map<string, AnalyzeResponse>();
  private readonly cacheSize: number;
  private nextId = 1;
  private inline: boolean;
  private readonly opts: AnalysisClientOptions;

  constructor(opts: AnalysisClientOptions = {}) {
    this.opts = opts;
    this.cacheSize = opts.cacheSize ?? 512;
    const canSpawn = !!opts.workerFactory || (typeof Worker !== 'undefined' && !opts.inline);
    this.inline = !canSpawn || !!opts.inline;
  }

  private ensureWorker(): Worker | null {
    if (this.inline) return null;
    if (this.worker) return this.worker;
    try {
      this.worker = this.opts.workerFactory
        ? this.opts.workerFactory()
        : new Worker(new URL('./analysis-worker.ts', import.meta.url), { type: 'module' });
      this.worker.onmessage = (ev: MessageEvent) => {
        const res = ev.data as AnalyzeResponse;
        const p = this.pending.get(res.id);
        if (p) {
          this.pending.delete(res.id);
          p.resolve(res);
        }
      };
      this.worker.onerror = (err: unknown) => {
        for (const [, p] of this.pending) p.reject(err);
        this.pending.clear();
      };
    } catch {
      // Worker construction failed → permanently fall back to inline.
      this.inline = true;
      this.worker = null;
    }
    return this.worker;
  }

  private cacheGet(key: string): AnalyzeResponse | undefined {
    const v = this.cache.get(key);
    if (v) {
      this.cache.delete(key);
      this.cache.set(key, v); // move to MRU
    }
    return v;
  }

  private cacheSet(key: string, v: AnalyzeResponse): void {
    this.cache.set(key, v);
    while (this.cache.size > this.cacheSize) {
      const oldest = this.cache.keys().next().value as string | undefined;
      if (oldest === undefined) break;
      this.cache.delete(oldest);
    }
  }

  /** Analyze one glyph for the requested axes (cached, off-thread when possible). */
  analyze(input: AnalyzeGlyphInput): Promise<AnalyzeResponse> {
    const params: AnalyzeParams = { ...DEFAULT_PARAMS, ...input.params };
    const axes = [...input.axes].sort();
    const key = `${input.glyphId}|${axes.join(',')}|${paramsKey(params)}`;

    const cached = this.cacheGet(key);
    if (cached) return Promise.resolve(cached);

    const id = this.nextId++;
    const req: AnalyzeRequest = {
      id,
      glyphId: input.glyphId,
      commands: input.commands,
      axes,
      params,
      advanceWidth: input.advanceWidth,
    };

    const worker = this.ensureWorker();
    if (!worker) {
      // Inline synchronous fallback.
      const res = analyzeGlyph(req);
      this.cacheSet(key, res);
      return Promise.resolve(res);
    }

    return new Promise<AnalyzeResponse>((resolve, reject) => {
      this.pending.set(id, {
        resolve: (r) => {
          this.cacheSet(key, r);
          resolve(r);
        },
        reject,
      });
      worker.postMessage(req);
    });
  }

  /** Number of cached analyses (for diagnostics/tests). */
  get cacheCount(): number {
    return this.cache.size;
  }

  clearCache(): void {
    this.cache.clear();
  }

  destroy(): void {
    if (this.worker) {
      this.worker.terminate();
      this.worker = null;
    }
    this.pending.clear();
    this.cache.clear();
  }
}
